// --- Module: manifest/manifest.js ---
// manifest.js - Asset Manifest Version Check for QuizVerse v3.0
// RPC: manifest_get_version

/**
 * Asset Manifest System — Production-Ready
 *
 * Provides CDN asset manifest version to clients at startup.
 * Lightweight single-read RPC — no writes on normal requests.
 *
 * Storage: collection="game_config", key="manifest_{gameId}"
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var MANIFEST_STORAGE_COLLECTION = 'game_config';

// ─── HELPERS ────────────────────────────────────────────────────────────────

function manifestErrorResponse(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function manifestValidatePayload(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

// ─── RPC: manifest_get_version ──────────────────────────────────────────────

function rpcManifestGetVersion(ctx, logger, nk, payload) {
    // No auth required for manifest check (can be called pre-login)
    var data = manifestValidatePayload(payload);
    if (data === null) return manifestErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var manifestKey = 'manifest_' + gameId;

    try {
        // System-owned storage (userId = null for system reads, but Nakama requires
        // a userId for storageRead, so we use a well-known system user or empty string)
        var records = nk.storageRead([{
            collection: MANIFEST_STORAGE_COLLECTION,
            key: manifestKey,
            userId: '00000000-0000-0000-0000-000000000000'
        }]);

        if (records && records.length > 0 && records[0].value) {
            var manifest = records[0].value;

            return JSON.stringify({
                success: true,
                gameId: gameId,
                version: manifest.version || '1.0.0',
                cdnBaseUrl: manifest.cdnBaseUrl || '',
                manifestUrl: manifest.manifestUrl || '',
                minAppVersion: manifest.minAppVersion || '1.0.0',
                forceUpdate: manifest.forceUpdate || false,
                maintenanceMode: manifest.maintenanceMode || false,
                maintenanceMessage: manifest.maintenanceMessage || '',
                lastUpdatedAt: manifest.lastUpdatedAt || null,
                features: manifest.features || {},
                timestamp: new Date().toISOString()
            });
        }

        // No manifest found — return defaults (don't block the client)
        logger.warn('[Manifest] No manifest found for ' + gameId + ', returning defaults');

        return JSON.stringify({
            success: true,
            gameId: gameId,
            version: '1.0.0',
            cdnBaseUrl: '',
            manifestUrl: '',
            minAppVersion: '1.0.0',
            forceUpdate: false,
            maintenanceMode: false,
            maintenanceMessage: '',
            lastUpdatedAt: null,
            features: {},
            isDefault: true,
            timestamp: new Date().toISOString()
        });

    } catch (err) {
        logger.error('[Manifest] Storage read failed: ' + err.message);
        // Never block client on manifest failure
        return JSON.stringify({
            success: true,
            gameId: gameId,
            version: '1.0.0',
            cdnBaseUrl: '',
            manifestUrl: '',
            minAppVersion: '1.0.0',
            forceUpdate: false,
            maintenanceMode: false,
            maintenanceMessage: '',
            lastUpdatedAt: null,
            features: {},
            isDefault: true,
            fallback: true,
            timestamp: new Date().toISOString()
        });
    }
}


// --- Module: matchmaking/matchmaking.js ---
/**
 * Matchmaking System for Multi-Game Platform
 * Supports skill-based matching, party queues, and game modes
 * 
 * Collections:
 * - matchmaking_tickets: Stores active matchmaking tickets
 * - matchmaking_history: Stores match history for analytics
 */

var MATCHMAKING_TICKETS_COLLECTION = "matchmaking_tickets";
var MATCHMAKING_HISTORY_COLLECTION = "matchmaking_history";

/**
 * RPC: matchmaking_find_match
 * Create matchmaking ticket and find match
 */
var rpcMatchmakingFindMatch = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id || !data.mode) {
            throw Error("game_id and mode are required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        var mode = data.mode;
        var skillLevel = data.skill_level || 1000;
        var partyMembers = data.party_members || [];
        var properties = data.properties || {};
        
        logger.info("[Matchmaking] Finding match for user: " + userId + ", mode: " + mode);
        
        // Calculate skill range (widen over time in production)
        var minSkill = skillLevel - 100;
        var maxSkill = skillLevel + 100;
        
        // Party size
        var partySize = partyMembers.length + 1;
        
        // Create matchmaking query
        var query = "+properties.game_id:" + gameId + " +properties.mode:" + mode;
        
        // Add matchmaking ticket
        var ticket = nk.matchmakerAdd(
            query,
            minSkill,
            maxSkill,
            query,
            {
                skill: skillLevel,
                party_size: partySize
            },
            Object.assign({
                game_id: gameId,
                mode: mode,
                user_id: userId
            }, properties)
        );
        
        // Store ticket info
        var ticketKey = "ticket_" + userId + "_" + gameId;
        var ticketData = {
            ticket_id: ticket,
            user_id: userId,
            game_id: gameId,
            mode: mode,
            skill_level: skillLevel,
            party_members: partyMembers,
            created_at: new Date().toISOString(),
            status: "searching"
        };
        
        nk.storageWrite([{
            collection: MATCHMAKING_TICKETS_COLLECTION,
            key: ticketKey,
            userId: userId,
            value: ticketData,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        
        logger.info("[Matchmaking] Ticket created: " + ticket);
        
        return JSON.stringify({
            success: true,
            ticket_id: ticket,
            estimated_wait_seconds: 30,
            mode: mode,
            skill_level: skillLevel
        });
        
    } catch (err) {
        logger.error("[Matchmaking] Find match error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: matchmaking_cancel
 * Cancel matchmaking ticket
 */
var rpcMatchmakingCancel = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.ticket_id) {
            throw Error("ticket_id is required");
        }
        
        var ticketId = data.ticket_id;
        
        // Remove from matchmaker
        nk.matchmakerRemove(ticketId);
        
        logger.info("[Matchmaking] Ticket cancelled: " + ticketId);
        
        return JSON.stringify({
            success: true,
            ticket_id: ticketId
        });
        
    } catch (err) {
        logger.error("[Matchmaking] Cancel error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: matchmaking_get_status
 * Check matchmaking status
 */
var rpcMatchmakingGetStatus = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id) {
            throw Error("game_id is required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        
        // Get ticket info
        var ticketKey = "ticket_" + userId + "_" + gameId;
        
        var records = nk.storageRead([{
            collection: MATCHMAKING_TICKETS_COLLECTION,
            key: ticketKey,
            userId: userId
        }]);
        
        if (!records || records.length === 0 || !records[0].value) {
            return JSON.stringify({
                success: true,
                status: "idle",
                message: "No active matchmaking"
            });
        }
        
        var ticketData = records[0].value;
        
        return JSON.stringify({
            success: true,
            status: ticketData.status,
            ticket_id: ticketData.ticket_id,
            mode: ticketData.mode,
            created_at: ticketData.created_at
        });
        
    } catch (err) {
        logger.error("[Matchmaking] Get status error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: matchmaking_create_party
 * Create a party for group matchmaking
 */
var rpcMatchmakingCreateParty = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.game_id) {
            throw Error("game_id is required");
        }
        
        var userId = ctx.userId;
        var gameId = data.game_id;
        var maxMembers = data.max_members || 4;
        
        // Create party (simplified - use Nakama parties in production)
        var partyId = "party_" + userId + "_" + Date.now();
        
        var party = {
            party_id: partyId,
            leader_id: userId,
            game_id: gameId,
            members: [userId],
            max_members: maxMembers,
            created_at: new Date().toISOString(),
            status: "open"
        };
        
        nk.storageWrite([{
            collection: "parties",
            key: partyId,
            userId: userId,
            value: party,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info("[Matchmaking] Party created: " + partyId);
        
        return JSON.stringify({
            success: true,
            party: party
        });
        
    } catch (err) {
        logger.error("[Matchmaking] Create party error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};

/**
 * RPC: matchmaking_join_party
 * Join an existing party
 */
var rpcMatchmakingJoinParty = function(ctx, logger, nk, payload) {
    try {
        var data = JSON.parse(payload || '{}');
        
        if (!data.party_id) {
            throw Error("party_id is required");
        }
        
        var userId = ctx.userId;
        var partyId = data.party_id;
        
        // Get party
        var records = nk.storageRead([{
            collection: "parties",
            key: partyId,
            userId: null
        }]);
        
        if (!records || records.length === 0 || !records[0].value) {
            throw Error("Party not found");
        }
        
        var party = records[0].value;
        
        // Check if party is full
        if (party.members.length >= party.max_members) {
            throw Error("Party is full");
        }
        
        // Check if already in party
        if (party.members.indexOf(userId) !== -1) {
            throw Error("Already in this party");
        }
        
        // Add member
        party.members.push(userId);
        
        nk.storageWrite([{
            collection: "parties",
            key: partyId,
            userId: party.leader_id,
            value: party,
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info("[Matchmaking] User " + userId + " joined party: " + partyId);
        
        return JSON.stringify({
            success: true,
            party: party
        });
        
    } catch (err) {
        logger.error("[Matchmaking] Join party error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
};


// --- Module: multigame_rpcs.js ---
// multigame_rpcs.js - Multi-Game RPCs for QuizVerse, LastToLive, and Custom Games
// Pure JavaScript - No TypeScript
// Compatible with Nakama V8 JavaScript runtime (No ES Modules)
//
// IMPORTANT TERMINOLOGY:
// - gameID: Legacy identifier for built-in games ("quizverse", "lasttolive")
// - gameUUID: Unique identifier (UUID) from external game registry API
// - gameTitle: Human-readable game name from external API
//
// This module supports both:
// 1. Legacy built-in games using gameID (backward compatibility)
// 2. New games using gameUUID from external registry

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Parse and validate payload with gameID or gameUUID
 * Supports both legacy gameID ("quizverse", "lasttolive") and new gameUUID (UUID)
 */
function parseAndValidateGamePayload(payload, requiredFields) {
    var data = {};
    try {
        data = JSON.parse(payload || "{}");
    } catch (e) {
        throw Error("Invalid JSON payload");
    }

    // Support both gameID (legacy) and gameUUID (new)
    var gameIdentifier = data.gameID || data.gameUUID;
    
    if (!gameIdentifier) {
        throw Error("Missing game identifier: provide either 'gameID' (for built-in games) or 'gameUUID' (for custom games)");
    }
    
    // Normalize to gameID field for backward compatibility
    if (!data.gameID && data.gameUUID) {
        data.gameID = data.gameUUID;
    }
    
    // Legacy validation for built-in games
    var isLegacyGame = ["quizverse", "lasttolive"].includes(data.gameID);
    var isUUID = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/.test(data.gameID);
    
    if (!isLegacyGame && !isUUID) {
        throw Error("Invalid game identifier. Must be 'quizverse', 'lasttolive', or a valid UUID");
    }

    // Validate required fields
    for (var i = 0; i < requiredFields.length; i++) {
        var field = requiredFields[i];
        if (!data.hasOwnProperty(field) || data[field] === null || data[field] === undefined) {
            throw Error("Missing required field: " + field);
        }
    }

    return data;
}

/**
 * Get user ID from data or context
 */
function getUserId(data, ctx) {
    return data.userID || ctx.userId;
}

/**
 * Create namespaced collection name
 */
function getCollection(gameID, type) {
    return gameID + "_" + type;
}

/**
 * Get leaderboard ID for game
 */
function getLeaderboardId(gameID, type) {
    if (type === "weekly" || !type) {
        return gameID + "_weekly";
    }
    return gameID + "_" + type;
}

// ============================================================================
// AUTHENTICATION & PROFILE
// ============================================================================

/**
 * RPC: quizverse_update_user_profile
 * Updates user profile for QuizVerse
 */
function quizverseUpdateUserProfile(context, logger, nk, payload) {
    try {
        var data = parseAndValidateGamePayload(payload, ["gameID"]);
        var userId = getUserId(data, context);
        
        var collection = getCollection(data.gameID, "profiles");
        var key = "profile_" + userId;
        
        // Read existing profile or create new
        var profile = {};
        try {
            var records = nk.storageRead([{
                collection: collection,
                key: key,
                userId: userId
            }]);
            if (records && records.length > 0 && records[0].value) {
                profile = records[0].value;
            }
        } catch (err) {
            logger.debug("No existing profile found, creating new");
        }
        
        // Update profile fields
        if (data.displayName) profile.displayName = data.displayName;
        if (data.avatar) profile.avatar = data.avatar;
        if (data.level !== undefined) profile.level = data.level;
        if (data.xp !== undefined) profile.xp = data.xp;
        if (data.metadata) profile.metadata = data.metadata;
        
        profile.updatedAt = new Date().toISOString();
        if (!profile.createdAt) {
            profile.createdAt = profile.updatedAt;
        }
        
        // Write profile
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: profile,
            permissionRead: 2,
            permissionWrite: 1
        }]);
        
        logger.info("[" + data.gameID + "] Profile updated for user: " + userId);
        
        return JSON.stringify({
            success: true,
            data: profile
        });
        
    } catch (err) {
        logger.error("quizverse_update_user_profile error: " + err.message);
        return JSON.stringify({
            success: false,
            error: err.message
        });
    }
}

/**
 * RPC: lasttolive_update_user_profile
 * Updates user profile for LastToLive
 */
function lasttoliveUpdateUserProfile(context, logger, nk, payload) {
    // Reuse the same logic as QuizVerse
    return quizverseUpdateUserProfile(context, logger, nk, payload);
}

