/**
 * Register all multi-game RPCs with safe auto-registration
 */
function registerMultiGameRPCs(initializer, logger) {
    logger.info('[MultiGameRPCs] Initializing Multi-Game RPC Module...');
    
    // Initialize global RPC registry
    if (!globalThis.__registeredRPCs) {
        globalThis.__registeredRPCs = new Set();
    }
    
    var rpcs = [
        // QuizVerse RPCs
        { id: 'quizverse_update_user_profile', handler: quizverseUpdateUserProfile },
        { id: 'quizverse_grant_currency', handler: quizverseGrantCurrency },
        { id: 'quizverse_spend_currency', handler: quizverseSpendCurrency },
        { id: 'quizverse_validate_purchase', handler: quizverseValidatePurchase },
        { id: 'quizverse_list_inventory', handler: quizverseListInventory },
        { id: 'quizverse_grant_item', handler: quizverseGrantItem },
        { id: 'quizverse_consume_item', handler: quizverseConsumeItem },
        { id: 'quizverse_submit_score', handler: quizverseSubmitScore },
        { id: 'quizverse_get_leaderboard', handler: quizverseGetLeaderboard },
        { id: 'quizverse_join_or_create_match', handler: quizverseJoinOrCreateMatch },
        { id: 'quizverse_claim_daily_reward', handler: quizverseClaimDailyReward },
        { id: 'quizverse_find_friends', handler: quizverseFindFriends },
        { id: 'quizverse_save_player_data', handler: quizverseSavePlayerData },
        { id: 'quizverse_load_player_data', handler: quizverseLoadPlayerData },
        
        // LastToLive RPCs
        { id: 'lasttolive_update_user_profile', handler: lasttoliveUpdateUserProfile },
        { id: 'lasttolive_grant_currency', handler: lasttoliveGrantCurrency },
        { id: 'lasttolive_spend_currency', handler: lasttoliveSpendCurrency },
        { id: 'lasttolive_validate_purchase', handler: lasttoliveValidatePurchase },
        { id: 'lasttolive_list_inventory', handler: lasttoliveListInventory },
        { id: 'lasttolive_grant_item', handler: lasttoliveGrantItem },
        { id: 'lasttolive_consume_item', handler: lasttoliveConsumeItem },
        { id: 'lasttolive_submit_score', handler: lasttoliveSubmitScore },
        { id: 'lasttolive_get_leaderboard', handler: lasttoliveGetLeaderboard },
        { id: 'lasttolive_join_or_create_match', handler: lasttoliveJoinOrCreateMatch },
        { id: 'lasttolive_claim_daily_reward', handler: lasttoliveClaimDailyReward },
        { id: 'lasttolive_find_friends', handler: lasttolliveFindFriends },
        { id: 'lasttolive_save_player_data', handler: lasttolliveSavePlayerData },
        { id: 'lasttolive_load_player_data', handler: lasttoliveLoadPlayerData }
    ];
    
    var registered = 0;
    var skipped = 0;
    
    for (var i = 0; i < rpcs.length; i++) {
        var rpc = rpcs[i];
        
        if (!globalThis.__registeredRPCs.has(rpc.id)) {
            try {
                initializer.registerRpc(rpc.id, rpc.handler);
                globalThis.__registeredRPCs.add(rpc.id);
                logger.info('[MultiGameRPCs] ✓ Registered RPC: ' + rpc.id);
                registered++;
            } catch (err) {
                logger.error('[MultiGameRPCs] ✗ Failed to register ' + rpc.id + ': ' + err.message);
            }
        } else {
            logger.info('[MultiGameRPCs] ⊘ Skipped (already registered): ' + rpc.id);
            skipped++;
        }
    }
    
    logger.info('[MultiGameRPCs] Registration complete: ' + registered + ' registered, ' + skipped + ' skipped');
    logger.info('[MultiGameRPCs] Total RPCs available: ' + rpcs.length);
}


// --- Module: notifications/notification_gate.js ---
// notification_gate.js - Notification Budget Gate for QuizVerse v3.0
// RPC: notification_gate_get_state

/**
 * Notification Gate — Production-Ready
 *
 * Controls client-side notification budget to prevent spam.
 * Max 3 notifications/day, 3-hour cooldown between each.
 * Priority queue ensures most important notifications fire first.
 *
 * Storage: collection="notification_state", key="{userId}_{gameId}"
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var DAILY_NOTIFICATION_BUDGET = 3;
var COOLDOWN_HOURS = 3;
var NOTIF_STORAGE_COLLECTION = 'notification_state';

// ─── HELPERS ────────────────────────────────────────────────────────────────

function notifStorageKey(userId, gameId) {
    return userId + '_' + gameId;
}

function readNotifState(nk, logger, userId, gameId) {
    try {
        var records = nk.storageRead([{
            collection: NOTIF_STORAGE_COLLECTION,
            key: notifStorageKey(userId, gameId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[NotifGate] Storage read failed: ' + err.message);
    }
    return null;
}

function writeNotifState(nk, logger, userId, gameId, data) {
    try {
        nk.storageWrite([{
            collection: NOTIF_STORAGE_COLLECTION,
            key: notifStorageKey(userId, gameId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[NotifGate] Storage write failed: ' + err.message);
        return false;
    }
}

function getTodayKey() {
    var now = new Date();
    return now.getUTCFullYear() + '-' +
           (now.getUTCMonth() + 1 < 10 ? '0' : '') + (now.getUTCMonth() + 1) + '-' +
           (now.getUTCDate() < 10 ? '0' : '') + now.getUTCDate();
}

function initNotifState() {
    var now = new Date().toISOString();
    return {
        dailyBudget: DAILY_NOTIFICATION_BUDGET,
        usedToday: 0,
        todayKey: getTodayKey(),
        lastNotificationAt: null,
        cooldownEndsAt: null,
        pendingQueue: [],
        history: [],
        totalSent: 0,
        createdAt: now,
        updatedAt: now
    };
}

function notifErrorResponse(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function notifValidatePayload(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

// ─── RPC: notification_gate_get_state ───────────────────────────────────────

function rpcNotifGateGetState(ctx, logger, nk, payload) {
    if (!ctx.userId) return notifErrorResponse('User not authenticated');

    var data = notifValidatePayload(payload);
    if (data === null) return notifErrorResponse('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var state = readNotifState(nk, logger, ctx.userId, gameId);
    var isNew = false;

    if (!state) {
        state = initNotifState();
        writeNotifState(nk, logger, ctx.userId, gameId, state);
        isNew = true;
    }

    // Reset daily counter if new day
    var todayKey = getTodayKey();
    if (state.todayKey !== todayKey) {
        state.usedToday = 0;
        state.todayKey = todayKey;
        state.pendingQueue = [];  // Clear stale queue
        state.updatedAt = new Date().toISOString();
        writeNotifState(nk, logger, ctx.userId, gameId, state);
    }

    var remaining = Math.max(0, DAILY_NOTIFICATION_BUDGET - state.usedToday);
    var now = new Date();
    var inCooldown = false;
    var cooldownEndsAt = null;

    if (state.lastNotificationAt) {
        var lastNotif = new Date(state.lastNotificationAt);
        var cooldownEnd = new Date(lastNotif.getTime() + COOLDOWN_HOURS * 3600000);
        if (now.getTime() < cooldownEnd.getTime()) {
            inCooldown = true;
            cooldownEndsAt = cooldownEnd.toISOString();
        }
    }

    // Sort pending queue by priority (higher priority = more important)
    var sortedQueue = (state.pendingQueue || []).slice();
    sortedQueue.sort(function(a, b) { return (b.priority || 0) - (a.priority || 0); });

    return JSON.stringify({
        success: true,
        isNew: isNew,
        userId: ctx.userId,
        gameId: gameId,
        dailyBudget: DAILY_NOTIFICATION_BUDGET,
        used: state.usedToday,
        remaining: remaining,
        inCooldown: inCooldown,
        cooldownEndsAt: cooldownEndsAt,
        cooldownHours: COOLDOWN_HOURS,
        lastNotificationAt: state.lastNotificationAt,
        pendingQueue: sortedQueue.slice(0, 10),  // Return max 10
        totalSent: state.totalSent || 0,
        timestamp: now.toISOString()
    });
}


// --- Module: notifications/notification_inbox.js ---
// notification_inbox.js - Notification Inbox System for QuizVerse v3.0
// RPCs: list_notification_inbox, mark_notifications_read
// Nakama is the source of truth for all notification state.

/**
 * Notification Inbox — Production-Ready
 *
 * Bridges Nakama built-in notifications (from nk.notificationSend across all modules)
 * with custom scheduled/inbox entries stored in "notification_inbox" collection.
 *
 * Storage: collection="notification_inbox", key="{notificationId}"
 *
 * Nakama built-in notifications come from:
 *   - social_v2.js (friend invites, friend challenges)
 *   - quizverse_depth.js (duel results)
 *   - player_gifts.js (gifts sent/claimed)
 *   - friends.js (friend challenges)
 *   - chat.js (chat notifications)
 *   - copilot/social_features.js (friend requests/accepts)
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var INBOX_COLLECTION = 'notification_inbox';
var MAX_INBOX_LIMIT = 100;

// Map Nakama built-in notification codes to event types
// These codes are used by nk.notificationSend across the codebase
var NOTIFICATION_CODE_MAP = {
    1: 'friend_request',
    2: 'friend_accept',
    3: 'duel_result',
    4: 'challenge_received',
    5: 'match_found',
    100: 'gift_received',
    101: 'gift_claimed',
    // Default for unknown codes
    0: 'system'
};

// ─── HELPERS ────────────────────────────────────────────────────────────────

function inboxErrorResponse(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function inboxParsePayload(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

/**
 * Convert a Nakama built-in notification to the unified ServerNotificationEntry format
 * that the Unity client expects.
 *
 * Nakama built-in notification shape:
 *   { id, subject, content (object), code (int), senderId, createTime (RFC3339 string) }
 */
function mapBuiltinNotification(n) {
    var code = n.code || 0;
    var eventType = NOTIFICATION_CODE_MAP[code] || 'system';
    var content = n.content || {};

    // Extract data fields from content (Nakama stores content as an object)
    var data = {};
    for (var key in content) {
        if (content.hasOwnProperty(key)) {
            data[key] = String(content[key]);
        }
    }

    // Determine title/body from Nakama fields
    var title = n.subject || 'Notification';
    var body = content.message || content.body || '';

    // If content has a type field, use it as the event_type (more specific)
    if (content.type) {
        eventType = content.type;
    }

    // Parse createTime — Nakama returns RFC3339 string (e.g. "2024-01-15T10:30:00Z")
    var sentAtMs = Date.now();
    if (n.createTime) {
        try {
            sentAtMs = new Date(n.createTime).getTime();
            if (isNaN(sentAtMs)) sentAtMs = Date.now();
        } catch (e) {
            sentAtMs = Date.now();
        }
    }

    return {
        notification_id: n.id || ('builtin_' + Date.now() + '_' + Math.random()),
        title: title,
        body: body,
        event_type: eventType,
        data: data,
        template_id: '',
        priority: code <= 5 ? (10 - code) : 5,   // Lower codes = higher priority
        channel: 'in_app',
        is_read: false,    // Nakama built-ins are unread until deleted
        sent_at: sentAtMs,
        created_at: sentAtMs,
        source: 'nakama_builtin'
    };
}

/**
 * Convert a custom inbox storage entry to the ServerNotificationEntry format.
 */
function mapCustomInboxEntry(record) {
    var v = record.value || {};
    return {
        notification_id: v.notification_id || record.key,
        title: v.title || 'Notification',
        body: v.body || '',
        event_type: v.event_type || 'general',
        data: v.data || {},
        template_id: v.template_id || '',
        priority: v.priority || 5,
        channel: v.channel || 'both',
        is_read: v.is_read || false,
        sent_at: v.sent_at || v.created_at || Date.now(),
        created_at: v.created_at || Date.now(),
        source: 'custom'
    };
}

/**
 * Read custom inbox entries from notification_inbox collection.
 * nk.storageList returns { objects: [...], cursor: "..." }
 */
function readCustomInbox(nk, logger, userId, limit) {
    var entries = [];
    try {
        var result = nk.storageList(userId, INBOX_COLLECTION, limit, '');
        if (result && result.objects && result.objects.length > 0) {
            for (var i = 0; i < result.objects.length; i++) {
                entries.push(mapCustomInboxEntry(result.objects[i]));
            }
        }
    } catch (err) {
        logger.warn('[NotifInbox] Failed to read custom inbox: ' + err.message);
    }
    return entries;
}

/**
 * Write a notification to the custom inbox
 */
function writeInboxEntry(nk, logger, userId, entry) {
    try {
        var notifId = entry.notification_id || ('notif_' + Date.now() + '_' + Math.floor(Math.random() * 10000));
        nk.storageWrite([{
            collection: INBOX_COLLECTION,
            key: notifId,
            userId: userId,
            value: {
                notification_id: notifId,
                title: entry.title || 'Notification',
                body: entry.body || '',
                event_type: entry.event_type || 'general',
                data: entry.data || {},
                template_id: entry.template_id || '',
                priority: entry.priority || 5,
                channel: entry.channel || 'both',
                is_read: false,
                sent_at: entry.sent_at || Date.now(),
                created_at: Date.now()
            },
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return notifId;
    } catch (err) {
        logger.error('[NotifInbox] Failed to write inbox entry: ' + err.message);
        return null;
    }
}

// ─── RPC: list_notification_inbox ───────────────────────────────────────────

/**
 * Fetch the user's unified notification inbox.
 * Merges Nakama built-in notifications + custom inbox entries.
 *
 * Payload: { limit: 50, include_read: true, event_type: null }
 * Response: { success, notifications[], count, unread_count }
 */
function rpcListNotificationInbox(ctx, logger, nk, payload) {
    if (!ctx.userId) return inboxErrorResponse('User not authenticated');

    var data = inboxParsePayload(payload);
    if (data === null) return inboxErrorResponse('Invalid JSON payload');

    var userId = ctx.userId;
    var limit = Math.min(data.limit || 50, MAX_INBOX_LIMIT);
    var includeRead = data.include_read !== false; // Default true
    var eventTypeFilter = data.event_type || null;

    var allNotifications = [];

    // ── Source 1: Nakama built-in notifications ──
    // nk.notificationsList returns { notifications: [...], cacheableCursor: "..." }
    try {
        var builtinResult = nk.notificationsList(userId, limit, null);
        if (builtinResult && builtinResult.notifications) {
            for (var i = 0; i < builtinResult.notifications.length; i++) {
                var mapped = mapBuiltinNotification(builtinResult.notifications[i]);
                allNotifications.push(mapped);
            }
            logger.debug('[NotifInbox] Loaded ' + builtinResult.notifications.length + ' built-in notifications');
        }
    } catch (err) {
        logger.warn('[NotifInbox] Failed to read built-in notifications: ' + err.message);
    }

    // ── Source 2: Custom inbox entries ──
    var customEntries = readCustomInbox(nk, logger, userId, limit);
    for (var j = 0; j < customEntries.length; j++) {
        allNotifications.push(customEntries[j]);
    }
    logger.debug('[NotifInbox] Loaded ' + customEntries.length + ' custom inbox entries');

    // ── Filter ──
    var filtered = [];
    var unreadCount = 0;

    for (var k = 0; k < allNotifications.length; k++) {
        var n = allNotifications[k];

        // Filter by read status
        if (!includeRead && n.is_read) continue;

        // Filter by event type
        if (eventTypeFilter && n.event_type !== eventTypeFilter) continue;

        filtered.push(n);

        if (!n.is_read) unreadCount++;
    }

    // ── Sort by sent_at descending (newest first) ──
    filtered.sort(function(a, b) {
        return (b.sent_at || 0) - (a.sent_at || 0);
    });

    // ── Trim to limit ──
    if (filtered.length > limit) {
        filtered = filtered.slice(0, limit);
    }

    logger.info('[NotifInbox] User ' + userId + ': ' + filtered.length + ' notifications (' + unreadCount + ' unread)');

    return JSON.stringify({
        success: true,
        notifications: filtered,
        count: filtered.length,
        unread_count: unreadCount
    });
}

// ─── RPC: mark_notifications_read ───────────────────────────────────────────

/**
 * Mark notifications as read.
 *
 * Payload: { notification_ids: ["id1", "id2"], mark_all: false }
 *   OR:    { mark_all: true }
 *
 * Response: { success, marked_count }
 *
 * For Nakama built-in notifications: deletes them (Nakama's canonical "mark read").
 * For custom inbox entries: sets is_read = true in storage.
 */
function rpcMarkNotificationsRead(ctx, logger, nk, payload) {
    if (!ctx.userId) return inboxErrorResponse('User not authenticated');

    var data = inboxParsePayload(payload);
    if (data === null) return inboxErrorResponse('Invalid JSON payload');

    var userId = ctx.userId;
    var markAll = data.mark_all === true;
    var notificationIds = data.notification_ids || [];
    var markedCount = 0;

    if (markAll) {
        // ── Mark ALL: Delete all built-in notifications ──
        try {
            var builtinResult = nk.notificationsList(userId, MAX_INBOX_LIMIT, null);
            if (builtinResult && builtinResult.notifications && builtinResult.notifications.length > 0) {
                var builtinIds = [];
                for (var i = 0; i < builtinResult.notifications.length; i++) {
                    builtinIds.push(builtinResult.notifications[i].id);
                }
                if (builtinIds.length > 0) {
                    nk.notificationsDelete(userId, builtinIds);
                    markedCount += builtinIds.length;
                    logger.info('[NotifInbox] Deleted ' + builtinIds.length + ' built-in notifications for mark-all-read');
                }
            }
        } catch (err) {
            logger.warn('[NotifInbox] Failed to clear built-in notifications: ' + err.message);
        }

        // ── Mark ALL: Update all custom inbox entries ──
        // nk.storageList returns { objects: [...], cursor: "..." }
        try {
            var customResult = nk.storageList(userId, INBOX_COLLECTION, MAX_INBOX_LIMIT, '');
            if (customResult && customResult.objects && customResult.objects.length > 0) {
                var writes = [];
                for (var ci = 0; ci < customResult.objects.length; ci++) {
                    var rec = customResult.objects[ci];
                    var val = rec.value || {};
                    if (!val.is_read) {
                        val.is_read = true;
                        val.read_at = Date.now();
                        writes.push({
                            collection: INBOX_COLLECTION,
                            key: rec.key,
                            userId: userId,
                            value: val,
                            permissionRead: 1,
                            permissionWrite: 0
                        });
                        markedCount++;
                    }
                }
                if (writes.length > 0) {
                    nk.storageWrite(writes);
                    logger.info('[NotifInbox] Marked ' + writes.length + ' custom inbox entries as read');
                }
            }
        } catch (err) {
            logger.warn('[NotifInbox] Failed to mark custom entries as read: ' + err.message);
        }

    } else if (notificationIds.length > 0) {
        // ── Mark specific IDs ──
        var builtinIdsToDelete = [];
        var customKeysToUpdate = [];

        // Separate built-in vs custom (try to read each from custom first)
        for (var ni = 0; ni < notificationIds.length; ni++) {
            var nid = notificationIds[ni];

            // Try to read from custom inbox
            try {
                var customCheck = nk.storageRead([{
                    collection: INBOX_COLLECTION,
                    key: nid,
                    userId: userId
                }]);
                if (customCheck && customCheck.length > 0) {
                    customKeysToUpdate.push({ key: nid, record: customCheck[0] });
                    continue;
                }
            } catch (readErr) {
                // Not in custom inbox — must be a built-in notification
            }

            // Assume it's a built-in notification ID
            builtinIdsToDelete.push(nid);
        }

        // Delete built-in notifications
        if (builtinIdsToDelete.length > 0) {
            try {
                nk.notificationsDelete(userId, builtinIdsToDelete);
                markedCount += builtinIdsToDelete.length;
                logger.info('[NotifInbox] Deleted ' + builtinIdsToDelete.length + ' built-in notifications');
            } catch (err) {
                logger.warn('[NotifInbox] Failed to delete built-in: ' + err.message);
            }
        }

        // Update custom inbox entries
        if (customKeysToUpdate.length > 0) {
            var updateWrites = [];
            for (var ui = 0; ui < customKeysToUpdate.length; ui++) {
                var item = customKeysToUpdate[ui];
                var value = item.record.value || {};
                value.is_read = true;
                value.read_at = Date.now();
                updateWrites.push({
                    collection: INBOX_COLLECTION,
                    key: item.key,
                    userId: userId,
                    value: value,
                    permissionRead: 1,
                    permissionWrite: 0
                });
                markedCount++;
            }
            if (updateWrites.length > 0) {
                try {
                    nk.storageWrite(updateWrites);
                    logger.info('[NotifInbox] Marked ' + updateWrites.length + ' custom entries as read');
                } catch (err) {
                    logger.warn('[NotifInbox] Failed to update custom entries: ' + err.message);
                }
            }
        }
    } else {
        return inboxErrorResponse('No notification_ids provided and mark_all is false');
    }

    return JSON.stringify({
        success: true,
        marked_count: markedCount
    });
}


// --- Module: onboarding/onboarding.js ---
/**
 * Nakama Onboarding Module
 * Handles user onboarding state, preferences, and first-session hooks
 * 
 * Storage Collections:
 * - onboarding_state: User's onboarding progress
 * - user_preferences: User interests and personalization
 * - first_session: First session hooks and rewards
 * - retention_data: D1-D7 retention tracking
 */

// Collection names
var COLLECTION_ONBOARDING = "onboarding_state";
var COLLECTION_PREFERENCES = "user_preferences";
var COLLECTION_FIRST_SESSION = "first_session";
var COLLECTION_RETENTION = "retention_data";

// Keys
var KEY_ONBOARDING = "state";
var KEY_PREFERENCES = "prefs";
var KEY_SESSION = "session";
var KEY_RETENTION = "retention";

// ============================================================================
// DEFAULT AVATAR SYSTEM
// ============================================================================
var DEFAULT_AVATARS = [
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Female1.png",
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Female2.png",
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Female3.png",
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Group-1.png",
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Male1.png",
    "https://intelli-verse-x-media.s3.us-east-1.amazonaws.com/quiz-verse/DefaultAvatar/Male2.png"
];

/**
 * Deterministically pick a default avatar from the pool.
 * Same userId always gets the same avatar (hash-based, not random).
 */
function getDefaultAvatarUrl(userId) {
    var hash = 0;
    for (var i = 0; i < userId.length; i++) {
        hash = ((hash << 5) - hash) + userId.charCodeAt(i);
        hash |= 0; // Convert to 32-bit integer
    }
    return DEFAULT_AVATARS[Math.abs(hash) % DEFAULT_AVATARS.length];
}

/**
 * Ensure a user has an avatar URL. If not, assign a deterministic default.
 * Non-fatal — wrapped in try-catch to never block authentication.
 */
function ensureUserHasAvatar(nk, logger, userId) {
    try {
        var accounts = nk.accountsGetId([userId]);
        if (accounts && accounts.length > 0) {
            var account = accounts[0];
            if (!account.user.avatarUrl || account.user.avatarUrl === "") {
                var defaultAvatar = getDefaultAvatarUrl(userId);
                nk.accountUpdateId(userId, null, null, null, null, null, defaultAvatar, null);
                logger.info("[Onboarding] Assigned default avatar to user " + userId + ": " + defaultAvatar);
                return true;
            }
        }
    } catch (avatarErr) {
        logger.warn("[Onboarding] Failed to assign default avatar for " + userId + ": " + avatarErr.message);
    }
    return false;
}

/**
 * Initialize onboarding module
 */
function _OnboardingInit(ctx, logger, nk, initializer) {
    logger.info("[Onboarding] Initializing onboarding module...");

    // Register RPCs
    __rpc_onboarding_get_state = __rpc_onboarding_get_state || (rpcGetOnboardingState);
    __rpc_onboarding_update_state = __rpc_onboarding_update_state || (rpcUpdateOnboardingState);
    __rpc_onboarding_complete_step = __rpc_onboarding_complete_step || (rpcCompleteStep);
    __rpc_onboarding_set_interests = __rpc_onboarding_set_interests || (rpcSetInterests);
    __rpc_onboarding_get_interests = __rpc_onboarding_get_interests || (rpcGetInterests);
    __rpc_onboarding_claim_welcome_bonus = __rpc_onboarding_claim_welcome_bonus || (rpcClaimWelcomeBonus);
    __rpc_onboarding_first_quiz_complete = __rpc_onboarding_first_quiz_complete || (rpcFirstQuizComplete);
    __rpc_onboarding_get_tomorrow_preview = __rpc_onboarding_get_tomorrow_preview || (rpcGetTomorrowPreview);
    __rpc_onboarding_track_session = __rpc_onboarding_track_session || (rpcTrackSession);
    __rpc_onboarding_get_retention_data = __rpc_onboarding_get_retention_data || (rpcGetRetentionData);
    __rpc_onboarding_grant_streak_shield = __rpc_onboarding_grant_streak_shield || (rpcGrantStreakShield);

    // Register hooks
    initializer.registerAfterAuthenticateDevice(afterAuthHook);
    initializer.registerAfterAuthenticateEmail(afterAuthHook);
    initializer.registerAfterAuthenticateApple(afterAuthHook);
    initializer.registerAfterAuthenticateGoogle(afterAuthHook);

    logger.info("[Onboarding] Module initialized successfully");
}

/**
 * After authentication hook - Initialize new users
 */
function afterAuthHook(ctx, logger, nk, data, request) {
    var userId = ctx.userId;
    
    try {
        // Check if user has onboarding state
        var existing = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (existing.length === 0) {
            // New user - initialize onboarding state
            logger.info(`[Onboarding] New user detected: ${userId}`);
            initializeNewUser(nk, logger, userId);
            // Assign default avatar for new user
            ensureUserHasAvatar(nk, logger, userId);
        } else {
            // Returning user - track session
            trackUserSession(nk, logger, userId);
            // Backfill avatar for returning users who don't have one
            ensureUserHasAvatar(nk, logger, userId);
        }
    } catch (e) {
        logger.error(`[Onboarding] Auth hook error: ${e.message}`);
    }
}

/**
 * Initialize new user with default onboarding state
 */
function initializeNewUser(nk, logger, userId) {
    var now = Date.now();
    
    // Default onboarding state
    var onboardingState = {
        userId: userId,
        createdAt: now,
        currentStep: 1,
        totalSteps: 5,
        completedSteps: [],
        welcomeBonusClaimed: false,
        firstQuizCompleted: false,
        onboardingComplete: false,
        streakShieldExpiry: 0,
        lastUpdated: now
    };

    // Default preferences
    var preferences = {
        userId: userId,
        interests: [],
        preferredDifficulty: "easy",
        dailyReminderEnabled: true,
        reminderTime: "09:00",
        language: "en",
        createdAt: now,
        lastUpdated: now
    };

    // Session data
    var sessionData = {
        userId: userId,
        firstSessionAt: now,
        totalSessions: 1,
        lastSessionAt: now,
        totalQuizzesPlayed: 0,
        totalCoinsEarned: 0,
        currentStreak: 0,
        longestStreak: 0,
        d1Returned: false,
        d7Returned: false
    };

    // Write all initial data
    nk.storageWrite([
        {
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: onboardingState,
            permissionRead: 1, // Owner read
            permissionWrite: 0 // Server write only
        },
        {
            collection: COLLECTION_PREFERENCES,
            key: KEY_PREFERENCES,
            userId: userId,
            value: preferences,
            permissionRead: 1,
            permissionWrite: 0
        },
        {
            collection: COLLECTION_FIRST_SESSION,
            key: KEY_SESSION,
            userId: userId,
            value: sessionData,
            permissionRead: 1,
            permissionWrite: 0
        }
    ]);

    logger.info(`[Onboarding] Initialized new user: ${userId}`);
}

/**
 * Track returning user session
 */
function trackUserSession(nk, logger, userId) {
    try {
        var result = nk.storageRead([{
            collection: COLLECTION_FIRST_SESSION,
            key: KEY_SESSION,
            userId: userId
        }]);

        if (result.length > 0) {
            var sessionData = result[0].value;
            var now = Date.now();
            var firstSession = sessionData.firstSessionAt;
            var hoursSinceFirst = (now - firstSession) / (1000 * 60 * 60);

            sessionData.totalSessions++;
            sessionData.lastSessionAt = now;

            // Track D1 return (returned within 24-48 hours)
            if (!sessionData.d1Returned && hoursSinceFirst >= 20 && hoursSinceFirst <= 48) {
                sessionData.d1Returned = true;
                logger.info(`[Onboarding] User ${userId} returned on D1!`);
            }

            // Track D7 return
            if (!sessionData.d7Returned && hoursSinceFirst >= 144 && hoursSinceFirst <= 192) {
                sessionData.d7Returned = true;
                logger.info(`[Onboarding] User ${userId} returned on D7!`);
            }

            nk.storageWrite([{
                collection: COLLECTION_FIRST_SESSION,
                key: KEY_SESSION,
                userId: userId,
                value: sessionData,
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }
    } catch (e) {
        logger.error(`[Onboarding] Track session error: ${e.message}`);
    }
}

// ==================== RPC HANDLERS ====================

/**
 * RPC: Get user's onboarding state
 */
function rpcGetOnboardingState(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    
    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            // Initialize if not exists
            initializeNewUser(nk, logger, userId);
            return JSON.stringify({
                success: true,
                isNewUser: true,
                state: {
                    currentStep: 1,
                    totalSteps: 5,
                    completedSteps: [],
                    welcomeBonusClaimed: false,
                    firstQuizCompleted: false,
                    onboardingComplete: false
                }
            });
        }

        return JSON.stringify({
            success: true,
            isNewUser: false,
            state: result[0].value
        });
    } catch (e) {
        logger.error(`[Onboarding] Get state error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Update onboarding state
 */
function rpcUpdateOnboardingState(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No onboarding state found" });
        }

        var state = result[0].value;
        
        // Update fields
        if (input.currentStep !== undefined) state.currentStep = input.currentStep;
        if (input.completedSteps !== undefined) state.completedSteps = input.completedSteps;
        if (input.onboardingComplete !== undefined) state.onboardingComplete = input.onboardingComplete;
        state.lastUpdated = Date.now();

        nk.storageWrite([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        return JSON.stringify({ success: true, state: state });
    } catch (e) {
        logger.error(`[Onboarding] Update state error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Complete a specific onboarding step
 */
function rpcCompleteStep(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);
    var stepId = input.stepId;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No onboarding state" });
        }

        var state = result[0].value;
        
        // Add step to completed if not already
        if (!state.completedSteps.includes(stepId)) {
            state.completedSteps.push(stepId);
        }

        // Auto-advance to next step
        if (stepId >= state.currentStep) {
            state.currentStep = stepId + 1;
        }

        // Check if onboarding is complete
        if (state.completedSteps.length >= state.totalSteps) {
            state.onboardingComplete = true;
            logger.info(`[Onboarding] User ${userId} completed onboarding!`);
        }

        state.lastUpdated = Date.now();

        nk.storageWrite([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        // Return rewards for completing step
        var rewards = getStepRewards(stepId);

        return JSON.stringify({ 
            success: true, 
            state: state,
            rewards: rewards
        });
    } catch (e) {
        logger.error(`[Onboarding] Complete step error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Set user interests/preferences
 */
function rpcSetInterests(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_PREFERENCES,
            key: KEY_PREFERENCES,
            userId: userId
        }]);

        var prefs;
        if (result.length === 0) {
            prefs = {
                userId: userId,
                interests: input.interests || [],
                preferredDifficulty: input.difficulty || "easy",
                dailyReminderEnabled: true,
                reminderTime: "09:00",
                language: input.language || "en",
                createdAt: Date.now(),
                lastUpdated: Date.now()
            };
        } else {
            prefs = result[0].value;
            if (input.interests) prefs.interests = input.interests;
            if (input.difficulty) prefs.preferredDifficulty = input.difficulty;
            if (input.language) prefs.language = input.language;
            if (input.reminderEnabled !== undefined) prefs.dailyReminderEnabled = input.reminderEnabled;
            if (input.reminderTime) prefs.reminderTime = input.reminderTime;
            prefs.lastUpdated = Date.now();
        }

        nk.storageWrite([{
            collection: COLLECTION_PREFERENCES,
            key: KEY_PREFERENCES,
            userId: userId,
            value: prefs,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        logger.info(`[Onboarding] User ${userId} set interests: ${prefs.interests.join(", ")}`);

        return JSON.stringify({ success: true, preferences: prefs });
    } catch (e) {
        logger.error(`[Onboarding] Set interests error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Get user interests
 */
function rpcGetInterests(ctx, logger, nk, payload) {
    var userId = ctx.userId;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_PREFERENCES,
            key: KEY_PREFERENCES,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ 
                success: true, 
                preferences: {
                    interests: [],
                    preferredDifficulty: "easy"
                }
            });
        }

        return JSON.stringify({ success: true, preferences: result[0].value });
    } catch (e) {
        logger.error(`[Onboarding] Get interests error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Claim welcome bonus (50 coins for new users)
 */
function rpcClaimWelcomeBonus(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var WELCOME_BONUS = 50;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No onboarding state" });
        }

        var state = result[0].value;

        if (state.welcomeBonusClaimed) {
            return JSON.stringify({ 
                success: false, 
                error: "Welcome bonus already claimed",
                alreadyClaimed: true
            });
        }

        // Grant coins via wallet
        var changeset = { coins: WELCOME_BONUS };
        var metadata = { source: "welcome_bonus" };
        nk.walletUpdate(userId, changeset, metadata, true);

        // Update state
        state.welcomeBonusClaimed = true;
        state.lastUpdated = Date.now();

        nk.storageWrite([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        logger.info(`[Onboarding] User ${userId} claimed welcome bonus: ${WELCOME_BONUS} coins`);

        return JSON.stringify({ 
            success: true, 
            coinsAwarded: WELCOME_BONUS,
            message: "Welcome! Here's 50 free coins! 🎉"
        });
    } catch (e) {
        logger.error(`[Onboarding] Claim welcome bonus error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: First quiz completed - award bonus
 */
function rpcFirstQuizComplete(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);
    var FIRST_QUIZ_BONUS = 200;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No onboarding state" });
        }

        var state = result[0].value;

        if (state.firstQuizCompleted) {
            return JSON.stringify({ 
                success: false, 
                error: "First quiz bonus already claimed",
                alreadyClaimed: true
            });
        }

        // Grant bonus
        var changeset = { coins: FIRST_QUIZ_BONUS };
        var metadata = { 
            source: "first_quiz_bonus",
            score: input.score || 0,
            correctAnswers: input.correctAnswers || 0
        };
        nk.walletUpdate(userId, changeset, metadata, true);

        // Update state
        state.firstQuizCompleted = true;
        state.lastUpdated = Date.now();

        // Also grant streak shield (48 hours)
        state.streakShieldExpiry = Date.now() + (48 * 60 * 60 * 1000);

        nk.storageWrite([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        // Update session data
        updateSessionStats(nk, logger, userId, {
            quizzesPlayed: 1,
            coinsEarned: FIRST_QUIZ_BONUS
        });

        logger.info(`[Onboarding] User ${userId} completed first quiz: ${FIRST_QUIZ_BONUS} coins + streak shield`);

        return JSON.stringify({ 
            success: true, 
            coinsAwarded: FIRST_QUIZ_BONUS,
            streakShieldHours: 48,
            message: "Amazing! First Quiz Bonus: +200 Coins! 🎉\n🛡️ Streak Shield activated for 48 hours!"
        });
    } catch (e) {
        logger.error(`[Onboarding] First quiz complete error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Get tomorrow's preview (personalized hook)
 */
function rpcGetTomorrowPreview(ctx, logger, nk, payload) {
    var userId = ctx.userId;

    try {
        // Get user preferences
        var prefsResult = nk.storageRead([{
            collection: COLLECTION_PREFERENCES,
            key: KEY_PREFERENCES,
            userId: userId
        }]);

        var interests = ["General Knowledge"];
        if (prefsResult.length > 0 && prefsResult[0].value.interests.length > 0) {
            interests = prefsResult[0].value.interests;
        }

        // Pick a random interest for tomorrow's quiz
        var tomorrowCategory = interests[Math.floor(Math.random() * interests.length)];

        // Generate preview
        var preview = {
            category: tomorrowCategory,
            xpMultiplier: 2,
            bonusCoins: 100,
            specialReward: "Mystery Box",
            message: `Tomorrow: ${tomorrowCategory} Quiz with 2x XP! 🔥`,
            notificationText: `Your ${tomorrowCategory} quiz is ready! Don't miss the 2x XP bonus!`
        };

        return JSON.stringify({ success: true, preview: preview });
    } catch (e) {
        logger.error(`[Onboarding] Get tomorrow preview error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Track session for retention analytics
 */
function rpcTrackSession(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);

    try {
        trackUserSession(nk, logger, userId);

        if (input.quizzesPlayed || input.coinsEarned) {
            updateSessionStats(nk, logger, userId, input);
        }

        return JSON.stringify({ success: true });
    } catch (e) {
        logger.error(`[Onboarding] Track session error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Get retention data for analytics
 */
function rpcGetRetentionData(ctx, logger, nk, payload) {
    var userId = ctx.userId;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_FIRST_SESSION,
            key: KEY_SESSION,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No session data" });
        }

        var sessionData = result[0].value;
        var now = Date.now();
        var daysSinceFirst = Math.floor((now - sessionData.firstSessionAt) / (1000 * 60 * 60 * 24));

        var data = {};
        for (var k in sessionData) { data[k] = sessionData[k]; }
        data.daysSinceFirstSession = daysSinceFirst;
        data.isD1 = daysSinceFirst === 1;
        data.isD7 = daysSinceFirst === 7;

        return JSON.stringify({
            success: true,
            data: data
        });
    } catch (e) {
        logger.error(`[Onboarding] Get retention data error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

/**
 * RPC: Grant streak shield to user
 */
function rpcGrantStreakShield(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    var input = JSON.parse(payload);
    var hours = input.hours || 48;

    try {
        var result = nk.storageRead([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId
        }]);

        if (result.length === 0) {
            return JSON.stringify({ success: false, error: "No onboarding state" });
        }

        var state = result[0].value;
        state.streakShieldExpiry = Date.now() + (hours * 60 * 60 * 1000);
        state.lastUpdated = Date.now();

        nk.storageWrite([{
            collection: COLLECTION_ONBOARDING,
            key: KEY_ONBOARDING,
            userId: userId,
            value: state,
            permissionRead: 1,
            permissionWrite: 0
        }]);

        return JSON.stringify({ 
            success: true, 
            streakShieldExpiry: state.streakShieldExpiry,
            hoursRemaining: hours
        });
    } catch (e) {
        logger.error(`[Onboarding] Grant streak shield error: ${e.message}`);
        return JSON.stringify({ success: false, error: e.message });
    }
}

