// --- Module: progression/mastery_system.js ---
/**
 * Prestige & Category Mastery System
 * Rewards deep engagement with specific categories and long-term progression
 * 
 * Impact: D30 +10% retention, increases session duration
 */

// ============================================================================
// MASTERY CONFIGURATION
// ============================================================================

var MASTERY_CONFIG = {
    // XP needed for each level in a category
    levels: [
        0,      // Level 0
        100,    // Level 1
        250,    // Level 2
        500,    // Level 3 (Bronze Badge)
        1000,   // Level 4
        2000,   // Level 5 (Silver Badge)
        4000,   // Level 6
        8000,   // Level 7 (Gold Badge)
        15000,  // Level 8
        30000   // Level 9 (Platinum Badge)
    ],
    
    // Rewards for reaching levels
    rewards: {
        3: { coins: 500, badge: "bronze" },
        5: { coins: 1500, gems: 20, badge: "silver" },
        7: { coins: 5000, gems: 100, badge: "gold" },
        9: { coins: 15000, gems: 500, badge: "platinum" }
    },
    
    // Prestige configuration
    prestige: {
        maxMasteryLevel: 9,
        prestigeLevels: [
            { id: 1, name: "Novice", xpBoost: 1.1, coinBoost: 1.05, requirements: { totalMastery: 5 } },
            { id: 2, name: "Scholar", xpBoost: 1.2, coinBoost: 1.1, requirements: { totalMastery: 15 } },
            { id: 3, name: "Sage", xpBoost: 1.5, coinBoost: 1.2, requirements: { totalMastery: 40 } },
            { id: 4, name: "Master", xpBoost: 2.0, coinBoost: 1.5, requirements: { totalMastery: 80 } },
            { id: 5, name: "Legend", xpBoost: 3.0, coinBoost: 2.0, requirements: { totalMastery: 150 } }
        ]
    }
};

// ============================================================================
// STORAGE KEYS
// ============================================================================

var STORAGE_COLLECTION = "progression";
var STORAGE_KEY_MASTERY = "category_mastery";
var STORAGE_KEY_PRESTIGE = "prestige_data";

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

function getMasteryData(nk, userId) {
    try {
        var objects = nk.storageRead([{
            collection: STORAGE_COLLECTION,
            key: STORAGE_KEY_MASTERY,
            userId: userId
        }]);
        
        if (objects && objects.length > 0) {
            return objects[0].value;
        }
    } catch (e) {
        // No data yet
    }
    
    return {
        categories: {}, // categoryId -> { xp, level, badges: [] }
        totalMasteryLevel: 0,
        lastUpdated: Date.now()
    };
}

function getPrestigeData(nk, userId) {
    try {
        var objects = nk.storageRead([{
            collection: STORAGE_COLLECTION,
            key: STORAGE_KEY_PRESTIGE,
            userId: userId
        }]);
        
        if (objects && objects.length > 0) {
            return objects[0].value;
        }
    } catch (e) {
        // No data yet
    }
    
    return {
        prestigeLevel: 0,
        unlockedPrestigeNames: [],
        currentXpBoost: 1.0,
        currentCoinBoost: 1.0,
        lastUpdated: Date.now()
    };
}

function saveMasteryData(nk, userId, data) {
    data.lastUpdated = Date.now();
    nk.storageWrite([{
        collection: STORAGE_COLLECTION,
        key: STORAGE_KEY_MASTERY,
        userId: userId,
        value: data,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function savePrestigeData(nk, userId, data) {
    data.lastUpdated = Date.now();
    nk.storageWrite([{
        collection: STORAGE_COLLECTION,
        key: STORAGE_KEY_PRESTIGE,
        userId: userId,
        value: data,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function calculateLevel(xp) {
    var level = 0;
    for (var i = 0; i < MASTERY_CONFIG.levels.length; i++) {
        if (xp >= MASTERY_CONFIG.levels[i]) {
            level = i;
        } else {
            break;
        }
    }
    return level;
}

// ============================================================================
// RPC FUNCTIONS
// ============================================================================

/**
 * Add XP to a category after a quiz
 * Payload: { categoryId: string, xp: number }
 */
function rpcAddMasteryXp(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var request = {};
    try {
        request = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid payload" });
    }
    
    var categoryId = request.categoryId;
    var xpToAdd = request.xp || 0;
    
    if (!categoryId) {
        return JSON.stringify({ success: false, error: "Category ID required" });
    }
    
    var masteryData = getMasteryData(nk, ctx.userId);
    var prestigeData = getPrestigeData(nk, ctx.userId);
    
    // Apply prestige boost
    var boostedXp = Math.floor(xpToAdd * (prestigeData.currentXpBoost || 1.0));
    
    if (!masteryData.categories[categoryId]) {
        masteryData.categories[categoryId] = { xp: 0, level: 0, badges: [] };
    }
    
    var oldLevel = masteryData.categories[categoryId].level;
    masteryData.categories[categoryId].xp += boostedXp;
    var newLevel = calculateLevel(masteryData.categories[categoryId].xp);
    
    var levelUps = [];
    if (newLevel > oldLevel) {
        masteryData.categories[categoryId].level = newLevel;
        
        // Grant rewards for each level up
        for (var l = oldLevel + 1; l <= newLevel; l++) {
            var reward = MASTERY_CONFIG.rewards[l];
            if (reward) {
                // Grant rewards to wallet
                var walletChanges = {};
                if (reward.coins) walletChanges.coins = reward.coins;
                if (reward.gems) walletChanges.gems = reward.gems;
                
                if (Object.keys(walletChanges).length > 0) {
                    nk.walletUpdate(ctx.userId, walletChanges, {}, true);
                }
                
                if (reward.badge) {
                    masteryData.categories[categoryId].badges.push(reward.badge);
                }
                
                levelUps.push({ level: l, reward: reward });
            } else {
                levelUps.push({ level: l });
            }
        }
        
        // Update total mastery level
        var total = 0;
        for (var cat in masteryData.categories) {
            total += masteryData.categories[cat].level;
        }
        masteryData.totalMasteryLevel = total;
    }
    
    saveMasteryData(nk, ctx.userId, masteryData);
    
    return JSON.stringify({
        success: true,
        data: {
            categoryId: categoryId,
            addedXp: boostedXp,
            totalXp: masteryData.categories[categoryId].xp,
            level: newLevel,
            levelUps: levelUps,
            totalMasteryLevel: masteryData.totalMasteryLevel
        }
    });
}

/**
 * Get current mastery and prestige state
 */
function rpcGetProgressionState(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var masteryData = getMasteryData(nk, ctx.userId);
    var prestigeData = getPrestigeData(nk, ctx.userId);
    
    // Check if new prestige levels are available
    var nextPrestige = null;
    for (var i = 0; i < MASTERY_CONFIG.prestige.prestigeLevels.length; i++) {
        var p = MASTERY_CONFIG.prestige.prestigeLevels[i];
        if (p.id > prestigeData.prestigeLevel) {
            var met = masteryData.totalMasteryLevel >= p.requirements.totalMastery;
            nextPrestige = {
                id: p.id,
                name: p.name,
                requirements: p.requirements,
                met: met,
                xpBoost: p.xpBoost,
                coinBoost: p.coinBoost
            };
            break;
        }
    }
    
    return JSON.stringify({
        success: true,
        data: {
            mastery: masteryData,
            prestige: prestigeData,
            nextPrestige: nextPrestige,
            levelConfig: MASTERY_CONFIG.levels
        }
    });
}

/**
 * Claim a prestige level if requirements are met
 */
function rpcClaimPrestige(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var masteryData = getMasteryData(nk, ctx.userId);
    var prestigeData = getPrestigeData(nk, ctx.userId);
    
    var nextLevelId = prestigeData.prestigeLevel + 1;
    var nextLevelConfig = null;
    
    for (var i = 0; i < MASTERY_CONFIG.prestige.prestigeLevels.length; i++) {
        if (MASTERY_CONFIG.prestige.prestigeLevels[i].id === nextLevelId) {
            nextLevelConfig = MASTERY_CONFIG.prestige.prestigeLevels[i];
            break;
        }
    }
    
    if (!nextLevelConfig) {
        return JSON.stringify({ success: false, error: "No more prestige levels" });
    }
    
    if (masteryData.totalMasteryLevel < nextLevelConfig.requirements.totalMastery) {
        return JSON.stringify({ success: false, error: "Requirements not met" });
    }
    
    // Update prestige
    prestigeData.prestigeLevel = nextLevelConfig.id;
    prestigeData.unlockedPrestigeNames.push(nextLevelConfig.name);
    prestigeData.currentXpBoost = nextLevelConfig.xpBoost;
    prestigeData.currentCoinBoost = nextLevelConfig.coinBoost;
    
    savePrestigeData(nk, ctx.userId, prestigeData);
    
    logger.info("User " + ctx.userId + " reached prestige level " + nextLevelConfig.id + " (" + nextLevelConfig.name + ")");
    
    return JSON.stringify({
        success: true,
        data: {
            prestigeLevel: prestigeData.prestigeLevel,
            name: nextLevelConfig.name,
            xpBoost: prestigeData.currentXpBoost,
            coinBoost: prestigeData.currentCoinBoost
        }
    });
}

// ============================================================================
// EXPORTS
// ============================================================================

module.exports = {
    rpcAddMasteryXp: rpcAddMasteryXp,
    rpcGetProgressionState: rpcGetProgressionState,
    rpcClaimPrestige: rpcClaimPrestige
};




// --- Module: progression/progressive_unlocks.js ---
/**
 * Progressive Content Unlocks Module
 * Unlocks game features over the first 7 days to maintain engagement
 * 
 * Impact: D7 +5% retention
 */

// ============================================================================
// UNLOCK CONFIGURATION
// ============================================================================

var UNLOCK_CONFIG = {
    // Day 1: Basic features (default)
    day1: {
        features: ["basic_quiz", "championship", "daily_quiz"],
        rewards: { coins: 50 },
        message: "Welcome! Start your trivia journey!"
    },
    // Day 2: Engagement features
    day2: {
        features: ["lucky_wheel", "daily_streak", "power_ups"],
        rewards: { coins: 100, energy: 3 },
        message: "🎡 Lucky Wheel unlocked! Spin for rewards!",
        requirement: { type: "login", day: 2 }
    },
    // Day 3: Social features
    day3: {
        features: ["multiplayer", "friends_list", "chat"],
        rewards: { coins: 150, gems: 10 },
        message: "⚔️ Multiplayer unlocked! Battle friends!",
        requirement: { type: "quizzes_won", count: 3 }
    },
    // Day 4: Content creation
    day4: {
        features: ["link_and_play", "custom_quizzes", "share_quiz"],
        rewards: { coins: 200, gems: 15 },
        message: "📚 Link & Play unlocked! Create your own quizzes!",
        requirement: { type: "login", day: 4 }
    },
    // Day 5: Advanced modes
    day5: {
        features: ["survival_mode", "timed_challenge", "hard_mode"],
        rewards: { coins: 250, gems: 20, mystery_box: 1 },
        message: "💀 Survival Mode unlocked! How long can you last?",
        requirement: { type: "quizzes_completed", count: 10 }
    },
    // Day 6: Competitive features
    day6: {
        features: ["weekly_tournament", "global_leaderboard", "rankings"],
        rewards: { coins: 300, gems: 25 },
        message: "🏆 Weekly Tournament unlocked! Compete globally!",
        requirement: { type: "login", day: 6 }
    },
    // Day 7: Premium trial
    day7: {
        features: ["premium_trial", "all_categories", "ad_free_trial"],
        rewards: { coins: 500, gems: 50, premium_days: 3 },
        message: "👑 VIP Trial unlocked! 3 days of Premium FREE!",
        requirement: { type: "login", day: 7 }
    }
};

// All possible features
var ALL_FEATURES = [
    "basic_quiz", "championship", "daily_quiz",
    "lucky_wheel", "daily_streak", "power_ups",
    "multiplayer", "friends_list", "chat",
    "link_and_play", "custom_quizzes", "share_quiz",
    "survival_mode", "timed_challenge", "hard_mode",
    "weekly_tournament", "global_leaderboard", "rankings",
    "premium_trial", "all_categories", "ad_free_trial"
];

// ============================================================================
// STORAGE KEYS
// ============================================================================

var STORAGE_COLLECTION = "progression";
var STORAGE_KEY_UNLOCKS = "progressive_unlocks";

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

function getUnlockData(nk, userId) {
    try {
        var objects = nk.storageRead([{
            collection: STORAGE_COLLECTION,
            key: STORAGE_KEY_UNLOCKS,
            userId: userId
        }]);
        
        if (objects && objects.length > 0) {
            return objects[0].value;
        }
    } catch (e) {
        // No data yet
    }
    
    // Initialize default data
    return {
        firstLoginDate: Date.now(),
        currentDay: 1,
        unlockedFeatures: UNLOCK_CONFIG.day1.features.slice(),
        claimedDays: [1],
        totalQuizzesCompleted: 0,
        totalQuizzesWon: 0,
        lastCheckDate: Date.now()
    };
}

function saveUnlockData(nk, userId, data) {
    data.lastUpdated = Date.now();
    
    nk.storageWrite([{
        collection: STORAGE_COLLECTION,
        key: STORAGE_KEY_UNLOCKS,
        userId: userId,
        value: data,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function calculateCurrentDay(firstLoginDate) {
    var now = Date.now();
    var daysSinceFirst = Math.floor((now - firstLoginDate) / (24 * 60 * 60 * 1000));
    return Math.min(daysSinceFirst + 1, 7); // Cap at day 7
}

function checkRequirement(data, requirement) {
    if (!requirement) return true;
    
    switch (requirement.type) {
        case "login":
            return data.currentDay >= requirement.day;
        case "quizzes_won":
            return data.totalQuizzesWon >= requirement.count;
        case "quizzes_completed":
            return data.totalQuizzesCompleted >= requirement.count;
        default:
            return true;
    }
}

function grantRewards(nk, userId, rewards, logger) {
    if (!rewards) return;
    
    try {
        // Grant coins
        if (rewards.coins) {
            nk.walletUpdate(userId, { coins: rewards.coins }, {}, true);
            logger.info("Granted " + rewards.coins + " coins to " + userId);
        }
        
        // Grant gems
        if (rewards.gems) {
            nk.walletUpdate(userId, { gems: rewards.gems }, {}, true);
            logger.info("Granted " + rewards.gems + " gems to " + userId);
        }
        
        // Grant energy
        if (rewards.energy) {
            nk.walletUpdate(userId, { energy: rewards.energy }, {}, true);
        }
        
        // Grant premium days
        if (rewards.premium_days) {
            var premiumExpiry = Date.now() + (rewards.premium_days * 24 * 60 * 60 * 1000);
            nk.storageWrite([{
                collection: "premium",
                key: "trial",
                userId: userId,
                value: { expiresAt: premiumExpiry, type: "trial" },
                permissionRead: 1,
                permissionWrite: 0
            }]);
        }
        
        // Grant mystery box
        if (rewards.mystery_box) {
            var inventoryData = { mystery_boxes: rewards.mystery_box };
            nk.walletUpdate(userId, inventoryData, {}, true);
        }
    } catch (e) {
        logger.error("Error granting rewards: " + e.message);
    }
}

// ============================================================================
// RPC FUNCTIONS
// ============================================================================

/**
 * Get current unlock state
 * Returns: unlockedFeatures, currentDay, nextUnlock, progress
 */
function rpcGetUnlockState(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var data = getUnlockData(nk, ctx.userId);
    
    // Update current day
    data.currentDay = calculateCurrentDay(data.firstLoginDate);
    saveUnlockData(nk, ctx.userId, data);
    
    // Calculate next unlock info
    var nextDay = null;
    var nextUnlock = null;
    
    for (var day = 1; day <= 7; day++) {
        var dayKey = "day" + day;
        var config = UNLOCK_CONFIG[dayKey];
        
        if (config && data.claimedDays.indexOf(day) === -1) {
            nextDay = day;
            nextUnlock = {
                day: day,
                features: config.features,
                rewards: config.rewards,
                message: config.message,
                canClaim: checkRequirement(data, config.requirement),
                requirement: config.requirement
            };
            break;
        }
    }
    
    // Build locked features list
    var lockedFeatures = [];
    ALL_FEATURES.forEach(function(feature) {
        if (data.unlockedFeatures.indexOf(feature) === -1) {
            lockedFeatures.push(feature);
        }
    });
    
    return JSON.stringify({
        success: true,
        data: {
            currentDay: data.currentDay,
            firstLoginDate: data.firstLoginDate,
            unlockedFeatures: data.unlockedFeatures,
            lockedFeatures: lockedFeatures,
            claimedDays: data.claimedDays,
            nextUnlock: nextUnlock,
            totalQuizzesCompleted: data.totalQuizzesCompleted,
            totalQuizzesWon: data.totalQuizzesWon,
            allUnlocked: data.claimedDays.length >= 7
        }
    });
}

/**
 * Claim unlock for a specific day
 * Payload: { day: number }
 */
function rpcClaimUnlock(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var request = {};
    try {
        request = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid payload" });
    }
    
    var day = request.day;
    if (!day || day < 1 || day > 7) {
        return JSON.stringify({ success: false, error: "Invalid day" });
    }
    
    var data = getUnlockData(nk, ctx.userId);
    data.currentDay = calculateCurrentDay(data.firstLoginDate);
    
    // Check if already claimed
    if (data.claimedDays.indexOf(day) !== -1) {
        return JSON.stringify({ success: false, error: "Already claimed" });
    }
    
    // Check if day is reachable
    if (day > data.currentDay) {
        return JSON.stringify({ success: false, error: "Day not yet available" });
    }
    
    // Check requirements
    var dayKey = "day" + day;
    var config = UNLOCK_CONFIG[dayKey];
    
    if (!config) {
        return JSON.stringify({ success: false, error: "Invalid day config" });
    }
    
    if (!checkRequirement(data, config.requirement)) {
        return JSON.stringify({ 
            success: false, 
            error: "Requirement not met",
            requirement: config.requirement
        });
    }
    
    // Claim the unlock
    data.claimedDays.push(day);
    config.features.forEach(function(feature) {
        if (data.unlockedFeatures.indexOf(feature) === -1) {
            data.unlockedFeatures.push(feature);
        }
    });
    
    // Grant rewards
    grantRewards(nk, ctx.userId, config.rewards, logger);
    
    // Save
    saveUnlockData(nk, ctx.userId, data);
    
    logger.info("User " + ctx.userId + " claimed Day " + day + " unlock");
    
    return JSON.stringify({
        success: true,
        data: {
            day: day,
            unlockedFeatures: config.features,
            rewards: config.rewards,
            message: config.message,
            allUnlockedFeatures: data.unlockedFeatures
        }
    });
}

/**
 * Check if a specific feature is unlocked
 */
function rpcCheckFeatureUnlocked(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var request = {};
    try {
        request = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid payload" });
    }
    
    var feature = request.feature;
    if (!feature) {
        return JSON.stringify({ success: false, error: "Feature required" });
    }
    
    var data = getUnlockData(nk, ctx.userId);
    var isUnlocked = data.unlockedFeatures.indexOf(feature) !== -1;
    
    // Find which day unlocks this feature
    var unlockDay = null;
    for (var day = 1; day <= 7; day++) {
        var config = UNLOCK_CONFIG["day" + day];
        if (config && config.features.indexOf(feature) !== -1) {
            unlockDay = day;
            break;
        }
    }
    
    return JSON.stringify({
        success: true,
        data: {
            feature: feature,
            isUnlocked: isUnlocked,
            unlockDay: unlockDay,
            currentDay: calculateCurrentDay(data.firstLoginDate)
        }
    });
}

/**
 * Update progress (quizzes completed/won)
 */
function rpcUpdateProgress(ctx, logger, nk, payload) {
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "Not authenticated" });
    }
    
    var request = {};
    try {
        request = JSON.parse(payload || "{}");
    } catch (e) {
        return JSON.stringify({ success: false, error: "Invalid payload" });
    }
    
    var data = getUnlockData(nk, ctx.userId);
    
    if (request.quizCompleted) {
        data.totalQuizzesCompleted++;
    }
    if (request.quizWon) {
        data.totalQuizzesWon++;
    }
    
    data.currentDay = calculateCurrentDay(data.firstLoginDate);
    saveUnlockData(nk, ctx.userId, data);
    
    // Check if any new unlocks are available
    var newUnlocksAvailable = [];
    for (var day = 1; day <= data.currentDay; day++) {
        if (data.claimedDays.indexOf(day) === -1) {
            var config = UNLOCK_CONFIG["day" + day];
            if (config && checkRequirement(data, config.requirement)) {
                newUnlocksAvailable.push({
                    day: day,
                    features: config.features,
                    message: config.message
                });
            }
        }
    }
    
    return JSON.stringify({
        success: true,
        data: {
            totalQuizzesCompleted: data.totalQuizzesCompleted,
            totalQuizzesWon: data.totalQuizzesWon,
            newUnlocksAvailable: newUnlocksAvailable
        }
    });
}

// ============================================================================
// EXPORTS
// ============================================================================

module.exports = {
    rpcGetUnlockState: rpcGetUnlockState,
    rpcClaimUnlock: rpcClaimUnlock,
    rpcCheckFeatureUnlocked: rpcCheckFeatureUnlocked,
    rpcUpdateProgress: rpcUpdateProgress
};




// --- Module: push_notifications/push_notifications.js ---
// push_notifications.js - Push Notification System (AWS SNS + Pinpoint + Lambda)
// Unity does NOT use AWS SDK - Unity only sends raw push tokens
// Nakama forwards to AWS Lambda Function URL for endpoint creation

/**
 * Lambda Function URL for push endpoint registration
 * This should be configured in your environment
 */
var LAMBDA_FUNCTION_URL = (typeof process!=="undefined"&&process.env?process.env.PUSH_LAMBDA_URL:undefined) || "https://your-lambda-url.lambda-url.region.on.aws/register-endpoint";

/**
 * Lambda Function URL for sending push notifications
 */
var LAMBDA_PUSH_URL = (typeof process!=="undefined"&&process.env?process.env.PUSH_SEND_URL:undefined) || "https://your-lambda-url.lambda-url.region.on.aws/send-push";

/**
 * Platform token types
 */
var PLATFORM_TYPES = {
    ios: "APNS",
    android: "FCM", 
    web: "FCM",
    windows: "WNS"
};

/**
 * Store endpoint ARN for user device
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {string} platform - Platform type (ios, android, web, windows)
 * @param {string} endpointArn - SNS endpoint ARN
 * @returns {boolean} Success status
 */
function storeEndpointArn(nk, logger, userId, gameId, platform, endpointArn) {
    var collection = "push_endpoints";
    var key = "push_endpoint_" + userId + "_" + gameId + "_" + platform;
    
    var data = {
        userId: userId,
        gameId: gameId,
        platform: platform,
        endpointArn: endpointArn,
        createdAt: utils.getCurrentTimestamp(),
        updatedAt: utils.getCurrentTimestamp()
    };
    
    return utils.writeStorage(nk, logger, collection, key, userId, data);
}

/**
 * Get endpoint ARN for user device
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {string} platform - Platform type
 * @returns {object|null} Endpoint data or null
 */
function getEndpointArn(nk, logger, userId, gameId, platform) {
    var collection = "push_endpoints";
    var key = "push_endpoint_" + userId + "_" + gameId + "_" + platform;
    return utils.readStorage(nk, logger, collection, key, userId);
}

/**
 * Get all endpoint ARNs for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @returns {Array} List of endpoint data
 */
function getAllEndpointArns(nk, logger, userId, gameId) {
    var collection = "push_endpoints";
    var endpoints = [];
    
    try {
        var records = nk.storageList(userId, collection, 100);
        for (var i = 0; i < records.length; i++) {
            var value = records[i].value;
            if (value.gameId === gameId) {
                endpoints.push(value);
            }
        }
    } catch (err) {
        utils.logWarn(logger, "Failed to list endpoints: " + err.message);
    }
    
    return endpoints;
}

/**
 * RPC: Register device token
 * Unity sends raw device token, Nakama forwards to Lambda
 * Lambda creates SNS endpoint and returns ARN
 * 
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with:
 *   {
 *     gameId: "uuid",
 *     platform: "ios"|"android"|"web"|"windows",
 *     token: "raw_device_token"
 *   }
 * @returns {string} JSON response
 */
function rpcPushRegisterToken(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC push_register_token called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['gameId', 'platform', 'token']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var gameId = data.gameId;
    if (!utils.isValidUUID(gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var platform = data.platform;
    var token = data.token;
    
    // Validate platform
    if (!PLATFORM_TYPES[platform]) {
        return utils.handleError(ctx, null, "Invalid platform. Must be: ios, android, web, or windows");
    }
    
    utils.logInfo(logger, "Registering " + platform + " push token for user " + userId);
    
    // Call Lambda to create SNS endpoint
    var lambdaPayload = {
        userId: userId,
        gameId: gameId,
        platform: platform,
        platformType: PLATFORM_TYPES[platform],
        deviceToken: token
    };
    
    var lambdaResponse;
    try {
        lambdaResponse = nk.httpRequest(
            LAMBDA_FUNCTION_URL,
            "post",
            {
                "Content-Type": "application/json",
                "Accept": "application/json"
            },
            JSON.stringify(lambdaPayload)
        );
    } catch (err) {
        utils.logError(logger, "Lambda request failed: " + err.message);
        return utils.handleError(ctx, err, "Failed to register push token with Lambda");
    }
    
    if (lambdaResponse.code !== 200 && lambdaResponse.code !== 201) {
        utils.logError(logger, "Lambda returned code " + lambdaResponse.code);
        return utils.handleError(ctx, null, "Lambda endpoint registration failed with code " + lambdaResponse.code);
    }
    
    var lambdaData;
    try {
        lambdaData = JSON.parse(lambdaResponse.body);
    } catch (err) {
        return utils.handleError(ctx, null, "Invalid Lambda response JSON");
    }
    
    if (!lambdaData.success || !lambdaData.snsEndpointArn) {
        return utils.handleError(ctx, null, "Lambda did not return endpoint ARN: " + (lambdaData.error || "Unknown error"));
    }
    
    var endpointArn = lambdaData.snsEndpointArn;
    
    // Store endpoint ARN
    if (!storeEndpointArn(nk, logger, userId, gameId, platform, endpointArn)) {
        return utils.handleError(ctx, null, "Failed to store endpoint ARN");
    }
    
    utils.logInfo(logger, "Successfully registered push endpoint: " + endpointArn);
    
    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        platform: platform,
        endpointArn: endpointArn,
        registeredAt: utils.getCurrentTimestamp()
    });
}

/**
 * RPC: Send push notification event
 * Server-side triggered push notifications
 * 
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with:
 *   {
 *     targetUserId: "uuid",
 *     gameId: "uuid",
 *     eventType: "daily_reward_available|mission_completed|streak_warning|friend_online|etc",
 *     title: "Notification Title",
 *     body: "Notification Body",
 *     data: { custom: "data" }
 *   }
 * @returns {string} JSON response
 */
function rpcPushSendEvent(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC push_send_event called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['targetUserId', 'gameId', 'eventType', 'title', 'body']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var gameId = data.gameId;
    if (!utils.isValidUUID(gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var targetUserId = data.targetUserId;
    var eventType = data.eventType;
    var title = data.title;
    var body = data.body;
    var customData = data.data || {};
    
    utils.logInfo(logger, "Sending push notification to user " + targetUserId + " for event " + eventType);
    
    // Get all endpoints for target user
    var endpoints = getAllEndpointArns(nk, logger, targetUserId, gameId);
    
    if (endpoints.length === 0) {
        return JSON.stringify({
            success: false,
            error: "No registered push endpoints for user"
        });
    }
    
    var sentCount = 0;
    var errors = [];
    
    // Send to each endpoint
    for (var i = 0; i < endpoints.length; i++) {
        var endpoint = endpoints[i];
        
        var pushPayload = {
            endpointArn: endpoint.endpointArn,
            platform: endpoint.platform,
            title: title,
            body: body,
            data: customData,
            gameId: gameId,
            eventType: eventType
        };
        
        try {
            var lambdaResponse = nk.httpRequest(
                LAMBDA_PUSH_URL,
                "post",
                {
                    "Content-Type": "application/json",
                    "Accept": "application/json"
                },
                JSON.stringify(pushPayload)
            );
            
            if (lambdaResponse.code === 200 || lambdaResponse.code === 201) {
                sentCount++;
                utils.logInfo(logger, "Push sent to " + endpoint.platform + " endpoint");
            } else {
                errors.push({
                    platform: endpoint.platform,
                    error: "Lambda returned code " + lambdaResponse.code
                });
            }
        } catch (err) {
            errors.push({
                platform: endpoint.platform,
                error: err.message
            });
            utils.logWarn(logger, "Failed to send push to " + endpoint.platform + ": " + err.message);
        }
    }
    
    // Log notification event
    var notificationLog = {
        targetUserId: targetUserId,
        gameId: gameId,
        eventType: eventType,
        title: title,
        body: body,
        sentCount: sentCount,
        totalEndpoints: endpoints.length,
        timestamp: utils.getCurrentTimestamp()
    };
    
    var logKey = "push_log_" + targetUserId + "_" + utils.getUnixTimestamp();
    utils.writeStorage(nk, logger, "push_notification_logs", logKey, targetUserId, notificationLog);
    
    return JSON.stringify({
        success: sentCount > 0,
        targetUserId: targetUserId,
        gameId: gameId,
        eventType: eventType,
        sentCount: sentCount,
        totalEndpoints: endpoints.length,
        errors: errors.length > 0 ? errors : undefined,
        timestamp: utils.getCurrentTimestamp()
    });
}

/**
 * RPC: Get user's registered endpoints
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with { gameId: "uuid" }
 * @returns {string} JSON response
 */
function rpcPushGetEndpoints(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC push_get_endpoints called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['gameId']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    var gameId = data.gameId;
    if (!utils.isValidUUID(gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var endpoints = getAllEndpointArns(nk, logger, userId, gameId);
    
    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        endpoints: endpoints,
        count: endpoints.length,
        timestamp: utils.getCurrentTimestamp()
    });
}


// --- Module: quests_analytics_bridge.js ---
/**
 * quests_analytics_bridge.js
 *
 * Nakama RPCs that expose analytics and player-profile data for the
 * quests-economy NestJS API.  This replaces the direct SQL queries that
 * the NestJS side was running against Nakama's storage / users tables
 * through the wrong DataSource.
 *
 * RPCs registered:
 *   qe_player_full_profile  – single-user profile aggregate
 *   qe_stale_sessions       – batch: sessions inactive > N days
 *   qe_cohort_export        – batch: active sessions + events
 *   qe_user_event_summary   – single-user event ring-buffer
 */

// ─── helpers ─────────────────────────────────────────────────────

function _qeParseMaybeJson(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch (e) { return v; }
}

// ─── RPC: qe_player_full_profile ─────────────────────────────────

function rpcQePlayerFullProfile(ctx, logger, nk, payload) {
  var input = JSON.parse(payload);
  var userId = input.user_id || '';
  if (!userId) {
    throw Error('user_id is required');
  }

  var profile = {};
  var gameStats = {};
  var analytics = {};
  var questAnalytics = null;

  try {
    var records = nk.storageRead([
      { collection: 'user_metadata', key: 'profile',    userId: userId },
      { collection: 'user_metadata', key: 'game_stats', userId: userId },
      { collection: 'user_metadata', key: 'analytics',  userId: userId },
      { collection: 'quest_analytics', key: 'summary',  userId: userId }
    ]);

    for (var i = 0; i < records.length; i++) {
      var rec = records[i];
      if (rec.collection === 'user_metadata') {
        if (rec.key === 'profile')    profile    = rec.value || {};
        if (rec.key === 'game_stats') gameStats  = rec.value || {};
        if (rec.key === 'analytics')  analytics  = rec.value || {};
      }
      if (rec.collection === 'quest_analytics' && rec.key === 'summary') {
        questAnalytics = rec.value || null;
      }
    }
  } catch (e) {
    logger.warn('[QeAnalytics] storageRead failed for ' + userId + ': ' + e);
  }

  var userRow = null;
  try {
    var userRows = nk.sqlQuery(
      'SELECT id, username, display_name, lang_tag, location, timezone, ' +
      'metadata, wallet, create_time, update_time, edge_count ' +
      'FROM users WHERE id = $1 LIMIT 1',
      [userId]
    );
    if (userRows && userRows.length > 0) {
      userRow = userRows[0];
      if (userRow.metadata && typeof userRow.metadata === 'string') {
        try { userRow.metadata = JSON.parse(userRow.metadata); } catch (e2) { /* keep raw */ }
      }
    }
  } catch (e) {
    logger.warn('[QeAnalytics] users query failed: ' + e);
  }

  var leaderboardCount = 0;
  try {
    var lbRows = nk.sqlQuery(
      'SELECT COUNT(*)::int AS cnt FROM leaderboard_record WHERE owner_id = $1',
      [userId]
    );
    if (lbRows && lbRows.length > 0) {
      leaderboardCount = Number(lbRows[0].cnt) || 0;
    }
  } catch (e) {
    logger.warn('[QeAnalytics] leaderboard count query failed: ' + e);
  }

  return JSON.stringify({
    profile:           profile,
    game_stats:        gameStats,
    analytics:         analytics,
    quest_analytics:   questAnalytics,
    user:              userRow,
    leaderboard_count: leaderboardCount
  });
}

// ─── RPC: qe_stale_sessions ─────────────────────────────────────

function rpcQeStaleSessions(ctx, logger, nk, payload) {
  var input = JSON.parse(payload);
  var inactiveDays = Number(input.inactive_days) || 3;
  var limit = Math.min(Number(input.limit) || 5000, 10000);

  try {
    var rows = nk.sqlQuery(
      "SELECT user_id, value FROM storage " +
      "WHERE collection = 'user_sessions' AND key = 'current' " +
      "AND update_time < (CURRENT_TIMESTAMP - ($1::int * interval '1 day')) " +
      "ORDER BY update_time ASC LIMIT $2::int",
      [inactiveDays, limit]
    );

    var results = [];
    for (var i = 0; i < rows.length; i++) {
      results.push({
        user_id: rows[i].user_id,
        session: _qeParseMaybeJson(rows[i].value)
      });
    }

    return JSON.stringify({ sessions: results, count: results.length });
  } catch (e) {
    logger.error('[QeAnalytics] qe_stale_sessions failed: ' + e);
    return JSON.stringify({ sessions: [], count: 0, error: String(e) });
  }
}

// ─── RPC: qe_cohort_export ──────────────────────────────────────

function rpcQeCohortExport(ctx, logger, nk, payload) {
  var input = JSON.parse(payload);
  var activeSinceDays = Number(input.active_since_days) || 30;
  var limit = Math.min(Number(input.limit) || 500, 2000);

  try {
    var rows = nk.sqlQuery(
      "SELECT user_id, value FROM storage " +
      "WHERE collection = 'user_sessions' AND key = 'current' " +
      "AND update_time >= (CURRENT_TIMESTAMP - ($1::int * interval '1 day')) " +
      "ORDER BY update_time DESC LIMIT $2::int",
      [activeSinceDays, limit]
    );

    // Batch-read analytics_events for every returned user in one call
    var readRequests = [];
    for (var i = 0; i < rows.length; i++) {
      readRequests.push({
        collection: 'analytics_events',
        key:        'events',
        userId:     rows[i].user_id
      });
    }

    var evMap = {};
    if (readRequests.length > 0) {
      try {
        var evRecords = nk.storageRead(readRequests);
        for (var j = 0; j < evRecords.length; j++) {
          evMap[evRecords[j].userId] = evRecords[j].value;
        }
      } catch (e) {
        logger.warn('[QeAnalytics] batch event read failed: ' + e);
      }
    }

    var cohort = [];
    for (var k = 0; k < rows.length; k++) {
      var uid = rows[k].user_id;
      cohort.push({
        user_id: uid,
        session: _qeParseMaybeJson(rows[k].value),
        events:  evMap[uid] || null
      });
    }

    return JSON.stringify({ cohort: cohort, count: cohort.length });
  } catch (e) {
    logger.error('[QeAnalytics] qe_cohort_export failed: ' + e);
    return JSON.stringify({ cohort: [], count: 0, error: String(e) });
  }
}

// ─── RPC: qe_user_event_summary ─────────────────────────────────

function rpcQeUserEventSummary(ctx, logger, nk, payload) {
  var input = JSON.parse(payload);
  var userId = input.user_id || '';
  if (!userId) {
    throw Error('user_id is required');
  }

  try {
    var records = nk.storageRead([
      { collection: 'analytics_events', key: 'events', userId: userId }
    ]);

    if (records && records.length > 0 && records[0].value) {
      return JSON.stringify({ events: records[0].value, found: true });
    }
  } catch (e) {
    logger.warn('[QeAnalytics] qe_user_event_summary failed for ' + userId + ': ' + e);
  }

  return JSON.stringify({ events: null, found: false });
}

// ─── Registration (postbuild picks up initializer.registerRpc) ──

function _QeAnalyticsBridgeInit(ctx, logger, nk, initializer) {
  logger.info('[QeAnalyticsBridge] Registering RPCs');
  __rpc_qe_player_full_profile = __rpc_qe_player_full_profile || (rpcQePlayerFullProfile);
  __rpc_qe_stale_sessions = __rpc_qe_stale_sessions || (rpcQeStaleSessions);
  __rpc_qe_cohort_export = __rpc_qe_cohort_export || (rpcQeCohortExport);
  __rpc_qe_user_event_summary = __rpc_qe_user_event_summary || (rpcQeUserEventSummary);
  logger.info('[QeAnalyticsBridge] 4 RPCs registered');
}


// --- Module: quests_economy_bridge.js ---
/**
 * Quests Economy Bridge — connects Nakama wallet operations to the
 * quests-economy global PointsLedger via S2S authenticated HTTP calls.
 *
 * The quests-economy API is the single source of truth for all wallet balances.
 * This module exposes RPCs that games can call to earn/spend/query the global wallet.
 *
 * Environment variables (set in Nakama config or docker-compose):
 *   QUESTS_ECONOMY_API_URL  — e.g. http://quests-api:3001
 *   NAKAMA_WEBHOOK_SECRET   — shared HMAC secret for S2S auth
 *   DEFAULT_GAME_ID         — default game_id if not provided
 */

var QUESTS_API_URL = '';
var WEBHOOK_SECRET = '';
var DEFAULT_GAME_ID = 'f6f7fe36-03de-43b8-8b5d-1a1892da4eed';

/**
 * Per-game conversion ratios.
 * Key = game_id, value = how many game coins equal 1 global wallet point.
 * E.g. 1000 means 1000 game coins = 1 global point.
 */
var GAME_CONVERSION_RATIOS = {};

function _QuestsBridgeInit(ctx, logger, nk, initializer) {
    QUESTS_API_URL = (ctx.env['QUESTS_ECONOMY_API_URL'] || 'http://localhost:3001').replace(/\/$/, '');
    WEBHOOK_SECRET = ctx.env['NAKAMA_WEBHOOK_SECRET'] || '';
    DEFAULT_GAME_ID = ctx.env['DEFAULT_GAME_ID'] || DEFAULT_GAME_ID;

    loadConversionRatios(nk, logger);

    logger.info('[QuestsBridge] Initializing — API: ' + QUESTS_API_URL);

    __rpc_global_wallet_balance = __rpc_global_wallet_balance || (rpcGlobalWalletBalance);
    __rpc_global_wallet_earn = __rpc_global_wallet_earn || (rpcGlobalWalletEarn);
    __rpc_global_wallet_spend = __rpc_global_wallet_spend || (rpcGlobalWalletSpend);
    __rpc_global_wallet_history = __rpc_global_wallet_history || (rpcGlobalWalletHistory);
    __rpc_game_to_global_convert = __rpc_game_to_global_convert || (rpcGameToGlobalConvert);
    __rpc_game_to_global_preview = __rpc_game_to_global_preview || (rpcGameToGlobalPreview);
    __rpc_conversion_ratio_set = __rpc_conversion_ratio_set || (rpcConversionRatioSet);
    __rpc_conversion_ratio_get = __rpc_conversion_ratio_get || (rpcConversionRatioGet);

    __rpc_intellidraws_list = __rpc_intellidraws_list || (rpcIntelliDrawsList);
    __rpc_intellidraws_winners = __rpc_intellidraws_winners || (rpcIntelliDrawsWinners);
    __rpc_intellidraws_enter = __rpc_intellidraws_enter || (rpcIntelliDrawsEnter);
    __rpc_intellidraws_past = __rpc_intellidraws_past || (rpcIntelliDrawsPast);

    logger.info('[QuestsBridge] RPCs registered (wallet + conversion + intellidraws)');
}

function signRequest(nk, body) {
    return nk.hmacSha256Hash(WEBHOOK_SECRET, body);
}

// Lightweight game wallet helpers (self-contained, mirrors index.js storage format)
function bridgeGetGameWallet(nk, logger, userId, gameId) {
    var key = 'wallet_' + userId + '_' + gameId;
    try {
        var records = nk.storageRead([{
            collection: 'wallets',
            key: key,
            userId: userId,
        }]);
        if (records && records.length > 0 && records[0].value) {
            var wallet = records[0].value;
            if (wallet.currencies) {
                if (wallet.currencies.game === undefined) wallet.currencies.game = wallet.currencies.tokens || 0;
                if (wallet.currencies.tokens === undefined) wallet.currencies.tokens = wallet.currencies.game || 0;
            }
            return wallet;
        }
    } catch (err) {
        logger.warn('[QuestsBridge] Failed to read game wallet: ' + err.message);
    }
    return {
        userId: userId,
        gameId: gameId,
        currencies: { game: 0, tokens: 0, xp: 0 },
        items: {},
    };
}

function bridgeSaveGameWallet(nk, logger, userId, gameId, wallet) {
    var key = 'wallet_' + userId + '_' + gameId;
    try {
        nk.storageWrite([{
            collection: 'wallets',
            key: key,
            userId: userId,
            value: wallet,
            permissionRead: 1,
            permissionWrite: 0,
        }]);
        return true;
    } catch (err) {
        logger.error('[QuestsBridge] Failed to save game wallet: ' + err.message);
        return false;
    }
}

function bridgeLogTransaction(nk, logger, userId, data) {
    try {
        var key = 'txn_' + Date.now() + '_' + Math.random().toString(36).substring(2, 8);
        nk.storageWrite([{
            collection: 'transaction_logs',
            key: key,
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0,
        }]);
    } catch (err) {
        logger.warn('[QuestsBridge] Failed to log transaction: ' + err.message);
    }
}

function questsApiCall(nk, logger, userId, gameId, endpoint, body) {
    var bodyStr = JSON.stringify(body || {});
    var signature = signRequest(nk, bodyStr);
    var url = QUESTS_API_URL + '/game-bridge/s2s/wallet/' + endpoint;

    var headers = {
        'Content-Type': 'application/json',
        'X-Source': 'nakama-rpc',
        'X-Webhook-Signature': signature,
        'X-User-Id': userId,
        'X-Game-Id': gameId || DEFAULT_GAME_ID,
    };

    try {
        var response = nk.httpRequest(url, 'post', headers, bodyStr);
        if (response.code >= 200 && response.code < 300) {
            return JSON.parse(response.body);
        }
        logger.error('[QuestsBridge] API error ' + response.code + ': ' + response.body);
        return { error: 'API returned ' + response.code, details: response.body };
    } catch (err) {
        logger.error('[QuestsBridge] HTTP request failed: ' + err.message);
        return { error: 'HTTP request failed', details: err.message };
    }
}

/**
 * RPC: Get global wallet balance from quests-economy PointsLedger.
 * Payload: {} (none required)
 * Returns: { userId, balance }
 */
function rpcGlobalWalletBalance(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var result = questsApiCall(nk, logger, userId, DEFAULT_GAME_ID, 'balance', {});

    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }

    return JSON.stringify({
        success: true,
        userId: userId,
        balance: result.balance || 0,
    });
}

/**
 * RPC: Earn points into the global wallet.
 * Payload: { amount: number, sourceType?: string, sourceId?: string, description?: string }
 * Returns: { userId, amountEarned, newBalance }
 */
function rpcGlobalWalletEarn(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    var amount = parsed.amount;
    if (!amount || amount <= 0) {
        return JSON.stringify({ success: false, error: 'amount must be > 0' });
    }

    var gameId = parsed.gameId || DEFAULT_GAME_ID;
    var body = {
        amount: amount,
        sourceType: parsed.sourceType || 'game_reward',
        sourceId: parsed.sourceId || gameId,
        description: parsed.description || ('Game reward: ' + amount + ' points'),
    };

    var result = questsApiCall(nk, logger, userId, gameId, 'earn', body);

    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }

    logger.info('[QuestsBridge] Earned ' + amount + ' for user ' + userId + ' → balance ' + result.newBalance);

    return JSON.stringify({
        success: true,
        userId: userId,
        amountEarned: result.amountEarned,
        newBalance: result.newBalance,
    });
}

/**
 * RPC: Spend points from the global wallet.
 * Payload: { amount: number, sourceType?: string, sourceId?: string, description?: string }
 * Returns: { userId, amountSpent, newBalance }
 */
function rpcGlobalWalletSpend(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    var amount = parsed.amount;
    if (!amount || amount <= 0) {
        return JSON.stringify({ success: false, error: 'amount must be > 0' });
    }

    var gameId = parsed.gameId || DEFAULT_GAME_ID;
    var body = {
        amount: amount,
        sourceType: parsed.sourceType || 'game_spend',
        sourceId: parsed.sourceId || gameId,
        description: parsed.description || ('Game spend: ' + amount + ' points'),
    };

    var result = questsApiCall(nk, logger, userId, gameId, 'spend', body);

    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }

    logger.info('[QuestsBridge] Spent ' + amount + ' for user ' + userId + ' → balance ' + result.newBalance);

    return JSON.stringify({
        success: true,
        userId: userId,
        amountSpent: result.amountSpent,
        newBalance: result.newBalance,
    });
}

/**
 * RPC: Get global wallet transaction history.
 * Payload: { limit?: number, offset?: number }
 * Returns: { userId, entries: [...], total }
 */
function rpcGlobalWalletHistory(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    var body = {
        limit: parsed.limit || 50,
        offset: parsed.offset || 0,
    };

    var result = questsApiCall(nk, logger, userId, DEFAULT_GAME_ID, 'history', body);

    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }

    return JSON.stringify({
        success: true,
        userId: userId,
        entries: result.entries || [],
        total: result.total || 0,
    });
}

// ═══════════════════════════════════════════════════════════════════
//  CONVERSION RATIO STORAGE
// ═══════════════════════════════════════════════════════════════════

var CONVERSION_STORAGE_COLLECTION = 'economy_config';
var CONVERSION_STORAGE_KEY = 'game_conversion_ratios';
var SYSTEM_USER_ID = '00000000-0000-0000-0000-000000000000';

function loadConversionRatios(nk, logger) {
    try {
        var records = nk.storageRead([{
            collection: CONVERSION_STORAGE_COLLECTION,
            key: CONVERSION_STORAGE_KEY,
            userId: SYSTEM_USER_ID,
        }]);
        if (records && records.length > 0 && records[0].value) {
            GAME_CONVERSION_RATIOS = records[0].value.ratios || {};
        }
    } catch (err) {
        logger.warn('[QuestsBridge] No saved conversion ratios found, using defaults');
    }

    // Hardcoded default: game 126bf539-dae2-4bcf-964d-316c0fa1f92b = 1000:1
    if (!GAME_CONVERSION_RATIOS['126bf539-dae2-4bcf-964d-316c0fa1f92b']) {
        GAME_CONVERSION_RATIOS['126bf539-dae2-4bcf-964d-316c0fa1f92b'] = 1000;
    }

    logger.info('[QuestsBridge] Conversion ratios loaded: ' + JSON.stringify(GAME_CONVERSION_RATIOS));
}

function saveConversionRatios(nk, logger) {
    try {
        nk.storageWrite([{
            collection: CONVERSION_STORAGE_COLLECTION,
            key: CONVERSION_STORAGE_KEY,
            userId: SYSTEM_USER_ID,
            value: { ratios: GAME_CONVERSION_RATIOS, updatedAt: Date.now() },
            permissionRead: 2,
            permissionWrite: 0,
        }]);
        return true;
    } catch (err) {
        logger.error('[QuestsBridge] Failed to save conversion ratios: ' + err.message);
        return false;
    }
}

function getConversionRatio(gameId) {
    return GAME_CONVERSION_RATIOS[gameId] || 0;
}

// ═══════════════════════════════════════════════════════════════════
//  CONVERSION RPCs
// ═══════════════════════════════════════════════════════════════════

/**
 * RPC: Preview how many global points a game coin amount would yield.
 * Payload: { gameId: string, gameCoinAmount: number }
 * Returns: { gameId, gameCoinAmount, globalPointsYield, ratio, gameBalance }
 */
function rpcGameToGlobalPreview(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    var gameId = parsed.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: 'gameId is required' });
    }

    var ratio = getConversionRatio(gameId);
    if (ratio <= 0) {
        return JSON.stringify({ success: false, error: 'No conversion ratio configured for game ' + gameId });
    }

    // Read current game wallet balance
    var gameWallet = bridgeGetGameWallet(nk, logger, userId, gameId);
    var gameBalance = (gameWallet.currencies && (gameWallet.currencies.game || gameWallet.currencies.tokens)) || 0;

    var gameCoinAmount = parsed.gameCoinAmount || gameBalance;
    if (gameCoinAmount <= 0) {
        return JSON.stringify({ success: false, error: 'No game coins to convert' });
    }

    var globalPointsYield = Math.floor(gameCoinAmount / ratio);

    // Also fetch global balance from quests-economy
    var globalResult = questsApiCall(nk, logger, userId, gameId, 'balance', {});
    var currentGlobalBalance = (globalResult && !globalResult.error) ? (globalResult.balance || 0) : 0;

    return JSON.stringify({
        success: true,
        gameId: gameId,
        gameCoinAmount: gameCoinAmount,
        globalPointsYield: globalPointsYield,
        ratio: ratio,
        gameBalance: gameBalance,
        currentGlobalBalance: currentGlobalBalance,
        projectedGlobalBalance: currentGlobalBalance + globalPointsYield,
    });
}

/**
 * RPC: Convert game wallet coins into global wallet points.
 * Deducts from game wallet in Nakama storage, credits to quests-economy PointsLedger.
 *
 * Payload: { gameId: string, gameCoinAmount: number }
 * Returns: { gameId, gameCoinsBurned, globalPointsEarned, newGameBalance, newGlobalBalance }
 */
function rpcGameToGlobalConvert(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    var gameId = parsed.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: 'gameId is required' });
    }

    var ratio = getConversionRatio(gameId);
    if (ratio <= 0) {
        return JSON.stringify({ success: false, error: 'No conversion ratio configured for game ' + gameId });
    }

    var gameCoinAmount = parsed.gameCoinAmount;
    if (!gameCoinAmount || gameCoinAmount <= 0) {
        return JSON.stringify({ success: false, error: 'gameCoinAmount must be > 0' });
    }

    // Must be at least 1 ratio unit to yield any global points
    if (gameCoinAmount < ratio) {
        return JSON.stringify({
            success: false,
            error: 'Minimum conversion is ' + ratio + ' game coins (= 1 global point)',
        });
    }

    // Read game wallet
    var gameWallet = bridgeGetGameWallet(nk, logger, userId, gameId);
    var gameBalance = (gameWallet.currencies && (gameWallet.currencies.game || gameWallet.currencies.tokens)) || 0;

    if (gameBalance < gameCoinAmount) {
        return JSON.stringify({
            success: false,
            error: 'Insufficient game balance. Have ' + gameBalance + ', need ' + gameCoinAmount,
        });
    }

    // Calculate yield (floor — fractional global points are not awarded)
    var globalPointsEarned = Math.floor(gameCoinAmount / ratio);
    var actualCoinsBurned = globalPointsEarned * ratio; // only burn exact multiples

    // Step 1: Deduct from game wallet
    var currenciesToUpdate = ['game', 'tokens'];
    for (var i = 0; i < currenciesToUpdate.length; i++) {
        var curr = currenciesToUpdate[i];
        if (gameWallet.currencies[curr] !== undefined) {
            gameWallet.currencies[curr] -= actualCoinsBurned;
            if (gameWallet.currencies[curr] < 0) gameWallet.currencies[curr] = 0;
        }
    }
    if (!bridgeSaveGameWallet(nk, logger, userId, gameId, gameWallet)) {
        return JSON.stringify({ success: false, error: 'Failed to deduct game coins' });
    }

    // Step 2: Credit to quests-economy global wallet
    var earnResult = questsApiCall(nk, logger, userId, gameId, 'earn', {
        amount: globalPointsEarned,
        sourceType: 'game_to_global_conversion',
        sourceId: gameId,
        description: 'Converted ' + actualCoinsBurned + ' game coins → ' + globalPointsEarned + ' global points (ratio ' + ratio + ':1)',
    });

    if (earnResult.error) {
        // Rollback: re-add game coins
        for (var i = 0; i < currenciesToUpdate.length; i++) {
            var curr = currenciesToUpdate[i];
            if (gameWallet.currencies[curr] !== undefined) {
                gameWallet.currencies[curr] += actualCoinsBurned;
            }
        }
        bridgeSaveGameWallet(nk, logger, userId, gameId, gameWallet);
        logger.error('[QuestsBridge] Conversion rolled back for user ' + userId + ': ' + earnResult.error);
        return JSON.stringify({ success: false, error: 'Failed to credit global wallet, game coins restored' });
    }

    // Log the conversion
    bridgeLogTransaction(nk, logger, userId, {
        type: 'game_to_global_conversion',
        gameId: gameId,
        gameCoinsBurned: actualCoinsBurned,
        globalPointsEarned: globalPointsEarned,
        ratio: ratio,
    });

    var newGameBalance = (gameWallet.currencies.game || gameWallet.currencies.tokens || 0);

    logger.info('[QuestsBridge] User ' + userId + ' converted ' + actualCoinsBurned + ' game coins → ' +
        globalPointsEarned + ' global pts (game ' + gameId + ')');

    return JSON.stringify({
        success: true,
        gameId: gameId,
        gameCoinsBurned: actualCoinsBurned,
        globalPointsEarned: globalPointsEarned,
        ratio: ratio,
        newGameBalance: newGameBalance,
        newGlobalBalance: earnResult.newBalance,
    });
}

/**
 * RPC: Set conversion ratio for a game (admin only — server-side trusted call).
 * Payload: { gameId: string, ratio: number }
 */
function rpcConversionRatioSet(ctx, logger, nk, payload) {
    var parsed = JSON.parse(payload || '{}');
    var gameId = parsed.gameId;
    var ratio = parsed.ratio;

    if (!gameId || !ratio || ratio <= 0) {
        return JSON.stringify({ success: false, error: 'gameId and ratio (> 0) are required' });
    }

    GAME_CONVERSION_RATIOS[gameId] = ratio;
    saveConversionRatios(nk, logger);

    logger.info('[QuestsBridge] Conversion ratio set: game ' + gameId + ' = ' + ratio + ':1');

    return JSON.stringify({
        success: true,
        gameId: gameId,
        ratio: ratio,
        allRatios: GAME_CONVERSION_RATIOS,
    });
}

/**
 * RPC: Get conversion ratio(s).
 * Payload: { gameId?: string } — if omitted, returns all ratios
 */
function rpcConversionRatioGet(ctx, logger, nk, payload) {
    var parsed = JSON.parse(payload || '{}');

    if (parsed.gameId) {
        var ratio = getConversionRatio(parsed.gameId);
        return JSON.stringify({
            success: true,
            gameId: parsed.gameId,
            ratio: ratio,
            configured: ratio > 0,
        });
    }

    return JSON.stringify({
        success: true,
        ratios: GAME_CONVERSION_RATIOS,
    });
}

// ═══════════════════════════════════════════════════════════════════
//  INTELLIDRAWS (LOTTERY) RPCs
// ═══════════════════════════════════════════════════════════════════

function questsApiGet(nk, logger, path) {
    var url = QUESTS_API_URL + path;
    try {
        var response = nk.httpRequest(url, 'get', { 'Content-Type': 'application/json' }, '');
        if (response.code >= 200 && response.code < 300) {
            return JSON.parse(response.body);
        }
        logger.error('[QuestsBridge] GET ' + path + ' returned ' + response.code);
        return { error: 'API returned ' + response.code };
    } catch (err) {
        logger.error('[QuestsBridge] GET ' + path + ' failed: ' + err.message);
        return { error: err.message };
    }
}

function questsApiPost(nk, logger, userId, path, body) {
    var bodyStr = JSON.stringify(body || {});
    var signature = signRequest(nk, bodyStr);
    var url = QUESTS_API_URL + path;
    var headers = {
        'Content-Type': 'application/json',
        'X-Source': 'nakama-rpc',
        'X-Webhook-Signature': signature,
        'X-User-Id': userId,
    };
    try {
        var response = nk.httpRequest(url, 'post', headers, bodyStr);
        if (response.code >= 200 && response.code < 300) {
            return JSON.parse(response.body);
        }
        logger.error('[QuestsBridge] POST ' + path + ' returned ' + response.code + ': ' + response.body);
        return { error: 'API returned ' + response.code, details: response.body };
    } catch (err) {
        logger.error('[QuestsBridge] POST ' + path + ' failed: ' + err.message);
        return { error: err.message };
    }
}

/**
 * RPC: intellidraws_list — get active IntelliDraws sweepstakes
 */
function rpcIntelliDrawsList(ctx, logger, nk, payload) {
    var result = questsApiGet(nk, logger, '/consumer/intellidraws');
    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }
    return JSON.stringify({ success: true, sweepstakes: result });
}

/**
 * RPC: intellidraws_winners — get recent IntelliDraws winners
 */
function rpcIntelliDrawsWinners(ctx, logger, nk, payload) {
    var result = questsApiGet(nk, logger, '/consumer/intellidraws/winners');
    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }
    return JSON.stringify({ success: true, winners: result });
}

/**
 * RPC: intellidraws_enter — enter an IntelliDraws sweepstake
 * Payload: { sweepstakeId: string, entries?: number }
 */
function rpcIntelliDrawsEnter(ctx, logger, nk, payload) {
    var userId = ctx.userId;
    if (!userId) {
        return JSON.stringify({ error: 'User not authenticated' });
    }

    var parsed = JSON.parse(payload || '{}');
    if (!parsed.sweepstakeId) {
        return JSON.stringify({ success: false, error: 'sweepstakeId is required' });
    }

    var result = questsApiPost(nk, logger, userId, '/consumer/intellidraws/enter', {
        sweepstakeId: parsed.sweepstakeId,
        entries: parsed.entries || 1,
    });

    if (result.error) {
        return JSON.stringify({ success: false, error: result.error, details: result.details });
    }

    logger.info('[QuestsBridge] User ' + userId + ' entered IntelliDraws ' + parsed.sweepstakeId);
    return JSON.stringify({ success: true, result: result });
}

/**
 * RPC: intellidraws_past — get past completed draws
 */
function rpcIntelliDrawsPast(ctx, logger, nk, payload) {
    var result = questsApiGet(nk, logger, '/consumer/intellidraws/past');
    if (result.error) {
        return JSON.stringify({ success: false, error: result.error });
    }
    return JSON.stringify({ success: true, pastDraws: result });
}


// --- Module: quiz_results/quiz_results.js ---
// quiz_results.js - Quiz Results Tracking & Analytics System
// Stores ALL quiz results from ALL game modes for analytics, history, and leaderboards

/**
 * Quiz Result Schema
 * Captures comprehensive data about each quiz attempt
 */
var QUIZ_RESULT_SCHEMA = {
    // Required fields
    gameId: "string",           // Game UUID
    gameMode: "string",         // QuickPlay, DailyChallenge, Championship, etc.
    
    // Score data
    score: "number",            // Final score
    correctAnswers: "number",   // Number of correct answers
    totalQuestions: "number",   // Total questions in quiz
    
    // Timing
    timeTakenSeconds: "number", // Total time taken
    
    // Win/Loss
    won: "boolean",             // Did user win?
    
    // Optional fields
    difficulty: "string",       // easy, medium, hard
    categoryId: "string",       // Category/topic ID
    categoryName: "string",     // Category/topic name
    opponentId: "string",       // For multiplayer
    opponentName: "string",     // Opponent display name
    tournamentId: "string",     // If part of tournament
    matchId: "string",          // Match ID for multiplayer
    hintsUsed: "number",        // Power-ups used
    skipsUsed: "number",
    extraTimeUsed: "number",
    extraLivesUsed: "number",
    coinsSpent: "number",       // Coins spent on power-ups
    coinsEarned: "number",      // Coins earned from this quiz
    xpEarned: "number",         // XP earned
    streakDay: "number",        // Daily streak day
    perfectScore: "boolean",    // 100% accuracy
    metadata: "object"          // Any additional game-specific data
};

/**
 * Get collection name for quiz results
 */
function getResultsCollection(gameId) {
    return "quiz_results_" + gameId;
}

/**
 * Get user stats collection
 */
function getUserStatsCollection(gameId) {
    return "quiz_user_stats_" + gameId;
}

/**
 * Generate unique result key
 */
function generateResultKey(userId, timestamp) {
    return "result_" + userId + "_" + timestamp;
}

/**
 * Calculate performance metrics
 */
function calculateMetrics(result) {
    var accuracy = result.totalQuestions > 0 
        ? (result.correctAnswers / result.totalQuestions) * 100 
        : 0;
    
    var avgTimePerQuestion = result.totalQuestions > 0 
        ? result.timeTakenSeconds / result.totalQuestions 
        : 0;
    
    var isPerfect = result.correctAnswers === result.totalQuestions && result.totalQuestions > 0;
    
    return {
        accuracy: Math.round(accuracy * 100) / 100,
        avgTimePerQuestion: Math.round(avgTimePerQuestion * 100) / 100,
        isPerfect: isPerfect,
        performanceRating: calculatePerformanceRating(accuracy, avgTimePerQuestion, result.won)
    };
}

/**
 * Calculate performance rating (1-5 stars)
 */
function calculatePerformanceRating(accuracy, avgTime, won) {
    var rating = 0;
    
    // Accuracy contribution (0-2.5 stars)
    if (accuracy >= 90) rating += 2.5;
    else if (accuracy >= 70) rating += 2.0;
    else if (accuracy >= 50) rating += 1.5;
    else if (accuracy >= 30) rating += 1.0;
    else rating += 0.5;
    
    // Speed contribution (0-1.5 stars)
    if (avgTime <= 5) rating += 1.5;
    else if (avgTime <= 10) rating += 1.0;
    else if (avgTime <= 15) rating += 0.5;
    
    // Win bonus (0-1 star)
    if (won) rating += 1.0;
    
    return Math.min(5, Math.round(rating * 10) / 10);
}

/**
 * Update user's aggregate statistics
 */
function updateUserStats(nk, logger, userId, gameId, result, metrics) {
    var collection = getUserStatsCollection(gameId);
    var key = "stats_" + userId;
    
    // Get existing stats
    var stats = utils.readStorage(nk, logger, collection, key, userId);
    
    if (!stats) {
        stats = {
            userId: userId,
            gameId: gameId,
            totalGames: 0,
            totalWins: 0,
            totalScore: 0,
            totalCorrect: 0,
            totalQuestions: 0,
            totalTimePlayed: 0,
            perfectGames: 0,
            highestScore: 0,
            longestStreak: 0,
            currentStreak: 0,
            lastPlayedAt: null,
            modeStats: {},
            createdAt: utils.getCurrentTimestamp()
        };
    }
    
    // Update totals
    stats.totalGames++;
    stats.totalScore += result.score || 0;
    stats.totalCorrect += result.correctAnswers || 0;
    stats.totalQuestions += result.totalQuestions || 0;
    stats.totalTimePlayed += result.timeTakenSeconds || 0;
    
    if (result.won) {
        stats.totalWins++;
        stats.currentStreak++;
        stats.longestStreak = Math.max(stats.longestStreak, stats.currentStreak);
    } else {
        stats.currentStreak = 0;
    }
    
    if (metrics.isPerfect) {
        stats.perfectGames++;
    }
    
    stats.highestScore = Math.max(stats.highestScore, result.score || 0);
    stats.lastPlayedAt = utils.getCurrentTimestamp();
    
    // Update per-mode stats
    var mode = result.gameMode || "unknown";
    if (!stats.modeStats[mode]) {
        stats.modeStats[mode] = {
            games: 0,
            wins: 0,
            totalScore: 0,
            highestScore: 0
        };
    }
    stats.modeStats[mode].games++;
    if (result.won) stats.modeStats[mode].wins++;
    stats.modeStats[mode].totalScore += result.score || 0;
    stats.modeStats[mode].highestScore = Math.max(
        stats.modeStats[mode].highestScore, 
        result.score || 0
    );
    
    stats.updatedAt = utils.getCurrentTimestamp();
    
    // Save stats
    utils.writeStorage(nk, logger, collection, key, userId, stats);
    
    return stats;
}

/**
 * RPC: quiz_submit_result
 * Submit quiz result from any game mode
 * 
 * Required payload:
 * {
 *   gameId: "uuid",
 *   gameMode: "QuickPlay",
 *   score: 850,
 *   correctAnswers: 8,
 *   totalQuestions: 10,
 *   timeTakenSeconds: 120,
 *   won: true
 * }
 * 
 * Optional fields: difficulty, categoryId, categoryName, opponentId,
 *   tournamentId, matchId, hintsUsed, skipsUsed, coinsSpent, coinsEarned, etc.
 */
function rpcQuizSubmitResult(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC quiz_submit_result called");
    
    // Parse payload
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    
    // Validate required fields
    var required = ['gameId', 'gameMode', 'score', 'correctAnswers', 'totalQuestions', 'timeTakenSeconds'];
    var validation = utils.validatePayload(data, required);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    // Validate gameId UUID
    if (!utils.isValidUUID(data.gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var username = ctx.username || "unknown";
    var timestamp = utils.getUnixTimestamp();
    
    // Build result object
    var result = {
        id: generateResultKey(userId, timestamp),
        userId: userId,
        username: username,
        gameId: data.gameId,
        gameMode: data.gameMode,
        score: parseInt(data.score) || 0,
        correctAnswers: parseInt(data.correctAnswers) || 0,
        totalQuestions: parseInt(data.totalQuestions) || 0,
        timeTakenSeconds: parseFloat(data.timeTakenSeconds) || 0,
        won: data.won === true || data.won === "true",
        
        // Optional fields
        difficulty: data.difficulty || "normal",
        categoryId: data.categoryId || null,
        categoryName: data.categoryName || null,
        opponentId: data.opponentId || null,
        opponentName: data.opponentName || null,
        tournamentId: data.tournamentId || null,
        matchId: data.matchId || null,
        hintsUsed: parseInt(data.hintsUsed) || 0,
        skipsUsed: parseInt(data.skipsUsed) || 0,
        extraTimeUsed: parseInt(data.extraTimeUsed) || 0,
        extraLivesUsed: parseInt(data.extraLivesUsed) || 0,
        coinsSpent: parseInt(data.coinsSpent) || 0,
        coinsEarned: parseInt(data.coinsEarned) || 0,
        xpEarned: parseInt(data.xpEarned) || 0,
        streakDay: parseInt(data.streakDay) || 0,
        metadata: data.metadata || {},
        
        // Server-generated
        timestamp: timestamp,
        submittedAt: utils.getCurrentTimestamp()
    };
    
    // Calculate metrics
    var metrics = calculateMetrics(result);
    result.metrics = metrics;
    result.perfectScore = metrics.isPerfect;
    
    try {
        // 1. Store the result
        var collection = getResultsCollection(data.gameId);
        var resultKey = result.id;
        utils.writeStorage(nk, logger, collection, resultKey, userId, result);
        utils.logInfo(logger, "Stored quiz result: " + resultKey);
        
        // 2. Update user stats
        var updatedStats = updateUserStats(nk, logger, userId, data.gameId, result, metrics);
        
        // 3. Update leaderboard if score > 0
        if (result.score > 0) {
            try {
                var leaderboardId = "leaderboard_" + data.gameId;
                var leaderboardMetadata = {
                    gameMode: result.gameMode,
                    accuracy: metrics.accuracy,
                    submittedAt: result.submittedAt
                };
                
                nk.leaderboardRecordWrite(
                    leaderboardId,
                    userId,
                    username,
                    result.score,
                    0, // subscore
                    JSON.stringify(leaderboardMetadata),
                    null // operator - use default (best)
                );
                utils.logInfo(logger, "Updated leaderboard: " + leaderboardId);
            } catch (lbErr) {
                utils.logWarning(logger, "Leaderboard update failed (non-critical): " + lbErr.message);
            }
        }
        
        // 4. Store in transaction log for analytics
        var transactionKey = "quiz_result_" + userId + "_" + timestamp;
        utils.writeStorage(nk, logger, "transaction_logs", transactionKey, userId, {
            type: "quiz_result",
            resultId: result.id,
            gameMode: result.gameMode,
            score: result.score,
            won: result.won,
            timestamp: result.submittedAt
        });
        
        utils.logInfo(logger, "Quiz result submitted: User " + userId + ", Mode: " + result.gameMode + ", Score: " + result.score);
        
        return JSON.stringify({
            success: true,
            resultId: result.id,
            metrics: metrics,
            stats: {
                totalGames: updatedStats.totalGames,
                totalWins: updatedStats.totalWins,
                currentStreak: updatedStats.currentStreak,
                highestScore: updatedStats.highestScore
            }
        });
        
    } catch (err) {
        utils.logError(logger, "Failed to submit quiz result: " + err.message);
        return JSON.stringify({
            success: false,
            error: "Failed to submit result: " + err.message
        });
    }
}

/**
 * RPC: quiz_get_history
 * Get quiz history for a user
 * 
 * Payload:
 * {
 *   gameId: "uuid",
 *   gameMode: "QuickPlay" (optional, filter by mode),
 *   limit: 20,
 *   cursor: "..." (for pagination)
 * }
 */
function rpcQuizGetHistory(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC quiz_get_history called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['gameId']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing gameId");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var collection = getResultsCollection(data.gameId);
    var limit = Math.min(parseInt(data.limit) || 20, 100);
    
    try {
        // List storage objects for this user
        var objects = nk.storageList(userId, collection, limit, data.cursor || "");
        
        var results = [];
        for (var obj of objects.objects || []) {
            var result = JSON.parse(obj.value);
            
            // Filter by gameMode if specified
            if (data.gameMode && result.gameMode !== data.gameMode) {
                continue;
            }
            
            results.push({
                id: result.id,
                gameMode: result.gameMode,
                score: result.score,
                correctAnswers: result.correctAnswers,
                totalQuestions: result.totalQuestions,
                won: result.won,
                metrics: result.metrics,
                categoryName: result.categoryName,
                submittedAt: result.submittedAt
            });
        }
        
        return JSON.stringify({
            success: true,
            results: results,
            cursor: objects.cursor || null,
            count: results.length
        });
        
    } catch (err) {
        utils.logError(logger, "Failed to get quiz history: " + err.message);
        return JSON.stringify({
            success: false,
            error: "Failed to get history: " + err.message
        });
    }
}

/**
 * RPC: quiz_get_stats
 * Get user's aggregate quiz statistics
 */
function rpcQuizGetStats(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC quiz_get_stats called");
    
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    var validation = utils.validatePayload(data, ['gameId']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing gameId");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    var collection = getUserStatsCollection(data.gameId);
    var key = "stats_" + userId;
    
    var stats = utils.readStorage(nk, logger, collection, key, userId);
    
    if (!stats) {
        return JSON.stringify({
            success: true,
            stats: {
                totalGames: 0,
                totalWins: 0,
                winRate: 0,
                totalScore: 0,
                averageScore: 0,
                accuracy: 0,
                highestScore: 0,
                currentStreak: 0,
                longestStreak: 0,
                perfectGames: 0,
                modeStats: {}
            }
        });
    }
    
    // Calculate derived stats
    var winRate = stats.totalGames > 0 
        ? Math.round((stats.totalWins / stats.totalGames) * 100) 
        : 0;
    
    var averageScore = stats.totalGames > 0 
        ? Math.round(stats.totalScore / stats.totalGames) 
        : 0;
    
    var accuracy = stats.totalQuestions > 0 
        ? Math.round((stats.totalCorrect / stats.totalQuestions) * 100) 
        : 0;
    
    return JSON.stringify({
        success: true,
        stats: {
            totalGames: stats.totalGames,
            totalWins: stats.totalWins,
            winRate: winRate,
            totalScore: stats.totalScore,
            averageScore: averageScore,
            accuracy: accuracy,
            highestScore: stats.highestScore,
            currentStreak: stats.currentStreak,
            longestStreak: stats.longestStreak,
            perfectGames: stats.perfectGames,
            totalTimePlayed: stats.totalTimePlayed,
            modeStats: stats.modeStats,
            lastPlayedAt: stats.lastPlayedAt
        }
    });
}

/**
 * RPC: quiz_check_daily_completion
 * Check if user has completed a quiz for a specific game mode today
 * Based on user UUID - queries across all quiz result collections for the user
 * 
 * Payload:
 * {
 *   gameMode: "DailyChallenge" | "DailyPremiumQuiz"
 *   gameId: "uuid" (optional - if provided, only checks that specific game)
 * }
 * 
 * Returns:
 * {
 *   success: true,
 *   completed: boolean,
 *   gameMode: "DailyChallenge",
 *   date: "2025-01-15" (YYYY-MM-DD format)
 * }
 */
function rpcQuizCheckDailyCompletion(ctx, logger, nk, payload) {
    utils.logInfo(logger, "RPC quiz_check_daily_completion called");
    
    // Parse payload
    var parsed = utils.safeJsonParse(payload);
    if (!parsed.success) {
        return utils.handleError(ctx, null, "Invalid JSON payload");
    }
    
    var data = parsed.data;
    
    // Validate required fields (only gameMode is required now)
    var validation = utils.validatePayload(data, ['gameMode']);
    if (!validation.valid) {
        return utils.handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }
    
    // Validate gameMode
    var validModes = ['DailyChallenge', 'DailyPremiumQuiz'];
    if (validModes.indexOf(data.gameMode) === -1) {
        return utils.handleError(ctx, null, "Invalid gameMode. Must be 'DailyChallenge' or 'DailyPremiumQuiz'");
    }
    
    // Validate gameId if provided (optional)
    if (data.gameId && !utils.isValidUUID(data.gameId)) {
        return utils.handleError(ctx, null, "Invalid gameId UUID format");
    }
    
    var userId = ctx.userId;
    if (!userId) {
        return utils.handleError(ctx, null, "User not authenticated");
    }
    
    try {
        // Get today's start timestamp (00:00:00 UTC)
        var todayStart = utils.getStartOfDay();
        var todayEnd = todayStart + 86400; // End of day (24 hours later)
        
        // Get current date string for response (YYYY-MM-DD)
        var today = new Date();
        var dateString = today.getUTCFullYear() + "-" + 
                          String(today.getUTCMonth() + 1).padStart(2, '0') + "-" + 
                          String(today.getUTCDate()).padStart(2, '0');
        
        var completed = false;
        
        // If gameId is provided, only check that specific collection
        if (data.gameId) {
            var collection = getResultsCollection(data.gameId);
            var limit = 100; // Check last 100 results (should be enough for daily check)
            
            var objects = nk.storageList(userId, collection, limit, "");
            
            // Check if any result matches gameMode and was submitted today
            for (var obj of objects.objects || []) {
                var result = JSON.parse(obj.value);
                
                // Check if gameMode matches
                if (result.gameMode !== data.gameMode) {
                    continue;
                }
                
                // Check if submitted today
                // result.timestamp is Unix timestamp in seconds
                if (result.timestamp >= todayStart && result.timestamp < todayEnd) {
                    completed = true;
                    utils.logInfo(logger, `User ${userId} completed ${data.gameMode} today (timestamp: ${result.timestamp})`);
                    break;
                }
            }
        } else {
            // No gameId provided - query transaction_logs which stores all quiz results
            var transactionCollection = "transaction_logs";
            var limit = 1000; // Higher limit to check more results
            var transactionObjects = nk.storageList(userId, transactionCollection, limit, "");
            
            // Check transaction logs for quiz results submitted today
            for (var obj of transactionObjects.objects || []) {
                var transaction = JSON.parse(obj.value);
                
                // Check if this is a quiz result transaction
                if (transaction.type === "quiz_result" && 
                    transaction.gameMode === data.gameMode) {
                    
                    // Parse timestamp from submittedAt (ISO string) or use timestamp if available
                    var transactionTimestamp = null;
                    if (transaction.timestamp) {
                        // If timestamp is a Unix timestamp (seconds)
                        if (typeof transaction.timestamp === 'number') {
                            transactionTimestamp = transaction.timestamp;
                        } else if (typeof transaction.timestamp === 'string') {
                            // If it's an ISO string, convert to Unix timestamp
                            var dateObj = new Date(transaction.timestamp);
                            if (!isNaN(dateObj.getTime())) {
                                transactionTimestamp = Math.floor(dateObj.getTime() / 1000);
                            }
                        }
                    } else if (transaction.submittedAt) {
                        // Fallback to submittedAt if timestamp not available
                        var dateObj = new Date(transaction.submittedAt);
                        if (!isNaN(dateObj.getTime())) {
                            transactionTimestamp = Math.floor(dateObj.getTime() / 1000);
                        }
                    }
                    
                    // Check if submitted today
                    if (transactionTimestamp && transactionTimestamp >= todayStart && transactionTimestamp < todayEnd) {
                        completed = true;
                        utils.logInfo(logger, `User ${userId} completed ${data.gameMode} today (from transaction log, timestamp: ${transactionTimestamp})`);
                        break;
                    }
                }
            }
        }
        
        return JSON.stringify({
            success: true,
            completed: completed,
            gameMode: data.gameMode,
            date: dateString
        });
        
    } catch (err) {
        utils.logError(logger, "Failed to check daily completion: " + err.message);
        return JSON.stringify({
            success: false,
            error: "Failed to check completion: " + err.message,
            completed: false
        });
    }
}


// --- Module: quizverse_depth/quizverse_depth.js ---
// quizverse_depth.js - Deep QuizVerse RPCs: Knowledge Maps, Streaks, Adaptive Difficulty, and more
// Nakama V8 JavaScript runtime (No ES Modules)

// ============================================================================
// UTILITY HELPERS
// ============================================================================

function qvdParsePayload(payload, requiredFields) {
    var data = {};
    try {
        data = JSON.parse(payload || "{}");
    } catch (e) {
        throw Error("Invalid JSON payload");
    }
    for (var i = 0; i < requiredFields.length; i++) {
        if (data[requiredFields[i]] === undefined || data[requiredFields[i]] === null) {
            throw Error("Missing required field: " + requiredFields[i]);
        }
    }
    return data;
}

function qvdStorageRead(nk, collection, key, userId) {
    var records = nk.storageRead([{ collection: collection, key: key, userId: userId }]);
    if (records && records.length > 0 && records[0].value) {
        return records[0].value;
    }
    return null;
}

function qvdStorageWrite(nk, collection, key, userId, value) {
    nk.storageWrite([{
        collection: collection,
        key: key,
        userId: userId,
        value: value,
        permissionRead: 1,
        permissionWrite: 0
    }]);
}

function qvdTodayKey() {
    var now = new Date();
    var y = now.getUTCFullYear();
    var m = ("0" + (now.getUTCMonth() + 1)).slice(-2);
    var d = ("0" + now.getUTCDate()).slice(-2);
    return y + "-" + m + "-" + d;
}

// ============================================================================
// 1. KNOWLEDGE MAP
// ============================================================================

function rpcQuizverseKnowledgeMap(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_quiz_history";

        var history = qvdStorageRead(nk, collection, "history", userId);
        if (!history || !history.entries) {
            return JSON.stringify({
                success: true,
                categories: {},
                overall_coverage_pct: 0,
                strongest: null,
                weakest: null,
                total_quizzes: 0
            });
        }

        var cats = {};
        var totalQuizzes = history.entries.length;

        for (var i = 0; i < history.entries.length; i++) {
            var entry = history.entries[i];
            var cat = entry.category || "general";
            if (!cats[cat]) {
                cats[cat] = { total_questions: 0, correct: 0, total_time_ms: 0 };
            }
            cats[cat].total_questions += 1;
            if (entry.correct) {
                cats[cat].correct += 1;
            }
            cats[cat].total_time_ms += (entry.time_ms || 0);
        }

        var strongest = null;
        var weakest = null;
        var highAcc = -1;
        var lowAcc = 101;
        var catKeys = Object.keys(cats);

        for (var j = 0; j < catKeys.length; j++) {
            var k = catKeys[j];
            var c = cats[k];
            var acc = c.total_questions > 0 ? Math.round((c.correct / c.total_questions) * 100) : 0;
            var avgTime = c.total_questions > 0 ? Math.round(c.total_time_ms / c.total_questions) : 0;

            var level = "weak";
            if (acc >= 90) {
                level = "expert";
            } else if (acc >= 70) {
                level = "strong";
            } else if (acc >= 40) {
                level = "moderate";
            }

            cats[k] = {
                total_questions: c.total_questions,
                correct: c.correct,
                accuracy_pct: acc,
                avg_time_ms: avgTime,
                strength_level: level
            };

            if (acc > highAcc) { highAcc = acc; strongest = k; }
            if (acc < lowAcc) { lowAcc = acc; weakest = k; }
        }

        var knownCategories = catKeys.length;
        var assumedTotal = Math.max(knownCategories, 10);
        var coveragePct = Math.round((knownCategories / assumedTotal) * 100);

        return JSON.stringify({
            success: true,
            categories: cats,
            overall_coverage_pct: coveragePct,
            strongest: strongest,
            weakest: weakest,
            total_quizzes: totalQuizzes
        });

    } catch (err) {
        logger.error("rpcQuizverseKnowledgeMap error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 2. STREAK QUIZ
// ============================================================================

function rpcQuizverseStreakQuiz(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_streak_quizzes";

        var streak = qvdStorageRead(nk, collection, "current", userId) || {
            current_streak: 0,
            best_streak: 0,
            alive: false
        };

        var reward = null;

        if (data.action === "start") {
            streak.current_streak = 0;
            streak.alive = true;

        } else if (data.action === "answer") {
            if (!streak.alive) {
                return JSON.stringify({ success: false, error: "No active streak session" });
            }
            if (data.answer_correct) {
                streak.current_streak += 1;
            } else {
                streak.alive = false;
            }

        } else if (data.action === "end") {
            streak.alive = false;
            if (streak.current_streak > streak.best_streak) {
                streak.best_streak = streak.current_streak;
            }
            var coins = streak.current_streak * 10;
            if (coins > 0) {
                nk.walletUpdate(userId, { coins: coins }, { reason: "streak_reward", streak: streak.current_streak }, true);
                reward = { coins: coins };
            }

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use start, answer, or end" });
        }

        qvdStorageWrite(nk, collection, "current", userId, streak);

        return JSON.stringify({
            success: true,
            current_streak: streak.current_streak,
            best_streak: streak.best_streak,
            alive: streak.alive,
            reward: reward
        });

    } catch (err) {
        logger.error("rpcQuizverseStreakQuiz error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 3. ADAPTIVE DIFFICULTY
// ============================================================================

function rpcQuizverseAdaptiveDifficulty(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "category", "recent_accuracy"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var category = data.category;
        var recentAccuracy = data.recent_accuracy;
        var collection = gameId + "_adaptive_difficulty";

        var record = qvdStorageRead(nk, collection, category, userId) || {
            difficulty: 5,
            history: []
        };

        var currentDiff = record.difficulty;
        var newDiff = currentDiff;

        if (recentAccuracy < 40) {
            newDiff = Math.max(1, currentDiff - 1);
        } else if (recentAccuracy > 70) {
            newDiff = Math.min(10, currentDiff + 1);
        }

        record.difficulty = newDiff;
        record.history.push({ accuracy: recentAccuracy, difficulty: newDiff, timestamp: Date.now() });
        if (record.history.length > 50) {
            record.history = record.history.slice(-50);
        }

        qvdStorageWrite(nk, collection, category, userId, record);

        var playerLevel = "beginner";
        if (newDiff >= 8) {
            playerLevel = "expert";
        } else if (newDiff >= 5) {
            playerLevel = "intermediate";
        }

        return JSON.stringify({
            success: true,
            recommended_difficulty: newDiff,
            category: category,
            player_level: playerLevel
        });

    } catch (err) {
        logger.error("rpcQuizverseAdaptiveDifficulty error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 4. DAILY PUZZLE
// ============================================================================

function rpcQuizverseDailyPuzzle(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var today = qvdTodayKey();
        var collection = gameId + "_daily_puzzles";
        var leaderboardId = gameId + "_daily_puzzle_leaderboard";

        if (data.action === "get") {
            var puzzle = qvdStorageRead(nk, collection, today, userId);
            if (!puzzle) {
                var seed = 0;
                for (var i = 0; i < today.length; i++) {
                    seed += today.charCodeAt(i);
                }
                puzzle = {
                    date: today,
                    seed: seed,
                    puzzle_type: ["word_scramble", "logic", "trivia", "pattern"][seed % 4],
                    difficulty: (seed % 5) + 1,
                    completed: false,
                    created_at: Date.now()
                };
                qvdStorageWrite(nk, collection, today, userId, puzzle);
            }

            return JSON.stringify({
                success: true,
                puzzle: puzzle
            });

        } else if (data.action === "submit") {
            if (!data.solve_time_ms) {
                return JSON.stringify({ success: false, error: "solve_time_ms required for submit" });
            }

            var existing = qvdStorageRead(nk, collection, today, userId);
            if (existing && existing.completed) {
                return JSON.stringify({ success: false, error: "Already submitted today" });
            }

            var solveTime = data.solve_time_ms;
            var score = Math.max(0, 100000 - solveTime);

            try {
                nk.leaderboardRecordWrite(leaderboardId, userId, ctx.username || "", score, 0, { date: today, solve_time_ms: solveTime });
            } catch (lbErr) {
                logger.warn("Leaderboard write failed (may not exist): " + lbErr.message);
            }

            var result = {
                date: today,
                solve_time_ms: solveTime,
                score: score,
                completed: true,
                completed_at: Date.now()
            };
            qvdStorageWrite(nk, collection, today, userId, result);

            return JSON.stringify({
                success: true,
                result: result
            });

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use get or submit" });
        }

    } catch (err) {
        logger.error("rpcQuizverseDailyPuzzle error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 5. CATEGORY WAR
// ============================================================================

function rpcQuizverseCategoryWar(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_category_wars";
        var today = qvdTodayKey();
        var warKey = "war_" + today;

        var war = qvdStorageRead(nk, collection, warKey, "00000000-0000-0000-0000-000000000000");
        if (!war) {
            var seed = 0;
            for (var s = 0; s < today.length; s++) {
                seed += today.charCodeAt(s);
            }
            var allCats = ["science", "history", "geography", "entertainment", "sports", "technology", "art", "literature"];
            var catA = allCats[seed % allCats.length];
            var catB = allCats[(seed + 3) % allCats.length];
            if (catA === catB) { catB = allCats[(seed + 5) % allCats.length]; }

            war = {
                war_id: warKey,
                categories: [catA, catB],
                scores: {},
                players: {},
                created_at: Date.now(),
                expires_at: Date.now() + 86400000
            };
            war.scores[catA] = 0;
            war.scores[catB] = 0;
        }

        if (data.action === "get_status") {
            var mySide = (war.players && war.players[userId]) ? war.players[userId] : null;
            return JSON.stringify({
                success: true,
                war_id: war.war_id,
                categories: war.categories,
                scores: war.scores,
                your_side: mySide,
                time_remaining: Math.max(0, war.expires_at - Date.now())
            });

        } else if (data.action === "join") {
            if (!data.category_choice) {
                return JSON.stringify({ success: false, error: "category_choice required" });
            }
            if (war.categories.indexOf(data.category_choice) === -1) {
                return JSON.stringify({ success: false, error: "Invalid category. Choose one of: " + war.categories.join(", ") });
            }
            if (!war.players) { war.players = {}; }
            war.players[userId] = data.category_choice;

            qvdStorageWrite(nk, collection, warKey, "00000000-0000-0000-0000-000000000000", war);

            return JSON.stringify({
                success: true,
                war_id: war.war_id,
                categories: war.categories,
                scores: war.scores,
                your_side: data.category_choice,
                time_remaining: Math.max(0, war.expires_at - Date.now())
            });

        } else if (data.action === "submit_score") {
            if (!data.score) {
                return JSON.stringify({ success: false, error: "score required" });
            }
            var playerSide = war.players ? war.players[userId] : null;
            if (!playerSide) {
                return JSON.stringify({ success: false, error: "Must join a side first" });
            }
            war.scores[playerSide] = (war.scores[playerSide] || 0) + data.score;

            qvdStorageWrite(nk, collection, warKey, "00000000-0000-0000-0000-000000000000", war);

            return JSON.stringify({
                success: true,
                war_id: war.war_id,
                categories: war.categories,
                scores: war.scores,
                your_side: playerSide,
                time_remaining: Math.max(0, war.expires_at - Date.now())
            });

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use get_status, join, or submit_score" });
        }

    } catch (err) {
        logger.error("rpcQuizverseCategoryWar error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 6. KNOWLEDGE DUEL
// ============================================================================

function rpcQuizverseKnowledgeDuel(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_knowledge_duels";

        if (data.action === "create") {
            if (!data.opponent_id) {
                return JSON.stringify({ success: false, error: "opponent_id required" });
            }
            var duelId = gameId + "_duel_" + userId.substring(0, 8) + "_" + Date.now();
            var duel = {
                duel_id: duelId,
                creator: userId,
                opponent: data.opponent_id,
                status: "pending",
                scores: {},
                created_at: Date.now(),
                expires_at: Date.now() + 3600000
            };
            duel.scores[userId] = null;
            duel.scores[data.opponent_id] = null;

            qvdStorageWrite(nk, collection, duelId, userId, duel);

            try {
                nk.notificationSend(
                    data.opponent_id,
                    "Knowledge Duel Challenge",
                    2,
                    { duel_id: duelId, challenger: userId, challenger_name: ctx.username || "Unknown" },
                    userId
                );
            } catch (notifErr) {
                logger.warn("Could not send duel notification: " + notifErr.message);
            }

            return JSON.stringify({
                success: true,
                duel_id: duelId,
                status: "pending",
                your_score: null,
                opponent_score: null,
                winner: null
            });

        } else if (data.action === "join") {
            if (!data.duel_id) {
                return JSON.stringify({ success: false, error: "duel_id required" });
            }
            var records = nk.storageRead([{ collection: collection, key: data.duel_id, userId: "*" }]);
            var joinDuel = null;
            if (records && records.length > 0) {
                joinDuel = records[0].value;
            }
            if (!joinDuel) {
                return JSON.stringify({ success: false, error: "Duel not found" });
            }
            if (joinDuel.opponent !== userId) {
                return JSON.stringify({ success: false, error: "You are not the invited opponent" });
            }
            joinDuel.status = "active";
            qvdStorageWrite(nk, collection, data.duel_id, joinDuel.creator, joinDuel);

            return JSON.stringify({
                success: true,
                duel_id: joinDuel.duel_id,
                status: "active",
                your_score: null,
                opponent_score: null,
                winner: null
            });

        } else if (data.action === "submit") {
            if (!data.duel_id || data.score === undefined) {
                return JSON.stringify({ success: false, error: "duel_id and score required" });
            }
            var subRecords = nk.storageRead([{ collection: collection, key: data.duel_id, userId: "*" }]);
            var subDuel = null;
            var storageOwner = null;
            if (subRecords && subRecords.length > 0) {
                subDuel = subRecords[0].value;
                storageOwner = subRecords[0].userId;
            }
            if (!subDuel) {
                return JSON.stringify({ success: false, error: "Duel not found" });
            }
            subDuel.scores[userId] = data.score;

            var winner = null;
            if (subDuel.scores[subDuel.creator] !== null && subDuel.scores[subDuel.opponent] !== null) {
                subDuel.status = "completed";
                if (subDuel.scores[subDuel.creator] > subDuel.scores[subDuel.opponent]) {
                    winner = subDuel.creator;
                } else if (subDuel.scores[subDuel.opponent] > subDuel.scores[subDuel.creator]) {
                    winner = subDuel.opponent;
                } else {
                    winner = "draw";
                }
                subDuel.winner = winner;

                var loserId = winner === subDuel.creator ? subDuel.opponent : subDuel.creator;
                if (winner !== "draw") {
                    nk.walletUpdate(winner, { coins: 50 }, { reason: "duel_win", duel_id: subDuel.duel_id }, true);
                    try {
                        nk.notificationSend(loserId, "Duel Result", 3, { duel_id: subDuel.duel_id, result: "lost" }, winner);
                        nk.notificationSend(winner, "Duel Result", 3, { duel_id: subDuel.duel_id, result: "won" }, loserId);
                    } catch (nErr) {
                        logger.warn("Duel result notification failed: " + nErr.message);
                    }
                }
            }

            qvdStorageWrite(nk, collection, data.duel_id, storageOwner || subDuel.creator, subDuel);

            var myScore = subDuel.scores[userId];
            var oppId = userId === subDuel.creator ? subDuel.opponent : subDuel.creator;
            var oppScore = subDuel.scores[oppId];

            return JSON.stringify({
                success: true,
                duel_id: subDuel.duel_id,
                status: subDuel.status,
                your_score: myScore,
                opponent_score: oppScore,
                winner: winner
            });

        } else if (data.action === "result") {
            if (!data.duel_id) {
                return JSON.stringify({ success: false, error: "duel_id required" });
            }
            var resRecords = nk.storageRead([{ collection: collection, key: data.duel_id, userId: "*" }]);
            var resDuel = null;
            if (resRecords && resRecords.length > 0) {
                resDuel = resRecords[0].value;
            }
            if (!resDuel) {
                return JSON.stringify({ success: false, error: "Duel not found" });
            }
            var resOppId = userId === resDuel.creator ? resDuel.opponent : resDuel.creator;

            return JSON.stringify({
                success: true,
                duel_id: resDuel.duel_id,
                status: resDuel.status,
                your_score: resDuel.scores[userId],
                opponent_score: resDuel.scores[resOppId],
                winner: resDuel.winner || null
            });

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use create, join, submit, or result" });
        }

    } catch (err) {
        logger.error("rpcQuizverseKnowledgeDuel error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 7. STUDY MODE
// ============================================================================

function rpcQuizverseStudyMode(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_study_progress";

        var progress = qvdStorageRead(nk, collection, "progress", userId) || {
            wrong_answers: [],
            attempts: {},
            started_at: Date.now()
        };

        if (data.action === "get_weak_areas") {
            var weakMap = {};
            for (var i = 0; i < progress.wrong_answers.length; i++) {
                var wa = progress.wrong_answers[i];
                var cat = wa.category || "general";
                if (!weakMap[cat]) {
                    weakMap[cat] = { wrong_count: 0, questions: [] };
                }
                weakMap[cat].wrong_count += 1;
                weakMap[cat].questions.push(wa.question_id);
            }

            var weakAreas = [];
            var wKeys = Object.keys(weakMap);
            for (var w = 0; w < wKeys.length; w++) {
                weakAreas.push({
                    category: wKeys[w],
                    wrong_count: weakMap[wKeys[w]].wrong_count,
                    question_ids: weakMap[wKeys[w]].questions
                });
            }
            weakAreas.sort(function(a, b) { return b.wrong_count - a.wrong_count; });

            return JSON.stringify({
                success: true,
                weak_areas: weakAreas,
                total_wrong: progress.wrong_answers.length
            });

        } else if (data.action === "record_attempt") {
            if (!data.question_id) {
                return JSON.stringify({ success: false, error: "question_id required" });
            }
            var qid = data.question_id;
            if (!progress.attempts[qid]) {
                progress.attempts[qid] = { total: 0, correct: 0 };
            }
            progress.attempts[qid].total += 1;

            if (data.was_correct) {
                progress.attempts[qid].correct += 1;
                progress.wrong_answers = progress.wrong_answers.filter(function(item) {
                    return item.question_id !== qid;
                });
            } else {
                var alreadyTracked = false;
                for (var a = 0; a < progress.wrong_answers.length; a++) {
                    if (progress.wrong_answers[a].question_id === qid) {
                        alreadyTracked = true;
                        break;
                    }
                }
                if (!alreadyTracked) {
                    progress.wrong_answers.push({
                        question_id: qid,
                        category: data.category || "general",
                        added_at: Date.now()
                    });
                }
            }

            qvdStorageWrite(nk, collection, "progress", userId, progress);

            return JSON.stringify({
                success: true,
                question_id: qid,
                attempts: progress.attempts[qid],
                remaining_weak: progress.wrong_answers.length
            });

        } else if (data.action === "get_improvement") {
            var totalAttempts = 0;
            var totalCorrect = 0;
            var attemptKeys = Object.keys(progress.attempts);
            for (var t = 0; t < attemptKeys.length; t++) {
                var att = progress.attempts[attemptKeys[t]];
                totalAttempts += att.total;
                totalCorrect += att.correct;
            }
            var improvementPct = totalAttempts > 0 ? Math.round((totalCorrect / totalAttempts) * 100) : 0;

            return JSON.stringify({
                success: true,
                total_questions_studied: attemptKeys.length,
                total_attempts: totalAttempts,
                total_correct: totalCorrect,
                accuracy_pct: improvementPct,
                remaining_weak: progress.wrong_answers.length,
                study_duration_ms: Date.now() - (progress.started_at || Date.now())
            });

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use get_weak_areas, record_attempt, or get_improvement" });
        }

    } catch (err) {
        logger.error("rpcQuizverseStudyMode error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// 8. TRIVIA NIGHT
// ============================================================================

function rpcQuizverseTriviaNight(ctx, logger, nk, payload) {
    try {
        var data = qvdParsePayload(payload, ["game_id", "action"]);
        var userId = ctx.userId;
        var gameId = data.game_id;
        var collection = gameId + "_trivia_nights";
        var systemUser = "00000000-0000-0000-0000-000000000000";

        if (data.action === "schedule") {
            var eventId = gameId + "_trivia_" + Date.now();
            var scheduledAt = data.scheduled_at || (Date.now() + 3600000);
            var eventData = {
                event_id: eventId,
                title: data.title || "Trivia Night",
                scheduled_at: scheduledAt,
                status: "upcoming",
                registered_players: [],
                scores: {},
                category: data.category || "mixed",
                created_by: userId,
                created_at: Date.now()
            };

            qvdStorageWrite(nk, collection, eventId, systemUser, eventData);

            return JSON.stringify({
                success: true,
                event_id: eventId,
                scheduled_at: scheduledAt,
                status: "upcoming"
            });

        } else if (data.action === "get_upcoming") {
            var upcoming = qvdStorageRead(nk, collection, "upcoming_index", systemUser) || { events: [] };
            var now = Date.now();
            var active = [];
            for (var i = 0; i < upcoming.events.length; i++) {
                if (upcoming.events[i].scheduled_at > now || upcoming.events[i].status === "active") {
                    active.push(upcoming.events[i]);
                }
            }

            return JSON.stringify({
                success: true,
                events: active
            });

        } else if (data.action === "register") {
            if (!data.event_id) {
                return JSON.stringify({ success: false, error: "event_id required" });
            }
            var regEvent = qvdStorageRead(nk, collection, data.event_id, systemUser);
            if (!regEvent) {
                return JSON.stringify({ success: false, error: "Event not found" });
            }
            if (!regEvent.registered_players) {
                regEvent.registered_players = [];
            }
            var alreadyRegistered = false;
            for (var r = 0; r < regEvent.registered_players.length; r++) {
                if (regEvent.registered_players[r] === userId) {
                    alreadyRegistered = true;
                    break;
                }
            }
            if (!alreadyRegistered) {
                regEvent.registered_players.push(userId);
                qvdStorageWrite(nk, collection, data.event_id, systemUser, regEvent);
            }

            return JSON.stringify({
                success: true,
                event_id: data.event_id,
                registered: true,
                total_registered: regEvent.registered_players.length
            });

        } else if (data.action === "submit_score") {
            if (!data.event_id || data.score === undefined) {
                return JSON.stringify({ success: false, error: "event_id and score required" });
            }
            var scoreEvent = qvdStorageRead(nk, collection, data.event_id, systemUser);
            if (!scoreEvent) {
                return JSON.stringify({ success: false, error: "Event not found" });
            }
            if (!scoreEvent.scores) { scoreEvent.scores = {}; }
            scoreEvent.scores[userId] = data.score;

            qvdStorageWrite(nk, collection, data.event_id, systemUser, scoreEvent);

            var leaderboardId = gameId + "_trivia_" + data.event_id;
            try {
                nk.leaderboardRecordWrite(leaderboardId, userId, ctx.username || "", data.score, 0, { event_id: data.event_id });
            } catch (lbErr) {
                logger.warn("Trivia leaderboard write failed: " + lbErr.message);
            }

            return JSON.stringify({
                success: true,
                event_id: data.event_id,
                your_score: data.score,
                total_participants: Object.keys(scoreEvent.scores).length
            });

        } else {
            return JSON.stringify({ success: false, error: "Invalid action. Use schedule, get_upcoming, register, or submit_score" });
        }

    } catch (err) {
        logger.error("rpcQuizverseTriviaNight error: " + err.message);
        return JSON.stringify({ success: false, error: err.message });
    }
}

// ============================================================================
// REGISTRATION
// ============================================================================

function registerQuizverseDepthRPCs(initializer, logger) {
    logger.info("[QuizverseDepth] Initializing QuizVerse Depth RPCs...");

    if (!globalThis.__registeredRPCs) {
        globalThis.__registeredRPCs = new Set();
    }

    var rpcs = [
        { id: "quizverse_knowledge_map", handler: rpcQuizverseKnowledgeMap },
        { id: "quizverse_streak_quiz", handler: rpcQuizverseStreakQuiz },
        { id: "quizverse_adaptive_difficulty", handler: rpcQuizverseAdaptiveDifficulty },
        { id: "quizverse_daily_puzzle", handler: rpcQuizverseDailyPuzzle },
        { id: "quizverse_category_war", handler: rpcQuizverseCategoryWar },
        { id: "quizverse_knowledge_duel", handler: rpcQuizverseKnowledgeDuel },
        { id: "quizverse_study_mode", handler: rpcQuizverseStudyMode },
        { id: "quizverse_trivia_night", handler: rpcQuizverseTriviaNight }
    ];

    var registered = 0;
    var skipped = 0;

    for (var i = 0; i < rpcs.length; i++) {
        var rpc = rpcs[i];
        if (!globalThis.__registeredRPCs.has(rpc.id)) {
            try {
                initializer.registerRpc(rpc.id, rpc.handler);
                globalThis.__registeredRPCs.add(rpc.id);
                logger.info("[QuizverseDepth] Registered RPC: " + rpc.id);
                registered++;
            } catch (err) {
                logger.error("[QuizverseDepth] Failed to register " + rpc.id + ": " + err.message);
            }
        } else {
            logger.info("[QuizverseDepth] Skipped (already registered): " + rpc.id);
            skipped++;
        }
    }

    logger.info("[QuizverseDepth] Registration complete: " + registered + " registered, " + skipped + " skipped");
}


