// Category mastery configuration
var MASTERY_CATEGORIES = [
    "Science", "History", "Geography", "Sports", "Entertainment", 
    "Technology", "Art", "Literature", "Nature", "General"
];

var MASTERY_LEVELS = [
    { level: 1, xpRequired: 0, bonus: 0 },
    { level: 2, xpRequired: 500, bonus: 5 },
    { level: 3, xpRequired: 1500, bonus: 10 },
    { level: 4, xpRequired: 3000, bonus: 15 },
    { level: 5, xpRequired: 5000, bonus: 20 } // Master
];

// Prestige configuration
var PRESTIGE_LEVELS = [
    { level: 0, xpRequired: 0, bonus: 0, frame: null },
    { level: 1, xpRequired: 50000, bonus: 10, frame: "frame_bronze" },
    { level: 2, xpRequired: 150000, bonus: 15, frame: "frame_silver" },
    { level: 3, xpRequired: 300000, bonus: 20, frame: "frame_gold" },
    { level: 4, xpRequired: 500000, bonus: 25, frame: "frame_platinum" },
    { level: 5, xpRequired: 1000000, bonus: 30, frame: "frame_diamond" }
];

/**
 * Read collection data for user
 */
function getCollectionData(nk, logger, userId, gameId) {
    var collection = "user_collections";
    var key = "data_" + userId + "_" + gameId;
    
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: userId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn("[Collections] Failed to read data: " + err.message);
    }
    
    return null;
}

/**
 * Save collection data
 */
function saveCollectionData(nk, logger, userId, gameId, data) {
    var collection = "user_collections";
    var key = "data_" + userId + "_" + gameId;
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error("[Collections] Failed to save data: " + err.message);
        return false;
    }
}

/**
 * Initialize collection data for new user
 */
function initializeCollectionData() {
    // Initialize unlocked items with defaults
    var unlocked = {
        avatars: ["avatar_default"],
        badges: [],
        titles: ["title_newbie"],
        frames: ["frame_default"]
    };
    
    // Initialize mastery for each category
    var mastery = {};
    for (var i = 0; i < MASTERY_CATEGORIES.length; i++) {
        var cat = MASTERY_CATEGORIES[i];
        mastery[cat] = {
            level: 1,
            xp: 0,
            questionsAnswered: 0,
            correctAnswers: 0
        };
    }
    
    return {
        unlocked: unlocked,
        equipped: {
            avatar: "avatar_default",
            title: "title_newbie",
            frame: "frame_default",
            badge: null
        },
        mastery: mastery,
        prestige: {
            level: 0,
            totalXp: 0
        },
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

/**
 * Calculate mastery level from XP
 */
function getMasteryLevel(xp) {
    for (var i = MASTERY_LEVELS.length - 1; i >= 0; i--) {
        if (xp >= MASTERY_LEVELS[i].xpRequired) {
            return MASTERY_LEVELS[i];
        }
    }
    return MASTERY_LEVELS[0];
}

/**
 * Calculate prestige level from total XP
 */
function getPrestigeLevel(totalXp) {
    for (var i = PRESTIGE_LEVELS.length - 1; i >= 0; i--) {
        if (totalXp >= PRESTIGE_LEVELS[i].xpRequired) {
            return PRESTIGE_LEVELS[i];
        }
    }
    return PRESTIGE_LEVELS[0];
}

/**
 * RPC: collections_get_status
 * Get user's collection status
 */
function rpcCollectionsGetStatus(ctx, logger, nk, payload) {
    logger.info("[Collections] RPC collections_get_status called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload || "{}");
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    var gameId = data.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var collectionData = getCollectionData(nk, logger, ctx.userId, gameId);
    
    if (!collectionData) {
        collectionData = initializeCollectionData();
        saveCollectionData(nk, logger, ctx.userId, gameId, collectionData);
    }
    
    // Build collections overview
    var collectionsOverview = {};
    for (var collType in COLLECTIONS) {
        var coll = COLLECTIONS[collType];
        var totalItems = Object.keys(coll.items).length;
        var unlockedCount = collectionData.unlocked[collType] ? collectionData.unlocked[collType].length : 0;
        
        collectionsOverview[collType] = {
            name: coll.name,
            unlocked: unlockedCount,
            total: totalItems,
            percentage: Math.round((unlockedCount / totalItems) * 100)
        };
    }
    
    // Build mastery overview
    var masteryOverview = [];
    for (var i = 0; i < MASTERY_CATEGORIES.length; i++) {
        var cat = MASTERY_CATEGORIES[i];
        var m = collectionData.mastery[cat];
        var levelInfo = getMasteryLevel(m.xp);
        var nextLevel = MASTERY_LEVELS[Math.min(levelInfo.level, MASTERY_LEVELS.length - 1)];
        
        masteryOverview.push({
            category: cat,
            level: levelInfo.level,
            xp: m.xp,
            xpToNext: levelInfo.level < 5 ? nextLevel.xpRequired - m.xp : 0,
            bonus: levelInfo.bonus,
            isMaster: levelInfo.level >= 5,
            questionsAnswered: m.questionsAnswered,
            accuracy: m.questionsAnswered > 0 ? Math.round((m.correctAnswers / m.questionsAnswered) * 100) : 0
        });
    }
    
    // Get prestige info
    var prestigeInfo = getPrestigeLevel(collectionData.prestige.totalXp);
    var nextPrestige = PRESTIGE_LEVELS[Math.min(prestigeInfo.level + 1, PRESTIGE_LEVELS.length - 1)];
    
    return JSON.stringify({
        success: true,
        userId: ctx.userId,
        gameId: gameId,
        collections: collectionsOverview,
        allCollections: COLLECTIONS,
        unlocked: collectionData.unlocked,
        equipped: collectionData.equipped,
        mastery: masteryOverview,
        prestige: {
            level: prestigeInfo.level,
            totalXp: collectionData.prestige.totalXp,
            xpToNext: prestigeInfo.level < 5 ? nextPrestige.xpRequired - collectionData.prestige.totalXp : 0,
            bonus: prestigeInfo.bonus,
            frame: prestigeInfo.frame
        },
        prestigeLevels: PRESTIGE_LEVELS,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: collections_unlock_item
 * Unlock a collectible item
 */
function rpcCollectionsUnlockItem(ctx, logger, nk, payload) {
    logger.info("[Collections] RPC collections_unlock_item called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.collectionType || !data.itemId) {
        return JSON.stringify({ success: false, error: "Missing required fields" });
    }
    
    var gameId = data.gameId;
    var collectionType = data.collectionType;
    var itemId = data.itemId;
    
    // Validate collection type
    if (!COLLECTIONS[collectionType]) {
        return JSON.stringify({ success: false, error: "Invalid collection type" });
    }
    
    // Validate item exists
    if (!COLLECTIONS[collectionType].items[itemId]) {
        return JSON.stringify({ success: false, error: "Item not found" });
    }
    
    var collectionData = getCollectionData(nk, logger, ctx.userId, gameId);
    if (!collectionData) {
        collectionData = initializeCollectionData();
    }
    
    // Check if already unlocked
    if (collectionData.unlocked[collectionType].indexOf(itemId) !== -1) {
        return JSON.stringify({
            success: true,
            alreadyUnlocked: true,
            itemId: itemId
        });
    }
    
    // Unlock item
    collectionData.unlocked[collectionType].push(itemId);
    collectionData.updatedAt = new Date().toISOString();
    
    saveCollectionData(nk, logger, ctx.userId, gameId, collectionData);
    
    var item = COLLECTIONS[collectionType].items[itemId];
    logger.info("[Collections] Item unlocked: " + itemId + " for user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        itemId: itemId,
        collectionType: collectionType,
        item: {
            name: item.name,
            rarity: item.rarity
        },
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: collections_equip_item
 * Equip a collectible item
 */
function rpcCollectionsEquipItem(ctx, logger, nk, payload) {
    logger.info("[Collections] RPC collections_equip_item called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.slot || !data.itemId) {
        return JSON.stringify({ success: false, error: "Missing required fields" });
    }
    
    var gameId = data.gameId;
    var slot = data.slot; // avatar, title, frame, badge
    var itemId = data.itemId;
    
    var collectionData = getCollectionData(nk, logger, ctx.userId, gameId);
    if (!collectionData) {
        return JSON.stringify({ success: false, error: "Collection not initialized" });
    }
    
    // Map slot to collection type
    var collectionType = slot + "s"; // avatar -> avatars, etc.
    if (slot === "badge") collectionType = "badges";
    
    // Check if item is unlocked
    if (collectionData.unlocked[collectionType].indexOf(itemId) === -1) {
        return JSON.stringify({ success: false, error: "Item not unlocked" });
    }
    
    // Equip item
    collectionData.equipped[slot] = itemId;
    collectionData.updatedAt = new Date().toISOString();
    
    saveCollectionData(nk, logger, ctx.userId, gameId, collectionData);
    
    return JSON.stringify({
        success: true,
        slot: slot,
        itemId: itemId,
        equipped: collectionData.equipped,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: collections_add_mastery_xp
 * Add XP to a category mastery
 */
function rpcCollectionsAddMasteryXP(ctx, logger, nk, payload) {
    logger.info("[Collections] RPC collections_add_mastery_xp called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.category || data.xp === undefined) {
        return JSON.stringify({ success: false, error: "Missing required fields" });
    }
    
    var gameId = data.gameId;
    var category = data.category;
    var xpToAdd = parseInt(data.xp);
    var questionsAnswered = data.questionsAnswered || 0;
    var correctAnswers = data.correctAnswers || 0;
    
    if (MASTERY_CATEGORIES.indexOf(category) === -1) {
        return JSON.stringify({ success: false, error: "Invalid category" });
    }
    
    var collectionData = getCollectionData(nk, logger, ctx.userId, gameId);
    if (!collectionData) {
        collectionData = initializeCollectionData();
    }
    
    var mastery = collectionData.mastery[category];
    var oldLevel = getMasteryLevel(mastery.xp).level;
    
    mastery.xp += xpToAdd;
    mastery.questionsAnswered += questionsAnswered;
    mastery.correctAnswers += correctAnswers;
    
    var newLevelInfo = getMasteryLevel(mastery.xp);
    var leveledUp = newLevelInfo.level > oldLevel;
    
    // Update prestige XP
    collectionData.prestige.totalXp += xpToAdd;
    var oldPrestige = getPrestigeLevel(collectionData.prestige.totalXp - xpToAdd).level;
    var newPrestige = getPrestigeLevel(collectionData.prestige.totalXp).level;
    var prestigeUp = newPrestige > oldPrestige;
    
    collectionData.updatedAt = new Date().toISOString();
    saveCollectionData(nk, logger, ctx.userId, gameId, collectionData);
    
    logger.info("[Collections] Added " + xpToAdd + " XP to " + category + " mastery for user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        category: category,
        xpAdded: xpToAdd,
        mastery: {
            level: newLevelInfo.level,
            xp: mastery.xp,
            bonus: newLevelInfo.bonus,
            leveledUp: leveledUp
        },
        prestige: {
            level: newPrestige,
            totalXp: collectionData.prestige.totalXp,
            prestigeUp: prestigeUp
        },
        timestamp: new Date().toISOString()
    });
}


// --- Module: retention/monthly_milestones.js ---
// monthly_milestones.js - Monthly Milestones System for D30 Retention
// Provides long-term goals that reset monthly

/**
 * Monthly Milestones System
 * 
 * Features:
 * - 12 milestones per month with escalating difficulty
 * - Legendary reward for completing all 12
 * - Progress carries over within month
 * - Per-game support
 */

// Monthly milestones configuration
var MONTHLY_MILESTONES = [
    { id: "quiz_50", title: "Quiz Master", description: "Complete 50 quizzes", target: 50, reward: { coins: 500 }, category: "engagement" },
    { id: "streak_7", title: "Week Warrior", description: "Login 7 consecutive days", target: 7, reward: { mysteryBox: 1 }, category: "streak" },
    { id: "accuracy_80", title: "Sharpshooter", description: "Reach 80% accuracy", target: 80, reward: { badge: "accurate" }, category: "skill" },
    { id: "win_5", title: "Champion", description: "Win 5 multiplayer battles", target: 5, reward: { gems: 100 }, category: "competitive" },
    { id: "create_3", title: "Creator", description: "Create 3 quizzes with Link & Play", target: 3, reward: { badge: "creator" }, category: "content" },
    { id: "invite_1", title: "Social", description: "Invite 1 friend who plays", target: 1, reward: { coins: 200, coinsForFriend: 200 }, category: "social" },
    { id: "guild_join", title: "Team Player", description: "Join or create a guild", target: 1, reward: { coins: 300 }, category: "social" },
    { id: "weekly_goals", title: "Goal Getter", description: "Complete all weekly goals", target: 1, reward: { mysteryBox: 1 }, category: "engagement" },
    { id: "questions_1000", title: "1K Club", description: "Answer 1000 questions", target: 1000, reward: { title: "1K Club", badge: "1k_club" }, category: "volume" },
    { id: "level_20", title: "Leveled Up", description: "Reach Level 20", target: 20, reward: { avatar: "level_20" }, category: "progression" },
    { id: "tournament_50", title: "Competitor", description: "Top 50 in weekly tournament", target: 50, reward: { badge: "competitor", gems: 150 }, category: "competitive" },
    { id: "season_25", title: "Season Climber", description: "Reach Season Pass Level 25", target: 25, reward: { coins: 1000, frame: "milestone_frame" }, category: "progression" }
];

// Legendary reward for completing all milestones
var LEGENDARY_REWARD = {
    coins: 5000,
    gems: 500,
    avatar: "legendary_monthly",
    title: "Monthly Legend",
    badge: "monthly_legend",
    frame: "legendary_frame"
};

/**
 * Get current month info
 */
function getCurrentMonthInfo() {
    var now = new Date();
    var year = now.getFullYear();
    var month = now.getMonth() + 1;
    
    // Days remaining in month
    var lastDay = new Date(year, month, 0).getDate();
    var currentDay = now.getDate();
    var daysRemaining = lastDay - currentDay;
    
    return {
        year: year,
        month: month,
        monthKey: year + "_" + (month < 10 ? "0" + month : month),
        daysRemaining: daysRemaining,
        totalDays: lastDay
    };
}

/**
 * Read milestones progress for user
 */
function getMilestonesProgress(nk, logger, userId, gameId) {
    var collection = "monthly_milestones";
    var monthInfo = getCurrentMonthInfo();
    var key = "progress_" + userId + "_" + gameId + "_" + monthInfo.monthKey;
    
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: userId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn("[MonthlyMilestones] Failed to read progress: " + err.message);
    }
    
    return null;
}

/**
 * Save milestones progress
 */
function saveMilestonesProgress(nk, logger, userId, gameId, data) {
    var collection = "monthly_milestones";
    var monthInfo = getCurrentMonthInfo();
    var key = "progress_" + userId + "_" + gameId + "_" + monthInfo.monthKey;
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error("[MonthlyMilestones] Failed to save progress: " + err.message);
        return false;
    }
}

/**
 * Initialize milestones for new month
 */
function initializeMilestones(monthInfo) {
    var milestones = {};
    
    for (var i = 0; i < MONTHLY_MILESTONES.length; i++) {
        var m = MONTHLY_MILESTONES[i];
        milestones[m.id] = {
            current: 0,
            target: m.target,
            completed: false,
            claimed: false
        };
    }
    
    return {
        monthKey: monthInfo.monthKey,
        year: monthInfo.year,
        month: monthInfo.month,
        milestones: milestones,
        totalCompleted: 0,
        allCompleted: false,
        legendaryRewardClaimed: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

/**
 * RPC: monthly_milestones_get_status
 * Get current monthly milestones status
 */
function rpcMonthlyMilestonesGetStatus(ctx, logger, nk, payload) {
    logger.info("[MonthlyMilestones] RPC monthly_milestones_get_status called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload || "{}");
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    var gameId = data.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var monthInfo = getCurrentMonthInfo();
    var progress = getMilestonesProgress(nk, logger, ctx.userId, gameId);
    
    // Initialize if new month
    if (!progress || progress.monthKey !== monthInfo.monthKey) {
        progress = initializeMilestones(monthInfo);
        saveMilestonesProgress(nk, logger, ctx.userId, gameId, progress);
    }
    
    // Build milestones array with details
    var milestonesArray = [];
    var completedCount = 0;
    
    for (var i = 0; i < MONTHLY_MILESTONES.length; i++) {
        var m = MONTHLY_MILESTONES[i];
        var p = progress.milestones[m.id];
        
        if (p.completed) completedCount++;
        
        milestonesArray.push({
            id: m.id,
            title: m.title,
            description: m.description,
            category: m.category,
            current: p.current,
            target: p.target,
            completed: p.completed,
            claimed: p.claimed,
            reward: m.reward,
            progress: Math.min(100, Math.round((p.current / p.target) * 100))
        });
    }
    
    return JSON.stringify({
        success: true,
        userId: ctx.userId,
        gameId: gameId,
        month: monthInfo,
        milestones: milestonesArray,
        totalMilestones: MONTHLY_MILESTONES.length,
        completedCount: completedCount,
        allCompleted: progress.allCompleted,
        legendaryReward: LEGENDARY_REWARD,
        legendaryRewardClaimed: progress.legendaryRewardClaimed,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: monthly_milestones_update_progress
 * Update progress on a milestone
 */
function rpcMonthlyMilestonesUpdateProgress(ctx, logger, nk, payload) {
    logger.info("[MonthlyMilestones] RPC monthly_milestones_update_progress called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.milestoneId) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, milestoneId" });
    }
    
    var gameId = data.gameId;
    var milestoneId = data.milestoneId;
    var value = data.value !== undefined ? data.value : 1;
    var increment = data.increment !== false;
    var setMax = data.setMax || false; // For accuracy-type milestones
    
    var monthInfo = getCurrentMonthInfo();
    var progress = getMilestonesProgress(nk, logger, ctx.userId, gameId);
    
    if (!progress || progress.monthKey !== monthInfo.monthKey) {
        return JSON.stringify({ success: false, error: "Milestones not initialized for this month" });
    }
    
    var milestone = progress.milestones[milestoneId];
    if (!milestone) {
        return JSON.stringify({ success: false, error: "Milestone not found: " + milestoneId });
    }
    
    if (milestone.completed) {
        return JSON.stringify({
            success: true,
            milestoneId: milestoneId,
            alreadyCompleted: true,
            current: milestone.current,
            target: milestone.target
        });
    }
    
    // Update progress
    if (setMax) {
        milestone.current = Math.max(milestone.current, value);
    } else if (increment) {
        milestone.current += value;
    } else {
        milestone.current = value;
    }
    
    // Check completion
    var justCompleted = false;
    if (milestone.current >= milestone.target && !milestone.completed) {
        milestone.completed = true;
        justCompleted = true;
        progress.totalCompleted++;
        
        logger.info("[MonthlyMilestones] Milestone completed: " + milestoneId + " by user " + ctx.userId);
    }
    
    // Check if all completed
    if (progress.totalCompleted >= MONTHLY_MILESTONES.length && !progress.allCompleted) {
        progress.allCompleted = true;
        logger.info("[MonthlyMilestones] All milestones completed by user " + ctx.userId);
    }
    
    progress.updatedAt = new Date().toISOString();
    saveMilestonesProgress(nk, logger, ctx.userId, gameId, progress);
    
    return JSON.stringify({
        success: true,
        milestoneId: milestoneId,
        current: milestone.current,
        target: milestone.target,
        completed: milestone.completed,
        justCompleted: justCompleted,
        totalCompleted: progress.totalCompleted,
        allCompleted: progress.allCompleted,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: monthly_milestones_claim_reward
 * Claim reward for a completed milestone
 */
function rpcMonthlyMilestonesClaimReward(ctx, logger, nk, payload) {
    logger.info("[MonthlyMilestones] RPC monthly_milestones_claim_reward called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.milestoneId) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, milestoneId" });
    }
    
    var gameId = data.gameId;
    var milestoneId = data.milestoneId;
    
    var progress = getMilestonesProgress(nk, logger, ctx.userId, gameId);
    if (!progress) {
        return JSON.stringify({ success: false, error: "Milestones not initialized" });
    }
    
    var milestone = progress.milestones[milestoneId];
    if (!milestone) {
        return JSON.stringify({ success: false, error: "Milestone not found" });
    }
    
    if (!milestone.completed) {
        return JSON.stringify({ success: false, error: "Milestone not completed" });
    }
    
    if (milestone.claimed) {
        return JSON.stringify({ success: false, error: "Reward already claimed" });
    }
    
    // Find reward
    var reward = null;
    for (var i = 0; i < MONTHLY_MILESTONES.length; i++) {
        if (MONTHLY_MILESTONES[i].id === milestoneId) {
            reward = MONTHLY_MILESTONES[i].reward;
            break;
        }
    }
    
    milestone.claimed = true;
    progress.updatedAt = new Date().toISOString();
    saveMilestonesProgress(nk, logger, ctx.userId, gameId, progress);
    
    // Grant rewards to wallet
    var walletChanges = {};
    if (reward && reward.coins) walletChanges.coins = reward.coins;
    if (reward && reward.gems) walletChanges.gems = reward.gems;
    if (Object.keys(walletChanges).length > 0) {
        try {
            nk.walletUpdate(ctx.userId, walletChanges, { source: "monthly_milestone", milestoneId: milestoneId }, true);
            logger.info("[MonthlyMilestones] Granted wallet: " + JSON.stringify(walletChanges) + " to " + ctx.userId);
        } catch (walletErr) {
            logger.error("[MonthlyMilestones] Wallet grant failed: " + walletErr.message);
        }
    }
    
    logger.info("[MonthlyMilestones] Reward claimed for " + milestoneId + " by user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        milestoneId: milestoneId,
        reward: reward,
        walletGranted: walletChanges,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: monthly_milestones_claim_legendary
 * Claim legendary reward for completing all milestones
 */
function rpcMonthlyMilestonesClaimLegendary(ctx, logger, nk, payload) {
    logger.info("[MonthlyMilestones] RPC monthly_milestones_claim_legendary called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var gameId = data.gameId;
    
    var progress = getMilestonesProgress(nk, logger, ctx.userId, gameId);
    if (!progress) {
        return JSON.stringify({ success: false, error: "Milestones not initialized" });
    }
    
    if (!progress.allCompleted) {
        return JSON.stringify({ success: false, error: "Not all milestones completed" });
    }
    
    if (progress.legendaryRewardClaimed) {
        return JSON.stringify({ success: false, error: "Legendary reward already claimed" });
    }
    
    progress.legendaryRewardClaimed = true;
    progress.updatedAt = new Date().toISOString();
    saveMilestonesProgress(nk, logger, ctx.userId, gameId, progress);
    
    // Grant legendary rewards to wallet
    var legendaryWallet = {};
    if (LEGENDARY_REWARD.coins) legendaryWallet.coins = LEGENDARY_REWARD.coins;
    if (LEGENDARY_REWARD.gems) legendaryWallet.gems = LEGENDARY_REWARD.gems;
    if (Object.keys(legendaryWallet).length > 0) {
        try {
            nk.walletUpdate(ctx.userId, legendaryWallet, { source: "monthly_milestone_legendary" }, true);
            logger.info("[MonthlyMilestones] Granted legendary wallet: " + JSON.stringify(legendaryWallet) + " to " + ctx.userId);
        } catch (walletErr) {
            logger.error("[MonthlyMilestones] Legendary wallet grant failed: " + walletErr.message);
        }
    }
    
    logger.info("[MonthlyMilestones] Legendary reward claimed by user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        reward: LEGENDARY_REWARD,
        walletGranted: legendaryWallet,
        message: "Congratulations! You've achieved Monthly Legend status!",
        timestamp: new Date().toISOString()
    });
}


// --- Module: retention/retention_v2.js ---
// retention_v2.js - Streak Repair & Wager System for QuizVerse v3.0
// Extends existing retention module with 2 new RPCs (does NOT modify existing retention RPCs)
// RPCs: streak_repair, streak_wager

/**
 * Streak Repair & Wager System — Production-Ready
 *
 * streak_repair: Pay gems to restore a broken streak (24h window, 3/month max)
 * streak_wager: Bet gems on maintaining your streak (Day 10+ unlock, up to 3x multiplier)
 *
 * Storage: collection="streak_data", key="{userId}_{gameId}"
 * Wallet: Uses nk.walletUpdate for atomic gem deduction/award
 */

// ─── CONSTANTS ──────────────────────────────────────────────────────────────

var STREAK_REPAIR_COST = 100;       // gems
var REPAIR_WINDOW_HOURS = 24;
var MAX_REPAIRS_PER_MONTH = 3;
var WAGER_MIN_STREAK_DAY = 10;
var WAGER_MAX_MULTIPLIER = 3.0;
var WAGER_MIN_AMOUNT = 10;
var WAGER_MAX_AMOUNT = 500;
var STREAK_STORAGE_COLLECTION = 'streak_data';

// ─── HELPERS ────────────────────────────────────────────────────────────────

function streakStorageKey(userId, gameId) {
    return userId + '_' + gameId;
}

function readStreakData(nk, logger, userId, gameId) {
    try {
        var records = nk.storageRead([{
            collection: STREAK_STORAGE_COLLECTION,
            key: streakStorageKey(userId, gameId),
            userId: userId
        }]);
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn('[StreakV2] Storage read failed: ' + err.message);
    }
    return null;
}

function writeStreakData(nk, logger, userId, gameId, data) {
    try {
        nk.storageWrite([{
            collection: STREAK_STORAGE_COLLECTION,
            key: streakStorageKey(userId, gameId),
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error('[StreakV2] Storage write failed: ' + err.message);
        return false;
    }
}

function getCurrentMonthKey() {
    var now = new Date();
    return now.getFullYear() + '-' + (now.getMonth() + 1 < 10 ? '0' : '') + (now.getMonth() + 1);
}

function validatePayloadV2(payload) {
    if (!payload || payload === '') return {};
    try {
        return JSON.parse(payload);
    } catch (err) {
        return null;
    }
}

function errorResponseV2(msg) {
    return JSON.stringify({ success: false, error: msg });
}

function generateWagerId() {
    return 'wager_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 6);
}

// ─── RPC: streak_repair ─────────────────────────────────────────────────────

function rpcStreakRepair(ctx, logger, nk, payload) {
    if (!ctx.userId) return errorResponseV2('User not authenticated');

    var data = validatePayloadV2(payload);
    if (data === null) return errorResponseV2('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var streakData = readStreakData(nk, logger, ctx.userId, gameId);

    if (!streakData) {
        return errorResponseV2('No streak data found. Play a quiz first.');
    }

    // Check if streak is actually broken
    if (!streakData.isBroken) {
        return errorResponseV2('streak_not_broken');
    }

    // Check repair window (24h from break time)
    var brokenAt = new Date(streakData.brokenAt || 0);
    var now = new Date();
    var hoursSinceBroken = (now.getTime() - brokenAt.getTime()) / (1000 * 60 * 60);

    if (hoursSinceBroken > REPAIR_WINDOW_HOURS) {
        return errorResponseV2('repair_window_expired');
    }

    // Check monthly limit
    var monthKey = getCurrentMonthKey();
    if (!streakData.repairs) streakData.repairs = {};
    var repairsThisMonth = streakData.repairs[monthKey] || 0;

    if (repairsThisMonth >= MAX_REPAIRS_PER_MONTH) {
        return JSON.stringify({
            success: false,
            error: 'monthly_limit_reached',
            repairsUsedThisMonth: repairsThisMonth,
            maxRepairsPerMonth: MAX_REPAIRS_PER_MONTH,
            resetsAt: (new Date(now.getFullYear(), now.getMonth() + 1, 1)).toISOString()
        });
    }

    // Check wallet balance atomically
    var repairCost = STREAK_REPAIR_COST;
    try {
        // Deduct gems — nk.walletUpdate will fail if insufficient
        var walletResult = nk.walletUpdate(ctx.userId, { gems: -repairCost }, {
            reason: 'streak_repair',
            gameId: gameId,
            streakDay: streakData.currentDay || 0
        }, true);

        // Restore streak
        streakData.isBroken = false;
        streakData.brokenAt = null;
        streakData.repairs[monthKey] = repairsThisMonth + 1;
        streakData.totalRepairs = (streakData.totalRepairs || 0) + 1;
        streakData.lastRepairedAt = now.toISOString();
        streakData.updatedAt = now.toISOString();

        if (!writeStreakData(nk, logger, ctx.userId, gameId, streakData)) {
            // Rollback wallet if storage fails
            try {
                nk.walletUpdate(ctx.userId, { gems: repairCost }, { reason: 'streak_repair_rollback' }, false);
            } catch (rollbackErr) {
                logger.error('[StreakV2] CRITICAL: Rollback failed for ' + ctx.userId + ': ' + rollbackErr.message);
            }
            return errorResponseV2('Failed to save streak data');
        }

        logger.info('[StreakV2] Streak repaired for ' + ctx.userId + ', cost: ' + repairCost + ' gems');

        return JSON.stringify({
            success: true,
            repairCost: repairCost,
            newStreakDay: streakData.currentDay || 0,
            repairsUsedThisMonth: repairsThisMonth + 1,
            maxRepairsPerMonth: MAX_REPAIRS_PER_MONTH,
            repairWindowExpiresAt: new Date(brokenAt.getTime() + REPAIR_WINDOW_HOURS * 3600000).toISOString(),
            timestamp: now.toISOString()
        });

    } catch (walletErr) {
        // Wallet insufficient or other error
        if (walletErr.message && walletErr.message.indexOf('insufficient') !== -1) {
            // Get current balance for error response
            var balance = 0;
            try {
                var account = nk.accountGetId(ctx.userId);
                if (account && account.wallet) {
                    var wallet = JSON.parse(account.wallet);
                    balance = wallet.gems || 0;
                }
            } catch (e) { /* ignore */ }

            return JSON.stringify({
                success: false,
                error: 'insufficient_gems',
                cost: repairCost,
                balance: balance
            });
        }
        logger.error('[StreakV2] Wallet error: ' + walletErr.message);
        return errorResponseV2('Wallet operation failed');
    }
}

// ─── RPC: streak_wager ──────────────────────────────────────────────────────

function rpcStreakWager(ctx, logger, nk, payload) {
    if (!ctx.userId) return errorResponseV2('User not authenticated');

    var data = validatePayloadV2(payload);
    if (data === null) return errorResponseV2('Invalid JSON payload');

    var gameId = data.gameId || 'quizverse';
    var action = data.action; // "place" or "resolve"

    if (action !== 'place' && action !== 'resolve') {
        return errorResponseV2('Invalid action. Must be "place" or "resolve".');
    }

    var streakData = readStreakData(nk, logger, ctx.userId, gameId);
    if (!streakData) {
        return errorResponseV2('No streak data found. Play a quiz first.');
    }

    var now = new Date();

    // ─── PLACE WAGER ────────────────────────────────────────────────────
    if (action === 'place') {
        var wagerAmount = parseInt(data.wagerAmount);
        var multiplier = parseFloat(data.multiplier) || 2.0;

        // Validate streak day requirement
        if ((streakData.currentDay || 0) < WAGER_MIN_STREAK_DAY) {
            return JSON.stringify({
                success: false,
                error: 'wager_locked_until_day_10',
                currentDay: streakData.currentDay || 0,
                requiredDay: WAGER_MIN_STREAK_DAY
            });
        }

        // Check for active wager
        if (streakData.activeWager && streakData.activeWager.status === 'active') {
            return JSON.stringify({
                success: false,
                error: 'wager_already_active',
                activeWager: {
                    wagerId: streakData.activeWager.wagerId,
                    amount: streakData.activeWager.amount,
                    multiplier: streakData.activeWager.multiplier,
                    expiresAt: streakData.activeWager.expiresAt
                }
            });
        }

        // Validate wager amount
        if (isNaN(wagerAmount) || wagerAmount < WAGER_MIN_AMOUNT) {
            return errorResponseV2('Minimum wager is ' + WAGER_MIN_AMOUNT + ' gems');
        }
        if (wagerAmount > WAGER_MAX_AMOUNT) {
            return errorResponseV2('Maximum wager is ' + WAGER_MAX_AMOUNT + ' gems');
        }

        // Clamp multiplier
        if (multiplier > WAGER_MAX_MULTIPLIER) multiplier = WAGER_MAX_MULTIPLIER;
        if (multiplier < 1.5) multiplier = 1.5;

        // Check if streak is broken
        if (streakData.isBroken) {
            return errorResponseV2('Cannot wager on a broken streak');
        }

        // Deduct gems
        try {
            nk.walletUpdate(ctx.userId, { gems: -wagerAmount }, {
                reason: 'streak_wager_place',
                gameId: gameId,
                streakDay: streakData.currentDay
            }, true);
        } catch (walletErr) {
            var balance = 0;
            try {
                var account = nk.accountGetId(ctx.userId);
                if (account && account.wallet) {
                    var w = JSON.parse(account.wallet);
                    balance = w.gems || 0;
                }
            } catch (e) { /* ignore */ }

            return JSON.stringify({
                success: false,
                error: 'insufficient_gems',
                cost: wagerAmount,
                balance: balance
            });
        }

        // Create wager
        var wagerId = generateWagerId();
        var tomorrow = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1, 23, 59, 59));

        streakData.activeWager = {
            wagerId: wagerId,
            amount: wagerAmount,
            multiplier: multiplier,
            status: 'active',
            placedAt: now.toISOString(),
            expiresAt: tomorrow.toISOString(),
            streakDayAtPlacement: streakData.currentDay
        };
        streakData.updatedAt = now.toISOString();

        if (!writeStreakData(nk, logger, ctx.userId, gameId, streakData)) {
            // Rollback wallet
            try {
                nk.walletUpdate(ctx.userId, { gems: wagerAmount }, { reason: 'streak_wager_rollback' }, false);
            } catch (rollbackErr) {
                logger.error('[StreakV2] CRITICAL: Wager rollback failed for ' + ctx.userId);
            }
            return errorResponseV2('Failed to save wager');
        }

        logger.info('[StreakV2] Wager placed: ' + wagerId + ' by ' + ctx.userId + ' (' + wagerAmount + ' gems x' + multiplier + ')');

        return JSON.stringify({
            success: true,
            wagerId: wagerId,
            wagerAmount: wagerAmount,
            multiplier: multiplier,
            potentialWinnings: Math.round(wagerAmount * multiplier),
            expiresAt: tomorrow.toISOString(),
            gemsDeducted: wagerAmount,
            timestamp: now.toISOString()
        });
    }

    // ─── RESOLVE WAGER ──────────────────────────────────────────────────
    if (action === 'resolve') {
        if (!streakData.activeWager || streakData.activeWager.status !== 'active') {
            return errorResponseV2('No active wager to resolve');
        }

        var wager = streakData.activeWager;

        // Check if quiz completed today
        var lastQuizDate = streakData.lastQuizCompletedAt ? new Date(streakData.lastQuizCompletedAt) : null;
        var todayStart = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));

        if (!lastQuizDate || lastQuizDate.getTime() < todayStart.getTime()) {
            return errorResponseV2('quiz_not_completed_today');
        }

        // Determine result: did user maintain streak?
        var streakMaintained = !streakData.isBroken && (streakData.currentDay || 0) > (wager.streakDayAtPlacement || 0);
        var result = streakMaintained ? 'won' : 'lost';
        var winnings = 0;

        if (result === 'won') {
            winnings = Math.round(wager.amount * wager.multiplier);
            try {
                nk.walletUpdate(ctx.userId, { gems: winnings }, {
                    reason: 'streak_wager_won',
                    wagerId: wager.wagerId,
                    multiplier: wager.multiplier
                }, false);
            } catch (walletErr) {
                logger.error('[StreakV2] Failed to award wager winnings: ' + walletErr.message);
                return errorResponseV2('Failed to award winnings');
            }
        }

        // Archive wager
        if (!streakData.wagerHistory) streakData.wagerHistory = [];
        var archivedWager = {
            wagerId: wager.wagerId,
            amount: wager.amount,
            multiplier: wager.multiplier,
            result: result,
            winnings: winnings,
            placedAt: wager.placedAt,
            resolvedAt: now.toISOString()
        };
        streakData.wagerHistory.push(archivedWager);

        // Keep only last 50 wagers in history
        if (streakData.wagerHistory.length > 50) {
            streakData.wagerHistory = streakData.wagerHistory.slice(-50);
        }

        streakData.activeWager = null;
        streakData.totalWagers = (streakData.totalWagers || 0) + 1;
        streakData.totalWagersWon = (streakData.totalWagersWon || 0) + (result === 'won' ? 1 : 0);
        streakData.updatedAt = now.toISOString();

        writeStreakData(nk, logger, ctx.userId, gameId, streakData);

        logger.info('[StreakV2] Wager resolved: ' + wager.wagerId + ' = ' + result +
                     (result === 'won' ? ' (+' + winnings + ' gems)' : ''));

        return JSON.stringify({
            success: true,
            wagerId: wager.wagerId,
            result: result,
            wagerAmount: wager.amount,
            multiplier: wager.multiplier,
            winnings: winnings,
            gemsAwarded: result === 'won' ? winnings : 0,
            totalWagers: streakData.totalWagers,
            totalWagersWon: streakData.totalWagersWon,
            timestamp: now.toISOString()
        });
    }
}


// --- Module: retention/season_pass.js ---
// season_pass.js - Season Pass / Battle Pass System for D7/D30 Retention
// Provides 30-day season with free and premium tracks

/**
 * Season Pass System
 * 
 * Features:
 * - 50 levels of rewards (free + premium tracks)
 * - Daily and weekly XP quests
 * - Season themes and exclusive rewards
 * - Premium pass purchase support
 * - Per-game season support
 */

// Season configuration
var SEASON_CONFIG = {
    maxLevel: 50,
    xpPerLevel: 1000,      // XP needed per level
    seasonDuration: 30,     // Days
    premiumPrice: 499,      // In gems
};

// Free track rewards (every 5 levels)
var FREE_REWARDS = {
    1:  { coins: 100 },
    5:  { coins: 200, avatar: "season_common_1" },
    10: { coins: 300, energyRefill: 1 },
    15: { coins: 500 },
    20: { coins: 500, frame: "season_bronze" },
    25: { coins: 750, luckyWheelSpin: 1 },
    30: { coins: 1000 },
    35: { coins: 1000, mysteryBox: 1 },
    40: { coins: 1500 },
    45: { coins: 2000, badge: "season_veteran" },
    50: { coins: 3000, title: "Season Veteran", badge: "season_badge" }
};

// Premium track rewards (every level)
var PREMIUM_REWARDS = {
    1:  { gems: 50, frame: "premium_starter" },
    5:  { gems: 100, avatar: "season_rare_1" },
    10: { gems: 150, coins: 1000 },
    15: { gems: 200, title: "Premium Player" },
    20: { gems: 250, avatar: "season_epic_1" },
    25: { gems: 300, coins: 2000, streakShield: 3 },
    30: { gems: 400, frame: "premium_gold" },
    35: { gems: 500, avatar: "season_epic_2" },
    40: { gems: 600, coins: 3000 },
    45: { gems: 750, avatar: "season_legendary" },
    50: { gems: 1000, title: "Season Master", avatar: "season_master", frame: "season_master_frame", badge: "season_master_badge" }
};

// Daily quests for XP
var DAILY_QUESTS = [
    { id: "daily_login", title: "Daily Login", description: "Log in today", xp: 50, autoComplete: true },
    { id: "daily_quiz_1", title: "First Quiz", description: "Complete 1 quiz", target: 1, xp: 100 },
    { id: "daily_quiz_3", title: "Quiz Trio", description: "Complete 3 quizzes", target: 3, xp: 150 },
    { id: "daily_correct_10", title: "Knowledge", description: "Answer 10 questions correctly", target: 10, xp: 100 },
    { id: "daily_accuracy", title: "Accurate", description: "Get 80%+ accuracy in a quiz", target: 80, xp: 150 }
];

// Weekly quests for XP
var WEEKLY_QUESTS = [
    { id: "weekly_quiz_10", title: "Quiz Master", description: "Complete 10 quizzes", target: 10, xp: 500 },
    { id: "weekly_win_3", title: "Triple Win", description: "Win 3 multiplayer matches", target: 3, xp: 400 },
    { id: "weekly_streak", title: "Streak Keeper", description: "Maintain 5-day streak", target: 5, xp: 300 },
    { id: "weekly_create", title: "Creator", description: "Create a quiz with Link & Play", target: 1, xp: 350 },
    { id: "weekly_challenge", title: "Challenger", description: "Challenge 3 friends", target: 3, xp: 350 }
];

/**
 * Get current season info
 */
function getCurrentSeasonInfo() {
    var now = new Date();
    var year = now.getFullYear();
    var month = now.getMonth() + 1;
    
    // Season number (12 per year)
    var seasonNumber = (year * 12) + month;
    
    // Season start date (1st of month)
    var seasonStart = new Date(year, month - 1, 1);
    
    // Season end date (last day of month)
    var seasonEnd = new Date(year, month, 0, 23, 59, 59);
    
    // Days remaining
    var daysRemaining = Math.ceil((seasonEnd - now) / (1000 * 60 * 60 * 24));
    
    return {
        seasonNumber: seasonNumber,
        seasonName: "Season " + seasonNumber,
        startDate: seasonStart.toISOString(),
        endDate: seasonEnd.toISOString(),
        daysRemaining: Math.max(0, daysRemaining),
        month: month,
        year: year
    };
}

/**
 * Read season pass data for user
 */
function getSeasonPassData(nk, logger, userId, gameId) {
    var collection = "season_pass";
    var season = getCurrentSeasonInfo();
    var key = "progress_" + userId + "_" + gameId + "_" + season.seasonNumber;
    
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: userId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn("[SeasonPass] Failed to read data: " + err.message);
    }
    
    return null;
}

/**
 * Save season pass data
 */
function saveSeasonPassData(nk, logger, userId, gameId, data) {
    var collection = "season_pass";
    var season = getCurrentSeasonInfo();
    var key = "progress_" + userId + "_" + gameId + "_" + season.seasonNumber;
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error("[SeasonPass] Failed to save data: " + err.message);
        return false;
    }
}

/**
 * Initialize season pass for new season
 */
function initializeSeasonPass(seasonInfo, isPremium) {
    var dailyQuests = {};
    var weeklyQuests = {};
    
    // Initialize daily quests
    for (var i = 0; i < DAILY_QUESTS.length; i++) {
        var quest = DAILY_QUESTS[i];
        dailyQuests[quest.id] = {
            current: 0,
            target: quest.target || 1,
            completed: false,
            claimed: false
        };
    }
    
    // Initialize weekly quests
    for (var j = 0; j < WEEKLY_QUESTS.length; j++) {
        var wquest = WEEKLY_QUESTS[j];
        weeklyQuests[wquest.id] = {
            current: 0,
            target: wquest.target || 1,
            completed: false,
            claimed: false
        };
    }
    
    return {
        seasonNumber: seasonInfo.seasonNumber,
        level: 1,
        xp: 0,
        totalXpEarned: 0,
        isPremium: isPremium || false,
        freeRewardsClaimed: {},
        premiumRewardsClaimed: {},
        dailyQuests: dailyQuests,
        weeklyQuests: weeklyQuests,
        lastDailyReset: new Date().toISOString().split('T')[0], // Date only
        lastWeeklyReset: getWeekStart().toISOString(),
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

/**
 * Get week start date (Monday)
 */
function getWeekStart() {
    var now = new Date();
    var day = now.getDay();
    var diff = now.getDate() - day + (day === 0 ? -6 : 1);
    return new Date(now.setDate(diff));
}

/**
 * Check and reset daily/weekly quests if needed
 */
function checkQuestResets(data) {
    var today = new Date().toISOString().split('T')[0];
    var currentWeekStart = getWeekStart().toISOString();
    var needsSave = false;
    
    // Daily reset
    if (data.lastDailyReset !== today) {
        for (var dqId in data.dailyQuests) {
            data.dailyQuests[dqId].current = 0;
            data.dailyQuests[dqId].completed = false;
            data.dailyQuests[dqId].claimed = false;
        }
        // Auto-complete login quest
        data.dailyQuests["daily_login"].current = 1;
        data.dailyQuests["daily_login"].completed = true;
        
        data.lastDailyReset = today;
        needsSave = true;
    }
    
    // Weekly reset
    if (data.lastWeeklyReset !== currentWeekStart) {
        for (var wqId in data.weeklyQuests) {
            data.weeklyQuests[wqId].current = 0;
            data.weeklyQuests[wqId].completed = false;
            data.weeklyQuests[wqId].claimed = false;
        }
        data.lastWeeklyReset = currentWeekStart;
        needsSave = true;
    }
    
    return needsSave;
}

/**
 * Calculate level from XP
 */
function calculateLevel(xp) {
    var level = Math.floor(xp / SEASON_CONFIG.xpPerLevel) + 1;
    return Math.min(level, SEASON_CONFIG.maxLevel);
}

/**
 * RPC: season_pass_get_status
 * Get current season pass status
 */
function rpcSeasonPassGetStatus(ctx, logger, nk, payload) {
    logger.info("[SeasonPass] RPC season_pass_get_status called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload || "{}");
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    var gameId = data.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var seasonInfo = getCurrentSeasonInfo();
    var passData = getSeasonPassData(nk, logger, ctx.userId, gameId);
    
    // Initialize if new or different season
    if (!passData || passData.seasonNumber !== seasonInfo.seasonNumber) {
        var wasPremium = passData ? passData.isPremium : false;
        passData = initializeSeasonPass(seasonInfo, wasPremium);
        saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    }
    
    // Check quest resets
    if (checkQuestResets(passData)) {
        saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    }
    
    // Build daily quests response
    var dailyQuests = [];
    for (var i = 0; i < DAILY_QUESTS.length; i++) {
        var dq = DAILY_QUESTS[i];
        var progress = passData.dailyQuests[dq.id];
        dailyQuests.push({
            id: dq.id,
            title: dq.title,
            description: dq.description,
            xp: dq.xp,
            current: progress.current,
            target: progress.target,
            completed: progress.completed,
            claimed: progress.claimed
        });
    }
    
    // Build weekly quests response
    var weeklyQuests = [];
    for (var j = 0; j < WEEKLY_QUESTS.length; j++) {
        var wq = WEEKLY_QUESTS[j];
        var wprogress = passData.weeklyQuests[wq.id];
        weeklyQuests.push({
            id: wq.id,
            title: wq.title,
            description: wq.description,
            xp: wq.xp,
            current: wprogress.current,
            target: wprogress.target,
            completed: wprogress.completed,
            claimed: wprogress.claimed
        });
    }
    
    // Build rewards for current level range
    var currentLevel = passData.level;
    var xpForNextLevel = (currentLevel < SEASON_CONFIG.maxLevel) 
        ? (currentLevel * SEASON_CONFIG.xpPerLevel) - passData.xp + SEASON_CONFIG.xpPerLevel
        : 0;
    
    return JSON.stringify({
        success: true,
        userId: ctx.userId,
        gameId: gameId,
        season: seasonInfo,
        level: currentLevel,
        xp: passData.xp,
        totalXpEarned: passData.totalXpEarned,
        xpToNextLevel: Math.max(0, xpForNextLevel),
        xpPerLevel: SEASON_CONFIG.xpPerLevel,
        maxLevel: SEASON_CONFIG.maxLevel,
        isPremium: passData.isPremium,
        premiumPrice: SEASON_CONFIG.premiumPrice,
        dailyQuests: dailyQuests,
        weeklyQuests: weeklyQuests,
        freeRewardsClaimed: passData.freeRewardsClaimed,
        premiumRewardsClaimed: passData.premiumRewardsClaimed,
        freeRewards: FREE_REWARDS,
        premiumRewards: PREMIUM_REWARDS,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: season_pass_add_xp
 * Add XP to season pass
 */
function rpcSeasonPassAddXP(ctx, logger, nk, payload) {
    logger.info("[SeasonPass] RPC season_pass_add_xp called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || data.xp === undefined) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, xp" });
    }
    
    var gameId = data.gameId;
    var xpToAdd = parseInt(data.xp);
    var source = data.source || "unknown";
    
    var seasonInfo = getCurrentSeasonInfo();
    var passData = getSeasonPassData(nk, logger, ctx.userId, gameId);
    
    if (!passData || passData.seasonNumber !== seasonInfo.seasonNumber) {
        return JSON.stringify({ success: false, error: "Season pass not initialized" });
    }
    
    var oldLevel = passData.level;
    passData.xp += xpToAdd;
    passData.totalXpEarned += xpToAdd;
    
    // Calculate new level
    passData.level = calculateLevel(passData.totalXpEarned);
    var leveledUp = passData.level > oldLevel;
    var levelsGained = passData.level - oldLevel;
    
    passData.updatedAt = new Date().toISOString();
    saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    
    logger.info("[SeasonPass] Added " + xpToAdd + " XP from " + source + " for user " + ctx.userId + ", level: " + passData.level);
    
    return JSON.stringify({
        success: true,
        xpAdded: xpToAdd,
        source: source,
        totalXp: passData.totalXpEarned,
        level: passData.level,
        oldLevel: oldLevel,
        leveledUp: leveledUp,
        levelsGained: levelsGained,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: season_pass_complete_quest
 * Complete and claim a quest
 */
function rpcSeasonPassCompleteQuest(ctx, logger, nk, payload) {
    logger.info("[SeasonPass] RPC season_pass_complete_quest called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.questId || !data.questType) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, questId, questType" });
    }
    
    var gameId = data.gameId;
    var questId = data.questId;
    var questType = data.questType; // "daily" or "weekly"
    var value = data.value !== undefined ? data.value : 1;
    
    var passData = getSeasonPassData(nk, logger, ctx.userId, gameId);
    if (!passData) {
        return JSON.stringify({ success: false, error: "Season pass not initialized" });
    }
    
    // Check resets
    checkQuestResets(passData);
    
    // Get quest config and progress
    var questConfig = null;
    var questProgress = null;
    var xpReward = 0;
    
    if (questType === "daily") {
        for (var i = 0; i < DAILY_QUESTS.length; i++) {
            if (DAILY_QUESTS[i].id === questId) {
                questConfig = DAILY_QUESTS[i];
                break;
            }
        }
        questProgress = passData.dailyQuests[questId];
        xpReward = questConfig ? questConfig.xp : 0;
    } else if (questType === "weekly") {
        for (var j = 0; j < WEEKLY_QUESTS.length; j++) {
            if (WEEKLY_QUESTS[j].id === questId) {
                questConfig = WEEKLY_QUESTS[j];
                break;
            }
        }
        questProgress = passData.weeklyQuests[questId];
        xpReward = questConfig ? questConfig.xp : 0;
    }
    
    if (!questConfig || !questProgress) {
        return JSON.stringify({ success: false, error: "Quest not found: " + questId });
    }
    
    if (questProgress.claimed) {
        return JSON.stringify({ success: true, alreadyClaimed: true });
    }
    
    // Update progress
    questProgress.current = Math.min(questProgress.current + value, questProgress.target);
    
    // Check completion
    var justCompleted = false;
    if (questProgress.current >= questProgress.target && !questProgress.completed) {
        questProgress.completed = true;
        justCompleted = true;
    }
    
    // Auto-claim if completed
    var xpEarned = 0;
    if (questProgress.completed && !questProgress.claimed) {
        questProgress.claimed = true;
        
        // Add XP
        var oldLevel = passData.level;
        passData.xp += xpReward;
        passData.totalXpEarned += xpReward;
        passData.level = calculateLevel(passData.totalXpEarned);
        xpEarned = xpReward;
        
        logger.info("[SeasonPass] Quest " + questId + " completed, +" + xpReward + " XP");
    }
    
    passData.updatedAt = new Date().toISOString();
    saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    
    return JSON.stringify({
        success: true,
        questId: questId,
        questType: questType,
        current: questProgress.current,
        target: questProgress.target,
        completed: questProgress.completed,
        claimed: questProgress.claimed,
        justCompleted: justCompleted,
        xpEarned: xpEarned,
        newLevel: passData.level,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: season_pass_claim_reward
 * Claim a level reward
 */
function rpcSeasonPassClaimReward(ctx, logger, nk, payload) {
    logger.info("[SeasonPass] RPC season_pass_claim_reward called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.level || !data.track) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, level, track" });
    }
    
    var gameId = data.gameId;
    var level = parseInt(data.level);
    var track = data.track; // "free" or "premium"
    
    var passData = getSeasonPassData(nk, logger, ctx.userId, gameId);
    if (!passData) {
        return JSON.stringify({ success: false, error: "Season pass not initialized" });
    }
    
    // Check if level is reached
    if (passData.level < level) {
        return JSON.stringify({ success: false, error: "Level " + level + " not reached yet" });
    }
    
    // Check track eligibility
    if (track === "premium" && !passData.isPremium) {
        return JSON.stringify({ success: false, error: "Premium pass required" });
    }
    
    // Get reward
    var rewardMap = track === "premium" ? PREMIUM_REWARDS : FREE_REWARDS;
    var reward = rewardMap[level];
    
    if (!reward) {
        return JSON.stringify({ success: false, error: "No reward at level " + level + " for " + track + " track" });
    }
    
    // Check if already claimed
    var claimedMap = track === "premium" ? passData.premiumRewardsClaimed : passData.freeRewardsClaimed;
    if (claimedMap[level]) {
        return JSON.stringify({ success: false, error: "Reward already claimed" });
    }
    
    // Mark as claimed
    claimedMap[level] = true;
    passData.updatedAt = new Date().toISOString();
    saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    
    // Grant rewards to wallet
    var walletChanges = {};
    if (reward.coins) walletChanges.coins = reward.coins;
    if (reward.gems) walletChanges.gems = reward.gems;
    if (Object.keys(walletChanges).length > 0) {
        try {
            nk.walletUpdate(ctx.userId, walletChanges, { source: "season_pass", level: level, track: track }, true);
            logger.info("[SeasonPass] Granted wallet: " + JSON.stringify(walletChanges) + " to " + ctx.userId);
        } catch (walletErr) {
            logger.error("[SeasonPass] Wallet grant failed: " + walletErr.message);
        }
    }
    
    logger.info("[SeasonPass] Level " + level + " " + track + " reward claimed by user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        level: level,
        track: track,
        reward: reward,
        walletGranted: walletChanges,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: season_pass_purchase_premium
 * Purchase premium season pass
 */
function rpcSeasonPassPurchasePremium(ctx, logger, nk, payload) {
    logger.info("[SeasonPass] RPC season_pass_purchase_premium called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var gameId = data.gameId;
    
    var passData = getSeasonPassData(nk, logger, ctx.userId, gameId);
    if (!passData) {
        return JSON.stringify({ success: false, error: "Season pass not initialized" });
    }
    
    if (passData.isPremium) {
        return JSON.stringify({ success: false, error: "Already premium" });
    }
    
    // In production, verify IAP receipt here
    // For now, just mark as premium
    passData.isPremium = true;
    passData.premiumPurchaseDate = new Date().toISOString();
    passData.updatedAt = new Date().toISOString();
    
    saveSeasonPassData(nk, logger, ctx.userId, gameId, passData);
    
    logger.info("[SeasonPass] Premium purchased by user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        isPremium: true,
        currentLevel: passData.level,
        availablePremiumRewards: Object.keys(PREMIUM_REWARDS).filter(function(l) { return parseInt(l) <= passData.level; }),
        timestamp: new Date().toISOString()
    });
}


// --- Module: retention/weekly_goals.js ---
// weekly_goals.js - Weekly Goals System for D7 Retention
// Provides progressive daily goals that reset weekly

/**
 * Weekly Goals System
 * 
 * Features:
 * - 7 progressive daily goals that build engagement
 * - Week streak bonuses for consecutive weeks
 * - Mystery box rewards for completing all 7 days
 * - Per-game support
 */

// Default weekly goals configuration
var DEFAULT_WEEKLY_GOALS = [
    { day: 1, id: "login", title: "Welcome Back", description: "Log in to the app", reward: { coins: 50 }, autoComplete: true },
    { day: 2, id: "complete_quizzes", title: "Quiz Starter", description: "Complete 3 quizzes", target: 3, reward: { coins: 100, xp: 50 } },
    { day: 3, id: "win_multiplayer", title: "Champion", description: "Win 1 multiplayer match", target: 1, reward: { coins: 150, xp: 75 } },
    { day: 4, id: "accuracy", title: "Precision", description: "Score 80%+ on any quiz", target: 80, reward: { coins: 200, xp: 100 } },
    { day: 5, id: "challenge_friend", title: "Social", description: "Challenge a friend", target: 1, reward: { coins: 250, xp: 125 } },
    { day: 6, id: "create_quiz", title: "Creator", description: "Create a quiz with Link & Play", target: 1, reward: { coins: 300, xp: 150 } },
    { day: 7, id: "complete_all", title: "Weekly Master", description: "Complete all weekly goals", reward: { coins: 500, xp: 250, mysteryBox: true } }
];

// Week streak bonus multipliers
var WEEK_STREAK_MULTIPLIERS = {
    1: 1.0,   // Week 1: Normal
    2: 1.25,  // Week 2: 25% bonus
    3: 1.5,   // Week 3: 50% bonus
    4: 2.0,   // Week 4+: Double rewards
};

/**
 * Get current week number (ISO week)
 */
function getCurrentWeekNumber() {
    var now = new Date();
    var startOfYear = new Date(now.getFullYear(), 0, 1);
    var days = Math.floor((now - startOfYear) / (24 * 60 * 60 * 1000));
    return Math.ceil((days + startOfYear.getDay() + 1) / 7);
}

/**
 * Get current year
 */
function getCurrentYear() {
    return new Date().getFullYear();
}

/**
 * Get day of week (1-7, Monday = 1)
 */
function getCurrentDayOfWeek() {
    var day = new Date().getDay();
    return day === 0 ? 7 : day; // Sunday becomes 7
}

/**
 * Read weekly goals progress for user
 */
function getWeeklyGoalsProgress(nk, logger, userId, gameId) {
    var collection = "weekly_goals";
    var key = "progress_" + userId + "_" + gameId;
    
    try {
        var records = nk.storageRead([{
            collection: collection,
            key: key,
            userId: userId
        }]);
        
        if (records && records.length > 0 && records[0].value) {
            return records[0].value;
        }
    } catch (err) {
        logger.warn("[WeeklyGoals] Failed to read progress: " + err.message);
    }
    
    return null;
}

/**
 * Save weekly goals progress
 */
function saveWeeklyGoalsProgress(nk, logger, userId, gameId, data) {
    var collection = "weekly_goals";
    var key = "progress_" + userId + "_" + gameId;
    
    try {
        nk.storageWrite([{
            collection: collection,
            key: key,
            userId: userId,
            value: data,
            permissionRead: 1,
            permissionWrite: 0
        }]);
        return true;
    } catch (err) {
        logger.error("[WeeklyGoals] Failed to save progress: " + err.message);
        return false;
    }
}

/**
 * Initialize or reset weekly goals for a new week
 */
function initializeWeeklyGoals(currentWeek, currentYear, weekStreak) {
    var goals = {};
    
    for (var i = 0; i < DEFAULT_WEEKLY_GOALS.length; i++) {
        var goal = DEFAULT_WEEKLY_GOALS[i];
        goals[goal.id] = {
            day: goal.day,
            title: goal.title,
            description: goal.description,
            target: goal.target || 1,
            current: 0,
            completed: false,
            claimed: false,
            reward: goal.reward,
            autoComplete: goal.autoComplete || false
        };
    }
    
    return {
        weekNumber: currentWeek,
        year: currentYear,
        weekStreak: weekStreak,
        goals: goals,
        allCompleted: false,
        bonusClaimed: false,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
}

/**
 * Calculate reward with week streak multiplier
 */
function calculateRewardWithMultiplier(reward, weekStreak) {
    var multiplier = WEEK_STREAK_MULTIPLIERS[Math.min(weekStreak, 4)] || 2.0;
    
    var adjustedReward = {};
    if (reward.coins) adjustedReward.coins = Math.floor(reward.coins * multiplier);
    if (reward.xp) adjustedReward.xp = Math.floor(reward.xp * multiplier);
    if (reward.gems) adjustedReward.gems = Math.floor(reward.gems * multiplier);
    if (reward.mysteryBox) adjustedReward.mysteryBox = true;
    
    return adjustedReward;
}

/**
 * RPC: weekly_goals_get_status
 * Get current weekly goals status
 */
function rpcWeeklyGoalsGetStatus(ctx, logger, nk, payload) {
    logger.info("[WeeklyGoals] RPC weekly_goals_get_status called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload || "{}");
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    var gameId = data.gameId;
    if (!gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var currentWeek = getCurrentWeekNumber();
    var currentYear = getCurrentYear();
    var currentDay = getCurrentDayOfWeek();
    
    // Get existing progress
    var progress = getWeeklyGoalsProgress(nk, logger, ctx.userId, gameId);
    
    // Check if we need to reset for a new week
    if (!progress || progress.weekNumber !== currentWeek || progress.year !== currentYear) {
        // Calculate week streak
        var weekStreak = 1;
        if (progress) {
            var wasLastWeek = (progress.weekNumber === currentWeek - 1 && progress.year === currentYear) ||
                              (currentWeek === 1 && progress.weekNumber === 52 && progress.year === currentYear - 1);
            
            if (wasLastWeek && progress.allCompleted) {
                weekStreak = (progress.weekStreak || 0) + 1;
            }
        }
        
        // Initialize new week
        progress = initializeWeeklyGoals(currentWeek, currentYear, weekStreak);
        
        // Auto-complete day 1 login goal
        progress.goals["login"].current = 1;
        progress.goals["login"].completed = true;
        
        saveWeeklyGoalsProgress(nk, logger, ctx.userId, gameId, progress);
        
        logger.info("[WeeklyGoals] New week initialized for user " + ctx.userId + ", week streak: " + weekStreak);
    }
    
    // Build response with goal details
    var goalsArray = [];
    var totalCompleted = 0;
    var totalGoals = Object.keys(progress.goals).length;
    
    for (var goalId in progress.goals) {
        var goal = progress.goals[goalId];
        var adjustedReward = calculateRewardWithMultiplier(goal.reward, progress.weekStreak);
        
        goalsArray.push({
            id: goalId,
            day: goal.day,
            title: goal.title,
            description: goal.description,
            target: goal.target,
            current: goal.current,
            completed: goal.completed,
            claimed: goal.claimed,
            reward: adjustedReward,
            isUnlocked: goal.day <= currentDay,
            isToday: goal.day === currentDay
        });
        
        if (goal.completed) totalCompleted++;
    }
    
    // Sort by day
    goalsArray.sort(function(a, b) { return a.day - b.day; });
    
    return JSON.stringify({
        success: true,
        userId: ctx.userId,
        gameId: gameId,
        weekNumber: currentWeek,
        year: currentYear,
        currentDay: currentDay,
        weekStreak: progress.weekStreak,
        weekStreakMultiplier: WEEK_STREAK_MULTIPLIERS[Math.min(progress.weekStreak, 4)] || 2.0,
        goals: goalsArray,
        totalCompleted: totalCompleted,
        totalGoals: totalGoals,
        allCompleted: progress.allCompleted,
        bonusClaimed: progress.bonusClaimed,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: weekly_goals_update_progress
 * Update progress on a specific goal
 */
function rpcWeeklyGoalsUpdateProgress(ctx, logger, nk, payload) {
    logger.info("[WeeklyGoals] RPC weekly_goals_update_progress called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.goalId) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, goalId" });
    }
    
    var gameId = data.gameId;
    var goalId = data.goalId;
    var value = data.value !== undefined ? data.value : 1;
    var increment = data.increment !== false;
    
    var currentWeek = getCurrentWeekNumber();
    var currentYear = getCurrentYear();
    var currentDay = getCurrentDayOfWeek();
    
    // Get progress
    var progress = getWeeklyGoalsProgress(nk, logger, ctx.userId, gameId);
    
    if (!progress || progress.weekNumber !== currentWeek) {
        return JSON.stringify({ success: false, error: "Weekly goals not initialized. Call get_status first." });
    }
    
    var goal = progress.goals[goalId];
    if (!goal) {
        return JSON.stringify({ success: false, error: "Goal not found: " + goalId });
    }
    
    // Check if goal day is unlocked
    if (goal.day > currentDay) {
        return JSON.stringify({ success: false, error: "This goal is not yet unlocked" });
    }
    
    // Don't update if already completed
    if (goal.completed) {
        return JSON.stringify({
            success: true,
            goalId: goalId,
            alreadyCompleted: true,
            current: goal.current,
            target: goal.target
        });
    }
    
    // Update progress
    if (increment) {
        goal.current += value;
    } else {
        goal.current = Math.max(goal.current, value);
    }
    
    // Check completion
    var justCompleted = false;
    if (goal.current >= goal.target && !goal.completed) {
        goal.completed = true;
        justCompleted = true;
        logger.info("[WeeklyGoals] Goal completed: " + goalId + " by user " + ctx.userId);
    }
    
    // Check if all goals completed
    var allCompleted = true;
    for (var gid in progress.goals) {
        if (gid !== "complete_all" && !progress.goals[gid].completed) {
            allCompleted = false;
            break;
        }
    }
    
    // Auto-complete the "complete all" goal
    if (allCompleted && !progress.goals["complete_all"].completed) {
        progress.goals["complete_all"].current = 1;
        progress.goals["complete_all"].completed = true;
        progress.allCompleted = true;
        logger.info("[WeeklyGoals] All goals completed by user " + ctx.userId);
    }
    
    progress.updatedAt = new Date().toISOString();
    saveWeeklyGoalsProgress(nk, logger, ctx.userId, gameId, progress);
    
    return JSON.stringify({
        success: true,
        goalId: goalId,
        current: goal.current,
        target: goal.target,
        completed: goal.completed,
        justCompleted: justCompleted,
        allCompleted: progress.allCompleted,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: weekly_goals_claim_reward
 * Claim reward for a completed goal
 */
function rpcWeeklyGoalsClaimReward(ctx, logger, nk, payload) {
    logger.info("[WeeklyGoals] RPC weekly_goals_claim_reward called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId || !data.goalId) {
        return JSON.stringify({ success: false, error: "Missing required fields: gameId, goalId" });
    }
    
    var gameId = data.gameId;
    var goalId = data.goalId;
    
    var currentWeek = getCurrentWeekNumber();
    
    // Get progress
    var progress = getWeeklyGoalsProgress(nk, logger, ctx.userId, gameId);
    
    if (!progress || progress.weekNumber !== currentWeek) {
        return JSON.stringify({ success: false, error: "Weekly goals not initialized" });
    }
    
    var goal = progress.goals[goalId];
    if (!goal) {
        return JSON.stringify({ success: false, error: "Goal not found: " + goalId });
    }
    
    if (!goal.completed) {
        return JSON.stringify({ success: false, error: "Goal not completed yet" });
    }
    
    if (goal.claimed) {
        return JSON.stringify({ success: false, error: "Reward already claimed" });
    }
    
    // Calculate reward with multiplier
    var reward = calculateRewardWithMultiplier(goal.reward, progress.weekStreak);
    
    // Mark as claimed
    goal.claimed = true;
    progress.updatedAt = new Date().toISOString();
    saveWeeklyGoalsProgress(nk, logger, ctx.userId, gameId, progress);
    
    // Log transaction
    try {
        var transactionKey = "weekly_goal_reward_" + ctx.userId + "_" + Date.now();
        nk.storageWrite([{
            collection: "transaction_logs",
            key: transactionKey,
            userId: ctx.userId,
            value: {
                type: "weekly_goal_reward",
                goalId: goalId,
                weekNumber: currentWeek,
                reward: reward,
                weekStreak: progress.weekStreak,
                timestamp: new Date().toISOString()
            },
            permissionRead: 1,
            permissionWrite: 0
        }]);
    } catch (err) {
        logger.warn("[WeeklyGoals] Failed to log transaction: " + err.message);
    }
    
    // Grant rewards to wallet
    var walletChanges = {};
    if (reward.coins) walletChanges.coins = reward.coins;
    if (reward.gems) walletChanges.gems = reward.gems;
    if (reward.xp) walletChanges.xp = reward.xp;
    if (Object.keys(walletChanges).length > 0) {
        try {
            nk.walletUpdate(ctx.userId, walletChanges, { source: "weekly_goal", goalId: goalId }, true);
            logger.info("[WeeklyGoals] Granted wallet: " + JSON.stringify(walletChanges) + " to " + ctx.userId);
        } catch (walletErr) {
            logger.error("[WeeklyGoals] Wallet grant failed: " + walletErr.message);
        }
    }
    
    logger.info("[WeeklyGoals] Reward claimed for goal " + goalId + " by user " + ctx.userId);
    
    return JSON.stringify({
        success: true,
        goalId: goalId,
        reward: reward,
        walletGranted: walletChanges,
        weekStreak: progress.weekStreak,
        timestamp: new Date().toISOString()
    });
}

/**
 * RPC: weekly_goals_claim_bonus
 * Claim bonus for completing all weekly goals
 */
function rpcWeeklyGoalsClaimBonus(ctx, logger, nk, payload) {
    logger.info("[WeeklyGoals] RPC weekly_goals_claim_bonus called");
    
    if (!ctx.userId) {
        return JSON.stringify({ success: false, error: "User not authenticated" });
    }
    
    var data;
    try {
        data = JSON.parse(payload);
    } catch (err) {
        return JSON.stringify({ success: false, error: "Invalid JSON payload" });
    }
    
    if (!data.gameId) {
        return JSON.stringify({ success: false, error: "Missing required field: gameId" });
    }
    
    var gameId = data.gameId;
    var currentWeek = getCurrentWeekNumber();
    
    // Get progress
    var progress = getWeeklyGoalsProgress(nk, logger, ctx.userId, gameId);
    
    if (!progress || progress.weekNumber !== currentWeek) {
        return JSON.stringify({ success: false, error: "Weekly goals not initialized" });
    }
    
    if (!progress.allCompleted) {
        return JSON.stringify({ success: false, error: "Not all goals completed" });
    }
    
    if (progress.bonusClaimed) {
        return JSON.stringify({ success: false, error: "Bonus already claimed" });
    }
    
    // Calculate bonus with streak multiplier
    var baseBonus = { coins: 500, gems: 100, mysteryBox: true };
    var bonus = calculateRewardWithMultiplier(baseBonus, progress.weekStreak);
    
    // Mark as claimed
    progress.bonusClaimed = true;
    progress.updatedAt = new Date().toISOString();
    saveWeeklyGoalsProgress(nk, logger, ctx.userId, gameId, progress);
    
    // Grant bonus rewards to wallet
    var bonusWalletChanges = {};
    if (bonus.coins) bonusWalletChanges.coins = bonus.coins;
    if (bonus.gems) bonusWalletChanges.gems = bonus.gems;
    if (Object.keys(bonusWalletChanges).length > 0) {
        try {
            nk.walletUpdate(ctx.userId, bonusWalletChanges, { source: "weekly_goal_bonus", weekStreak: progress.weekStreak }, true);
            logger.info("[WeeklyGoals] Granted bonus wallet: " + JSON.stringify(bonusWalletChanges) + " to " + ctx.userId);
        } catch (walletErr) {
            logger.error("[WeeklyGoals] Bonus wallet grant failed: " + walletErr.message);
        }
    }
    
    logger.info("[WeeklyGoals] Week bonus claimed by user " + ctx.userId + ", streak: " + progress.weekStreak);
    
    return JSON.stringify({
        success: true,
        bonus: bonus,
        walletGranted: bonusWalletChanges,
        weekStreak: progress.weekStreak,
        message: progress.weekStreak >= 4 ? "4+ Week Streak! DOUBLE REWARDS!" : "Week " + progress.weekStreak + " completed!",
        timestamp: new Date().toISOString()
    });
}


