    // Special
    "tournament": { entryCost: 100, rewardOnComplete: 25, rewardOnWin: 500, freeDaily: 0 },
    "weekly_challenge": { entryCost: 40, rewardOnComplete: 20, rewardOnWin: 150, freeDaily: 1 }
