        var records = listResult.records || [];
        var results = [];
        for (var i = 0; i < records.length; i++) {
            var rec = records[i];
            if (rec.key && rec.key.indexOf("result_") === 0 && rec.value) {
                results.push(rec.value);
            }
        }
        results.sort(function (a, b) { return (b.timestamp || 0) - (a.timestamp || 0); });
